def section_61_plaintext_class_injectivity(m: dict[str, list[int]]) -> dict:
    """Tier H8 (task 2): CSP — plaintext-class injectivity within Rule-A blocks.

    Build the standard class union-find (`build_class_union_find`: literal ≥5,
    isomorph ≥15, repeats ≥2). Under monoalphabetic-within-block + injective
    σ, **distinct positions in the same block must map to distinct plaintext
    symbols**, hence distinct class IDs.

    Check: for each of 91 blocks, |{classroot(p) : p in block}| = block length.
    Violations would mean the equivalence graph merges two within-block cells
    that must carry different plaintext — inconsistent with §10/§27.
    """
    banner(61, 'PLAINTEXT-CLASS INJECTIVITY ON 91 BLOCKS (Tier H8)')

    uf = build_class_union_find(m)
    violations = _rule_a_block_injectivity_violations(m, uf)

    kv('within-block class-ID collisions (!!)', len(violations))
    assert len(violations) == 0

    print('  ✓ All 91 Rule-A blocks: injective plaintext-class assignment')
    print('    (same as ciphertext injectivity within each block).')

    return {'class_injectivity_violations': 0, 'blocks_checked': 91}


def section_62_w2_w3_plaintext_class_bridges(m: dict[str, list[int]]) -> dict:
    """Tier H8 (task 3): W2/W3 — **structural** (plaintext-class) bridges only.

    Uses `build_class_union_find` — no raw CT co-occurrence scan (cf. §57
    “weak” counts).  Two positions bridge iff they share the **same class
    root** (same plaintext letter under the isomorph/literal graph).

    Count how many W2 (resp. W3) ciphertext cells have at least one other
    position in Fam A / B-core / {E3} that shares their class.
    """
    banner(62, 'W2 / W3 — PLAINTEXT-CLASS BRIDGES (Tier H8)')

    uf = build_class_union_find(m)
    comp, by_root = _plaintext_class_partition(m, uf)
    hc = _w2_w3_bridge_headline_counts(m, comp, by_root)

    kv('W2 cells with class-mate in Fam A (off-W2)',
        f'{hc["w2_classmate_positions_famA"]} / {len(m["W2"])}')
    kv('W3 cells with class-mate in Fam A (off-W3)',
        f'{hc["w3_classmate_positions_famA"]} / {len(m["W3"])}')
    kv('W2 cells with class-mate in B-core',
        f'{hc["w2_classmate_positions_bcore"]} / {len(m["W2"])}')
    kv('W3 cells with class-mate in B-core',
        f'{hc["w3_classmate_positions_bcore"]} / {len(m["W3"])}')
    kv('W2 cells with class-mate in E3 only',
        f'{hc["w2_classmate_positions_e3"]} / {len(m["W2"])}')
    kv('W3 cells with class-mate in E3 only',
        f'{hc["w3_classmate_positions_e3"]} / {len(m["W3"])}')
    print()

    mates_w2_14 = [x for x in by_root[comp[('W2', 14)]] if x != ('W2', 14)]
    kv('class-mates of W2[14] (sample)', mates_w2_14[:12])
    kv('W2[14] ct equals E1[0] ct (ciphertext pin)', m['W2'][14] == m['E1'][0])
    print()
    print('  Note: literal pins W2[14]=E1[0], W2[15]=W1[0] (§50) are **not**')
    print('  necessarily one union-find class — the isomorph graph can miss')
    print('  short CT-equality links.  Use §50/§57 CT pins + this § for class links.')
    print()
    print('  Class-mate counts are **far below** §57 weak CT matches; they only')
    print('  count isomorph/literal graph agreement.')

    return {
        'w2_classmate_positions_famA': hc['w2_classmate_positions_famA'],
        'w3_classmate_positions_famA': hc['w3_classmate_positions_famA'],
        'w2_classmate_positions_bcore': hc['w2_classmate_positions_bcore'],
        'w3_classmate_positions_bcore': hc['w3_classmate_positions_bcore'],
    }


