def section_65_ct_pin_union_augmentation(m: dict[str, list[int]]) -> dict:
    """Tier H9: Augment `build_class_union_find` with **explicit CT pins**
    from §50 (ciphertext equality = same plaintext under shared σ where those
    blocks share a key).

    Pins (verified from data, not from vocabulary):
      (W2,14) ~ (E1,0)   same CT
      (W2,15) ~ (W1,0)   same CT

    The baseline isomorph graph already merges `(E1,0) ~ (W1,0) ~ (E2,0)`
    (message-index “slot”).  Adding both pins therefore forces
    `W2[14] ≡ W2[15]` in plaintext class, contradicting unique letters within
    **W2[0]** if digits 1 and 2 are distinct — *unless* the pos-0 merges are
    reinterpreted.

    **Result:** a small number of **within-block class collisions** appear
    (quantified); base graph + pins cannot all model “distinct list digits”
    naïvely.

    Also reports W2→Fam-A class-bridge counts **before** vs **after** pins.
    """
    banner(65, 'CT-PIN AUGMENTATION ON CLASS UNION-FIND (Tier H9)')

    assert m['W2'][14] == m['E1'][0] and m['W2'][15] == m['W1'][0]

    uf0 = build_class_union_find(m)
    kv('baseline UF: (E1,0),(W1,0) same class?', uf0.find(('E1', 0)) == uf0.find(('W1', 0)))
    v0 = _rule_a_block_injectivity_violations(m, uf0)
    kv('baseline within-block injectivity violations', len(v0))

    uf1 = build_class_union_find(m)
    uf1.union(('W2', 14), ('E1', 0))
    uf1.union(('W2', 15), ('W1', 0))
    v1 = _rule_a_block_injectivity_violations(m, uf1)
    kv('within-block violations after CT pins', len(v1))
    for L, bi, n, nr in v1:
        kv(f'  collision {L}[block {bi}]', f'len={n}, distinct_roots={nr}')

    assert len(v0) == 0
    assert len(v1) == 3
    assert {(L, bi) for L, bi, _, _ in v1} == {('W2', 0), ('E3', 2), ('W3', 1)}

    FAM_A = {'E1', 'W1', 'E2'}

    def count_w2_famA(uf: UnionFind) -> int:
        by: dict[object, list[tuple[str, int]]] = defaultdict(list)
        for L in MSG_LABELS:
            for p in range(len(m[L])):
                by[uf.find((L, p))].append((L, p))
        c = 0
        for p in range(len(m['W2'])):
            r = uf.find(('W2', p))
            if any(L in FAM_A and (L, q) != ('W2', p) for L, q in by[r]):
                c += 1
        return c

    bf0 = count_w2_famA(uf0)
    bf1 = count_w2_famA(uf1)
    kv('W2 positions with class-mate in Fam A (baseline §62)', f'{bf0} / {len(m["W2"])}')
    kv('W2 positions with class-mate in Fam A (after CT pins)',   f'{bf1} / {len(m["W2"])}')

    print()
    print('  ⇒ Pins interact with the default pos-0 cross-msg class merge.')
    print('    Treat §65 as a consistency diagnostic, not a failing §61.')

    return {
        'baseline_injectivity_violations': len(v0),
        'pinned_injectivity_violations': len(v1),
        'w2_famA_classmates_baseline': bf0,
        'w2_famA_classmates_after_pins': bf1,
    }


def section_66_no_cross_message_pos0_class_uf(m: dict[str, list[int]]) -> dict:
    """Tier H10: Resolve §65↔pos-0 tension by **not** merging distinct msgs at pos 0.

    `build_class_union_find_no_cross_message_pos0` applies the same literal
    (≥5) and isomorph (≥15, ≥2) unions as `build_class_union_find`, but skips
    any union between `(L,0)` and `(L',0)` when `L != L'`.

    With this graph, the §50 ciphertext pins unioned on top no longer force
    `W2[14] ≡ W2[15]` in plaintext class, and Rule-A within-block injectivity
    holds (cf. §61) even **after** pins — unlike §65's stock UF.
    """
    banner(66, 'NO CROSS-MSG POS-0 MERGE — CLASS UF + §50 PINS (Tier H10)')

    assert m['W2'][14] == m['E1'][0] and m['W2'][15] == m['W1'][0]

    def n_classes(uf: UnionFind) -> int:
        return len({uf.find(x) for x in uf.parent})

    uf_stock = build_class_union_find(m)
    uf_var = build_class_union_find_no_cross_message_pos0(m)

    kv('class count (stock `build_class_union_find`)', n_classes(uf_stock))
    kv('class count (no cross-msg pos-0 merges)',       n_classes(uf_var))
    assert n_classes(uf_stock) == 492
    assert n_classes(uf_var) == 496

    kv('stock UF: (E1,0) ~ (W1,0)?', uf_stock.find(('E1', 0)) == uf_stock.find(('W1', 0)))
    kv('variant UF: (E1,0) ~ (W1,0)?', uf_var.find(('E1', 0)) == uf_var.find(('W1', 0)))
    assert uf_var.find(('E1', 0)) != uf_var.find(('W1', 0))

    v_base = _rule_a_block_injectivity_violations(m, uf_var)
    kv('variant alone: within-block injectivity violations', len(v_base))
    assert len(v_base) == 0

    uf_pin = build_class_union_find_no_cross_message_pos0(m)
    uf_pin.union(('W2', 14), ('E1', 0))
    uf_pin.union(('W2', 15), ('W1', 0))
    v_pin = _rule_a_block_injectivity_violations(m, uf_pin)
    kv('variant + §50 CT pins: injectivity violations', len(v_pin))
    assert len(v_pin) == 0

    FAM_A = {'E1', 'W1', 'E2'}

    def count_w2_famA(uf: UnionFind) -> int:
        by: dict[object, list[tuple[str, int]]] = defaultdict(list)
        for L in MSG_LABELS:
            for p in range(len(m[L])):
                by[uf.find((L, p))].append((L, p))
        c = 0
        for p in range(len(m['W2'])):
            r = uf.find(('W2', p))
            if any(L in FAM_A and (L, q) != ('W2', p) for L, q in by[r]):
                c += 1
        return c

    w2a_var = count_w2_famA(uf_var)
    w2a_pin = count_w2_famA(uf_pin)
    kv('W2 → Fam-A class-mates (variant, no pins)', f'{w2a_var} / {len(m["W2"])}')
    kv('W2 → Fam-A class-mates (variant + pins)',  f'{w2a_pin} / {len(m["W2"])}')
    assert w2a_var == 5
    assert w2a_pin == 7

    print()
    print('  ⇒ Splitting pos-0 across messages makes §50 pins compatible with')
    print('    monoalphabetic-within-block + injective σ on every Rule-A block.')

    return {
        'stock_class_count': 492,
        'variant_class_count': 496,
        'variant_injectivity_violations': 0,
        'variant_pinned_injectivity_violations': 0,
        'w2_famA_classmates_variant': w2a_var,
        'w2_famA_classmates_variant_pinned': w2a_pin,
    }


