def section_71_variant_uf_partition_audit(m: dict[str, list[int]]) -> dict:
    """Tier H10+ : **Audit** stock vs ``no_cross_message_pos0`` plaintext classes.

    Quantifies *how much* partitions differ and shows that §62 headline bridge
    counts are **bit-for-bit identical** — the variant only splits the two
    ``K₃`` cliques on message-index digits at pos 0 (Fam A and B-core).
    """
    banner(71, 'VARIANT UF vs STOCK — PARTITION AUDIT (Tier H10)')

    uf0 = build_class_union_find(m)
    uf1 = build_class_union_find_no_cross_message_pos0(m)

    n0 = len({uf0.find(x) for x in uf0.parent})
    n1 = len({uf1.find(x) for x in uf1.parent})
    kv('plaintext classes (stock `build_class_union_find`)', n0)
    kv('plaintext classes (`build_class_union_find_no_cross_message_pos0`)', n1)
    assert n0 == 492 and n1 == 496

    ca = _normalized_uf_class_ids(m, uf0)
    cb = _normalized_uf_class_ids(m, uf1)
    n_move = sum(
        1 for L in MSG_LABELS for p in range(len(m[L]))
        if ca[(L, p)] != cb[(L, p)]
    )
    kv('cells with different dense class index (stock vs variant)', f'{n_move} / 1036')

    flips = _pairwise_class_equivalence_flips(m, uf0, uf1)
    kv('unordered cell pairs with changed same-class predicate', len(flips))
    assert len(flips) == 6
    print('  (those 6 pairs are exactly the Fam-A pos0 triangle + B-core pos0'
          ' triangle:)')
    for x, y, s0, s1 in flips:
        kv(f'    {x}  {y}', f'stock_same={s0}  variant_same={s1}')

    c0, b0 = _plaintext_class_partition(m, uf0)
    c1, b1 = _plaintext_class_partition(m, uf1)
    h0 = _w2_w3_bridge_headline_counts(m, c0, b0)
    h1 = _w2_w3_bridge_headline_counts(m, c1, b1)
    assert h0 == h1
    kv('§62 W2/W3 bridge counts (stock)', h0)
    kv('§62 W2/W3 bridge counts (variant)', h1)

    m14_0 = frozenset(x for x in b0[c0[('W2', 14)]] if x != ('W2', 14))
    m14_1 = frozenset(x for x in b1[c1[('W2', 14)]] if x != ('W2', 14))
    kv('class-mates of W2[14] (stock, as a set)', sorted(m14_0))
    kv('class-mates of W2[14] (variant)', sorted(m14_1))
    assert m14_0 == m14_1

    assert n_move == 695

    print()
    print('  Interpretation: **695** cells sit in components that were re-id’d')
    print('    after splitting pos-0 cliques, but only **6** *binary* class')
    print('    equalities flip — all six among {(E1,0),(W1,0),(E2,0)} and')
    print('    {(E4,0),(W4,0),(E5,0)}.  W2/W3 “who bridges to whom” is unchanged.')

    return {
        'stock_classes': n0,
        'variant_classes': n1,
        'cells_reindexed': n_move,
        'pairwise_equivalence_flips': len(flips),
        'bridge_counts_unchanged': True,
    }


