def section_73_ct_pin_union_stock_vs_variant_full_audit(m: dict[str, list[int]]) -> dict:
    """Tier H11: §50 CT pins — **stock** UF vs **pos-0-split** UF (`all` policy).

    Same two unions as §65: ``(W2,14)~(E1,0)`` and ``(W2,15)~(W1,0)``.
    Tabulates Rule-A injectivity, full §62 six-vector, and **explicit**
    class-mate sets for ``W2[14]`` / ``W2[15]`` (the coarse bridge counts can
    match even when components differ).
    """
    banner(73, 'CT PINS ON STOCK vs VARIANT UF — FULL AUDIT (Tier H11)')

    assert m['W2'][14] == m['E1'][0] and m['W2'][15] == m['W1'][0]

    def pinned_ufs() -> tuple[tuple[str, UnionFind], tuple[str, UnionFind]]:
        a = build_class_union_find(m)
        a.union(('W2', 14), ('E1', 0))
        a.union(('W2', 15), ('W1', 0))
        b = build_class_union_find_pos0_policy(m, 'all')
        b.union(('W2', 14), ('E1', 0))
        b.union(('W2', 15), ('W1', 0))
        return (('stock+pins', a), ('variant+pins', b))

    for label, uf in pinned_ufs():
        inj = _rule_a_block_injectivity_violations(m, uf)
        kv(f'Rule-A injectivity violations ({label})', len(inj))
        comp, by_root = _plaintext_class_partition(m, uf)
        h = _w2_w3_bridge_headline_counts(m, comp, by_root)
        kv(f'§62 six-vector ({label})', h)
        m14 = sorted(x for x in by_root[comp[('W2', 14)]] if x != ('W2', 14))
        m15 = sorted(x for x in by_root[comp[('W2', 15)]] if x != ('W2', 15))
        kv(f'class-mates of W2[14] ({label})', m14)
        kv(f'class-mates of W2[15] ({label})', m15)
        print()

    uf_s = build_class_union_find(m)
    uf_s.union(('W2', 14), ('E1', 0))
    uf_s.union(('W2', 15), ('W1', 0))
    uf_v = build_class_union_find_pos0_policy(m, 'all')
    uf_v.union(('W2', 14), ('E1', 0))
    uf_v.union(('W2', 15), ('W1', 0))

    assert len(_rule_a_block_injectivity_violations(m, uf_s)) == 3
    assert len(_rule_a_block_injectivity_violations(m, uf_v)) == 0

    cs, bs = _plaintext_class_partition(m, uf_s)
    cv, bv = _plaintext_class_partition(m, uf_v)
    assert _w2_w3_bridge_headline_counts(m, cs, bs) == _w2_w3_bridge_headline_counts(
        m, cv, bv
    )

    m14_s = sorted(x for x in bs[cs[('W2', 14)]] if x != ('W2', 14))
    m15_s = sorted(x for x in bs[cs[('W2', 15)]] if x != ('W2', 15))
    m14_v = sorted(x for x in bv[cv[('W2', 14)]] if x != ('W2', 14))
    m15_v = sorted(x for x in bv[cv[('W2', 15)]] if x != ('W2', 15))

    assert m14_s == [('E1', 0), ('E2', 0), ('E3', 20), ('E3', 21), ('W1', 0),
                     ('W2', 15), ('W3', 19), ('W3', 20)]
    assert m15_s == [('E1', 0), ('E2', 0), ('E3', 20), ('E3', 21), ('W1', 0),
                     ('W2', 14), ('W3', 19), ('W3', 20)]
    assert m14_v == [('E1', 0), ('E3', 20), ('W3', 19)]
    assert m15_v == [('E3', 21), ('W1', 0), ('W3', 20)]

    print('  Headline §62 counts agree across stock+pins vs variant+pins, but the')
    print('  W2[14]/W2[15] **components** shrink under the variant (no shared pos-0')
    print('  clique wrapping E1/W1/E2[0] into one class).')

    return {
        'stock_pinned_injectivity_violations': 3,
        'variant_pinned_injectivity_violations': 0,
        'pinned_bridge_vectors_equal': True,
    }


