def section_75_abstract_joint_pool_prefix_consistency(m: dict[str, list[int]]) -> dict:
    """Tier H11: Where shared ciphertext **forces** shared σ, joint `_abstract_ct_labels`
    transcripts agree on fixed **prefixes** (letter-for-letter in abstract space).

    Uses only structural overlaps from §50-style Fam-A / B-core literals — no
    vocabulary.
    """
    banner(75, 'JOINT-POOL ABSTRACT PREFIX CONSISTENCY (Tier H11)')

    # Fam A — absolute positions 1..11 (skip cross-message list-index digit at 0)
    pb = [('E1', 1, 12), ('W1', 1, 12), ('E2', 1, 12)]
    lb = _abstract_ct_labels(m, pb)
    t1 = ''.join(lb[m['E1'][p]] for p in range(1, 12))
    t2 = ''.join(lb[m['W1'][p]] for p in range(1, 12))
    t3 = ''.join(lb[m['E2'][p]] for p in range(1, 12))
    kv('Fam A [1,12) joint abstract (pos 0 excluded)', t1)
    assert t1 == t2 == t3

    # Fam A block 1 — first 13 chars align across the trio (§50)
    p1 = [('E1', 12, 25), ('W1', 12, 25), ('E2', 12, 25)]
    l1 = _abstract_ct_labels(m, p1)
    u1 = ''.join(l1[m['E1'][p]] for p in range(12, 25))
    u2 = ''.join(l1[m['W1'][p]] for p in range(12, 25))
    u3 = ''.join(l1[m['E2'][p]] for p in range(12, 25))
    kv('Fam A block-1 [12,25) joint abstract', u1)
    assert u1 == u2 == u3

    # B-core block 1 — identical 6-tuples (§50/§55)
    pc = [('E4', 10, 16), ('W4', 10, 16), ('E5', 10, 16)]
    lc = _abstract_ct_labels(m, pc)
    v4 = ''.join(lc[m['E4'][p]] for p in range(10, 16))
    vw = ''.join(lc[m['W4'][p]] for p in range(10, 16))
    v5 = ''.join(lc[m['E5'][p]] for p in range(10, 16))
    kv('B-core block-1 [10,16) joint abstract', v4)
    assert v4 == vw == v5

    print('  ⇒ Shared-CT regions yield **identical** abstract strings under a')
    print('    **single pooled** labelling pass per check (prefix / full span).')

    return {
        'famA_body_1_12_identical': True,
        'famA_block1_prefix_13_identical': True,
        'bcore_block1_6_identical': True,
    }


def section_76_pos0_policy_ablation_scan(m: dict[str, list[int]]) -> dict:
    """Tier H11: Enumerate pos-0 skip policies on the literal/isomorph merges.

    Policies refine which cross-message `(L,0)–(L',0)` unions are forbidden.
    Pairwise flip counts are vs **stock** (`build_class_union_find`).
    """
    banner(76, 'POS-0 POLICY ABLATION — CLASS COUNT & PARTITION DELTA (Tier H11)')

    uf_stock = build_class_union_find(m)
    n_stock = len({uf_stock.find(x) for x in uf_stock.parent})
    kv('policy `none` (stock) classes', n_stock)
    assert n_stock == 492

    rows: list[tuple[str, int, int, int]] = []
    for pol, n_exp, nflips in [
        ('fam_a', 494, 3),
        ('b_core', 494, 3),
        ('all', 496, 6),
    ]:
        uf = build_class_union_find_pos0_policy(m, pol)
        n = len({uf.find(x) for x in uf.parent})
        kv(f"policy `{pol}` classes", n)
        assert n == n_exp
        fl = _pairwise_class_equivalence_flips(m, uf_stock, uf)
        kv(f"pairwise class-relation flips vs stock (`{pol}`)", len(fl))
        assert len(fl) == nflips
        comp, br = _plaintext_class_partition(m, uf)
        w2fa = _w2_w3_bridge_headline_counts(m, comp, br)['w2_classmate_positions_famA']
        kv(f"  W2→Fam-A bridge headcount (`{pol}`)", f'{w2fa} / {len(m["W2"])}')
        assert w2fa == 5
        rows.append((pol, n, nflips, w2fa))
        print()

    print('  Reading: Fam-A-only and B-core-only splits each add **+2** classes')
    print('    vs stock (494); doing both (policy `all`) adds **+4** (496).')
    print('    §62 W2→Fam-A count stays **5** under every policy here.')

    return {'ablation_rows': rows}


def section_77_pos0_equivalence_minimal_change_certificate(m: dict[str, list[int]]) -> dict:
    """Tier H11: Formal certificate for the **stock vs `all`** partition delta.

    Strengthens §71: every flipped **pairwise** class relation touches only
    position **0**, and theflip edge set is **exactly** the two `K₃` cliques
    on message-index digits (Fam A and B-core).
    """
    banner(77, 'POS-0 SPLIT — MINIMAL CHANGE CERTIFICATE (Tier H11)')

    uf0 = build_class_union_find(m)
    uf1 = build_class_union_find_pos0_policy(m, 'all')
    flips = _pairwise_class_equivalence_flips(m, uf0, uf1)
    assert len(flips) == 6

    for x, y, _, _ in flips:
        assert x[1] == 0 and y[1] == 0

    got = {frozenset((x, y)) for x, y, _, _ in flips}
    expected = {
        frozenset((('E1', 0), ('W1', 0))),
        frozenset((('E1', 0), ('E2', 0))),
        frozenset((('W1', 0), ('E2', 0))),
        frozenset((('E4', 0), ('W4', 0))),
        frozenset((('E4', 0), ('E5', 0))),
        frozenset((('W4', 0), ('E5', 0))),
    }
    assert got == expected

    print('  Certified: **6** flipped unordered pairs; each is a distinct pos-0')
    print('    cross-message edge inside Fam A or inside B-core; no other pair')
    print('    changes equivalence (hence “minimal” edit to the relation).')

    return {'flipped_pairs': 6, 'only_pos0_indices': True, 'edge_set_is_two_K3': True}


def section_78_e1_invariant_w2_b61_65_ruleA_injectivity_baseline(
        m: dict[str, list[int]]) -> dict:
    """Tier H11+: **E1** unchanged under pos-0 variant; **W2[61..65]** Rule-A slot;
    §61 injectivity baseline (stock vs variant, no pins).

    Consolidates four reproducibility probes requested after §77.
    """
    banner(78, 'E1 INVARIANT, W2 [61,66) RULE-A SLOT, INJECTIVITY BASELINE (Tier H11+)')

    uf_stock = build_class_union_find(m)
    uf_variant = build_class_union_find_pos0_policy(m, 'all')

    ca = _normalized_uf_class_ids(m, uf_stock)
    cb = _normalized_uf_class_ids(m, uf_variant)
    for p in range(len(m['E1'])):
        assert ca[('E1', p)] == cb[('E1', p)], (p, ca[('E1', p)], cb[('E1', p)])
    n_e1 = len(m['E1'])
    for p in range(n_e1):
        for q in range(p + 1, n_e1):
            same_s = uf_stock.find(('E1', p)) == uf_stock.find(('E1', q))
            same_v = uf_variant.find(('E1', p)) == uf_variant.find(('E1', q))
            assert same_s == same_v, ((p, q), same_s, same_v)
    kv('probe E1: `_normalized_uf_class_ids` match stock vs variant (`all`)',
       f'{n_e1} / {n_e1} positions')
    kv('probe E1: within-E1 same-class predicate unchanged', 'all pairs OK')

    print()
    print('  Pos-0 policy `all` removes only cross-message merges among the nine')
    print('    list-index cells `(L,0)` with `L` ranging over messages;')
    print('    every literal/isomorph edge incident on `E1[p]` for `p≥1` is unchanged,')
    print('    and §77 certifies the **only** partition flips are six pos-0 pairs — none')
    print('    lie inside `E1×E1`, so dense IDs in scan order stay aligned on E1 and')
    print('    the within-E1 equivalence relation is identical to stock.')

    OBS = _observed_cuts_h4()
    bb = [0] + OBS['W2'] + [len(m['W2'])]
    found_bi = -1
    for bi in range(len(bb) - 1):
        lo, hi = bb[bi], bb[bi + 1]
        if lo <= 61 < hi:
            found_bi = bi
            assert lo == 60 and hi == 66, (bi, lo, hi)
            break
    assert found_bi == 5
    kv('probe W2: Rule-A block index for positions 61–65', found_bi)
    kv('probe W2: half-open span `_observed_cuts_h4()`', '[60, 66)')

    uf_pin = build_class_union_find_pos0_policy(m, 'all')
    uf_pin.union(('W2', 14), ('E1', 0))
    uf_pin.union(('W2', 15), ('W1', 0))
    comp, by_root = _plaintext_class_partition(m, uf_pin)
    FAM_A = {'E1', 'W1', 'E2'}

    expected_fam_a = {
        61: [('E1', 55), ('E1', 83), ('E2', 60), ('E2', 67), ('E2', 95),
             ('W1', 55), ('W1', 85)],
        62: [('E1', 56), ('E1', 84), ('E2', 61), ('E2', 68), ('E2', 96),
             ('W1', 56), ('W1', 86)],
        63: [('E1', 57), ('E1', 85), ('E2', 69), ('W1', 57), ('W1', 87)],
        64: [('E1', 58), ('E1', 86), ('E2', 70), ('W1', 58), ('W1', 60),
             ('W1', 88)],
        65: [('W1', 59)],
    }
    for p in range(61, 66):
        root = comp[('W2', p)]
        mates = sorted(x for x in by_root[root] if x[0] in FAM_A)
        kv(f'probe W2: Fam-A class-mates W2[{p}] (variant+pins)', mates)
        assert mates == expected_fam_a[p], (p, mates, expected_fam_a[p])

    print()
    print('  Structure: indices 61–65 occupy the **length-6** Rule-A block')
    print('    immediately after cut **60**; Fam-A ties come from literal/isomorph')
    print('    chains in the class graph.  **W2[65]** is special: its **only** Fam-A')
    print('    class-mate is **W1[59]** (no E1/E2 partner in that component).')

    v_st = _rule_a_block_injectivity_violations(m, uf_stock)
    v_va = _rule_a_block_injectivity_violations(m, uf_variant)
    kv('probe injectivity: violations stock (no pins)', len(v_st))
    kv('probe injectivity: violations variant `all` (no pins)', len(v_va))
    assert len(v_st) == 0 and len(v_va) == 0

    return {
        'e1_normalized_ids_match_stock_variant': True,
        'e1_within_msg_equivalence_unchanged': True,
        'w2_rule_a_block61_65': 5,
        'w2_span_61_65': (60, 66),
        'injectivity_violations_stock_no_pins': 0,
        'injectivity_violations_variant_no_pins': 0,
    }


def section_79_probe_anomalies_megacomponent_w3_w2_65(m: dict[str, list[int]]) -> dict:
    """Tier H11+: **Probe C / §78 tail** — largest stock component; W3 isolation;
    stock **W2[64]** vs **W2[65]** split inside Rule-A block `[60,66)`.

    **Probe C** found a unique **18**-cell component with labels
    `{E1,E2,E3,E4,E5,W1,W2,W4}` and no `W3`.  **§78** showed `W2[65]` has a
    thinner Fam-A envelope than `W2[61–64]` under variant+pins.  This section
    certifies the **exact** stock UF cells and explains both phenomena as
    structural (thresholded literal/isomorph graph), not bugs.
    """
    banner(79, 'ANOMALIES — MAX COMPONENT, W3, W2[64] vs W2[65] (Tier H11+)')

    uf = build_class_union_find(m)
    comp, by_root = _plaintext_class_partition(m, uf)
    sizes: dict[int, int] = {}
    for root in by_root:
        sz = len(by_root[root])
        sizes[sz] = sizes.get(sz, 0) + 1
    assert sizes.get(18, 0) == 1

    # Unique maximum-size component in stock UF at thresholds (5,15,2).
    roots18 = [r for r in by_root if len(by_root[r]) == 18]
    assert len(roots18) == 1
    cells18 = frozenset(by_root[roots18[0]])
    expected18 = frozenset({
        ('E1', 58), ('E1', 86), ('E2', 70),
        ('E3', 89), ('E3', 91),
        ('E4', 14), ('E4', 16), ('E4', 98),
        ('E5', 14), ('E5', 16), ('E5', 99),
        ('W1', 58), ('W1', 60), ('W1', 88),
        ('W2', 64),
        ('W4', 14), ('W4', 16), ('W4', 101),
    })
    assert cells18 == expected18
    labs18 = {L for L, _ in cells18}
    assert labs18 == {'E1', 'E2', 'E3', 'E4', 'E5', 'W1', 'W2', 'W4'}

    roots_w3 = {comp[('W3', p)] for p in range(len(m['W3']))}
    assert roots18[0] not in roots_w3
    n_w3_singleton = sum(
        1 for p in range(len(m['W3'])) if len(by_root[comp[('W3', p)]]) == 1
    )
    kv('stock UF: unique max component size', 18)
    kv('stock UF: labels in max component', sorted(labs18))
    kv('W3 positions in 1-cell components (isolated under stock UF)', n_w3_singleton)
    assert n_w3_singleton == 93

    print()
    print('  **W3 vs megacomponent:** no `W3` cell shares a class root with the')
    print('    18-cell cluster — and **93 / 124** W3 positions are **singleton**')
    print('    components (no merges with *any* other corpus cell at literal≥5 /')
    print('    iso≥15, repeats≥2).  The anomaly is **W3’s extreme sparsity** in this')
    print('    graph, not a missing edge inside the cluster.')

    r64 = comp[('W2', 64)]
    r65 = comp[('W2', 65)]
    assert r64 != r65
    assert len(by_root[r64]) == 18
    cells65 = frozenset(by_root[r65])
    expected65 = frozenset({
        ('E3', 90), ('E4', 15), ('E4', 99), ('E5', 15), ('E5', 100),
        ('W1', 59), ('W2', 65), ('W4', 15), ('W4', 102),
    })
    assert cells65 == expected65
    labs65 = {L for L, _ in cells65}
    kv('stock UF: W2[64] component size', len(by_root[r64]))
    kv('stock UF: W2[65] component size', len(by_root[r65]))
    kv('stock UF: labels in W2[65] component', sorted(labs65))
    assert 'E1' not in labs65 and 'E2' not in labs65

    print()
    print('  **W2[64] vs W2[65]** occupy the same Rule-A block `[60,66)` but sit in')
    print('    **different** stock components: `[64]` is in the **18**-cell graph')
    print('    (with E1[58], E2[70], …), while `[65]` is in a **9**-cell graph tied')
    print('    to **W1[59]** and B-core / E3 cells only — hence under variant+pins')
    print('    the only Fam-A pull to `W2[65]` is **W1[59]** (§78).')

    return {
        'stock_max_component_size': 18,
        'stock_max_component_labels': sorted(labs18),
        'w3_singleton_cells': n_w3_singleton,
        'w2_64_in_max_component': True,
        'w2_65_component_size': 9,
        'w2_65_has_no_e1_e2_in_stock_component': True,
    }


def _stock_megacomponent_18_cells(m: dict[str, list[int]]) -> frozenset[tuple[str, int]]:
    """The unique size-18 `build_class_union_find` component (see §79)."""
    uf = build_class_union_find(m)
    comp, by_root = _plaintext_class_partition(m, uf)
    roots18 = [r for r in by_root if len(by_root[r]) == 18]
    assert len(roots18) == 1
    return frozenset(by_root[roots18[0]])


def _typed_direct_edges_among_cells(
    m: dict[str, list[int]],
    cellset: set[tuple[str, int]],
    *,
    literal_min: int,
    iso_min_len: int,
    iso_min_reps: int,
) -> dict[frozenset[tuple[str, int]], frozenset[str]]:
    """Map undirected intra-`cellset` edge → source kinds ``literal`` / ``isomorph``."""
    edge_modes: dict[frozenset[tuple[str, int]], set[str]] = defaultdict(set)
    for l1, l2 in combinations(MSG_LABELS, 2):
        for i, j, L in find_pair_literal_matches(m[l1], m[l2], literal_min):
            for k in range(L):
                a, b = (l1, i + k), (l2, j + k)
                if a in cellset and b in cellset:
                    edge_modes[frozenset((a, b))].add('literal')
        for i, j, L in find_pair_isomorphs(m[l1], m[l2], iso_min_len, iso_min_reps):
            for k in range(L):
                a, b = (l1, i + k), (l2, j + k)
                if a in cellset and b in cellset:
                    edge_modes[frozenset((a, b))].add('isomorph')
    return {k: frozenset(v) for k, v in edge_modes.items()}


def _direct_uf_edges_among_cells(
    m: dict[str, list[int]],
    cellset: set[tuple[str, int]],
    *,
    literal_min: int,
    iso_min_len: int,
    iso_min_reps: int,
) -> set[frozenset[tuple[str, int]]]:
    """Undirected edges from literal/isomorph scans with both endpoints in `cellset`."""
    return set(_typed_direct_edges_among_cells(
        m, cellset,
        literal_min=literal_min, iso_min_len=iso_min_len, iso_min_reps=iso_min_reps,
    ).keys())


def _rule_a_block_index(msg: dict[str, list[int]], L: str, pos: int) -> int:
    """Rule-A half-open block index containing absolute position ``pos`` on ``L``."""
    bb = [0] + _observed_cuts_h4()[L] + [len(msg[L])]
    for bi in range(len(bb) - 1):
        if bb[bi] <= pos < bb[bi + 1]:
            return bi
    raise AssertionError((L, pos, bb))


def section_80_probes_abcd_formal_lock_in(m: dict[str, list[int]]) -> dict:
    """Tier H12: Formalize **probes A, B, D** from `probes_abcd_union_find_note.txt`.

    Probe **C** is covered by **§79** (exact 18-cell set + W3 singleton count).
    """
    banner(80, 'PROBES A / B / D — FORMAL LOCK-IN (Tier H12)')

    uf0 = build_class_union_find(m)
    uf1 = build_class_union_find_pos0_policy(m, 'all')

    n_pairs = 0
    for L in MSG_LABELS:
        n = len(m[L])
        for p in range(n):
            for q in range(p + 1, n):
                n_pairs += 1
                s0 = uf0.find((L, p)) == uf0.find((L, q))
                s1 = uf1.find((L, p)) == uf1.find((L, q))
                assert s0 == s1, ((L, p, q), s0, s1)
    kv('probe A: same-message pairs checked', n_pairs)
    kv('probe A: within-message class relation stock vs variant `all`', 'identical')

    comp, br = _plaintext_class_partition(m, uf1)
    FAM_A = {'E1', 'W1', 'E2'}
    w3_fa_hits: list[int] = []
    for p in range(len(m['W3'])):
        r = comp[('W3', p)]
        if any(L in FAM_A and (L, q) != ('W3', p) for L, q in br[r]):
            w3_fa_hits.append(p)
    kv('probe B: W3 positions with Fam-A class-mate (variant, no pins)', w3_fa_hits)
    assert w3_fa_hits == []

    body = min(len(m['E1']), len(m['W1'])) - 1
    drift = 0
    for p in range(1, body + 1):
        a0 = uf0.find(('E1', p)) == uf0.find(('W1', p))
        a1 = uf1.find(('E1', p)) == uf1.find(('W1', p))
        assert a0 == a1
        if a0:
            drift += 1
    kv('probe D: aligned E1/W1 body indices p=1..', body)
    kv('probe D: positions with (E1,p)~(W1,p) same class (both UFs)', drift)

    print()
    print('  Locks in the three informal probes as harness assertions (probe C → §79).')

    return {
        'probe_a_pairs_checked': n_pairs,
        'probe_b_w3_famA_positions': 0,
        'probe_d_body_max_p': body,
    }


def section_81_stock_megacomponent_direct_union_edges(m: dict[str, list[int]]) -> dict:
    """Tier H12: **Edge-origin scan** for the §79 **18**-cell stock component.

    Lists undirected **direct** unions (literal≥5 or isomorph≥15) with **both**
    endpoints inside the mega-set — structural hooks for how the blob fuses.
    """
    banner(81, 'STOCK MEGACOMPONENT — DIRECT UNION EDGES (Tier H12)')

    cellset = set(_stock_megacomponent_18_cells(m))
    typed = _typed_direct_edges_among_cells(
        m, cellset, literal_min=5, iso_min_len=15, iso_min_reps=2,
    )
    kv('undirected direct edges (both ends in 18-set)', len(typed))
    assert len(typed) == 31

    def label_modes(mm: frozenset[str]) -> str:
        if mm == frozenset({'literal'}):
            return 'LIT'
        if mm == frozenset({'isomorph'}):
            return 'ISO'
        if mm == frozenset({'literal', 'isomorph'}):
            return 'LIT+ISO'
        raise AssertionError(mm)

    n_lit = sum(1 for mm in typed.values() if mm == frozenset({'literal'}))
    n_iso = sum(1 for mm in typed.values() if mm == frozenset({'isomorph'}))
    n_mix = sum(
        1 for mm in typed.values() if mm == frozenset({'literal', 'isomorph'}))
    kv('among them: literal-only edges', n_lit)
    kv('among them: isomorph-only edges', n_iso)
    kv('among them: witnessed by **both** mechanisms', n_mix)
    assert n_lit == 0 and n_iso == 25 and n_mix == 6

    def keypair(f: frozenset) -> tuple:
        x, y = sorted(f)
        return (x[0], x[1], y[0], y[1])

    shown = sorted(typed.keys(), key=keypair)

    for e in shown[:24]:
        a, b = sorted(e)
        kv(f'  edge [{label_modes(typed[e])}]', f'{a} — {b}')
    if len(typed) > 24:
        kv('  …', f'{len(typed) - 24} further edges')

    print()
    print('  Typed scan: megacomponent cohesion is overwhelmingly **isomorph**-borne')
    print('    (25 iso-only + 6 lit+iso); **no** edge is purely **literal-only**.')

    print()
    print('  Edges are **direct** segment matches; full connectivity of the 18-set')
    print('    is transitive through union-find closure (cells outside may mediate paths).')

    return {
        'direct_edges_inside_mega18': len(typed),
        'mega18_edges_literal_only': n_lit,
        'mega18_edges_isomorph_only': n_iso,
        'mega18_edges_literal_and_isomorph': n_mix,
    }


def section_82_w3_singleton_vs_literal_threshold(m: dict[str, list[int]]) -> dict:
    """Tier H12: **W3 isolation** vs **literal_min** (iso parameters held at defaults).

    §79 uses literal **≥5**.  Here we tabulate how many **W3** cells stay in
    global **singleton** components when literal_min is relaxed/tightened.
    """
    banner(82, 'W3 ISOLATION vs LITERAL_MIN (Tier H12)')

    def n_w3_singleton(lm: int) -> int:
        uf = build_class_union_find(m, literal_min=lm)
        comp, br = _plaintext_class_partition(m, uf)
        return sum(
            1 for p in range(len(m['W3']))
            if len(br[comp[('W3', p)]]) == 1
        )

    for lm in (3, 4, 5, 6):
        ns = n_w3_singleton(lm)
        kv(f'W3 positions in 1-cell components (literal_min={lm})', f'{ns} / {len(m["W3"])}')

    assert n_w3_singleton(3) == 93
    assert n_w3_singleton(5) == 93
    assert n_w3_singleton(4) == 93
    assert n_w3_singleton(6) == 98
    assert n_w3_singleton(6) > n_w3_singleton(5)

    print()
    print('  Lowering **literal_min** to **3** or **4** still yields **93** singleton W3')
    print('    cells — no extra cross-message literal runs at those minima touch W3 in')
    print('    a way that changes its UF degree.  **Raising** **literal_min** to **6**')
    print('    isolates **5** more W3 cells (stricter graph).')

    return {'w3_singletons_literal4': n_w3_singleton(4), 'w3_singletons_literal5': 93, 'w3_singletons_literal6': n_w3_singleton(6)}


def section_83_csp_shell_json_artifact(m: dict[str, list[int]]) -> dict:
    """Tier H12: Machine-readable **CSP shell** snapshot for downstream tooling.

    Writes `eye/uf_csp_shell_artifact_v1.json` next to the harness (regenerated
    each full run when this section executes).
    """
    banner(83, 'CSP SHELL ARTIFACT (JSON export, Tier H12)')

    uf_s = build_class_union_find(m)
    n_stock = len({uf_s.find(x) for x in uf_s.parent})

    uf_v = build_class_union_find_pos0_policy(m, 'all')
    n_var = len({uf_v.find(x) for x in uf_v.parent})

    assert m['W2'][14] == m['E1'][0] and m['W2'][15] == m['W1'][0]
    uf_pin = build_class_union_find_pos0_policy(m, 'all')
    uf_pin.union(('W2', 14), ('E1', 0))
    uf_pin.union(('W2', 15), ('W1', 0))
    n_pin = len({uf_pin.find(x) for x in uf_pin.parent})
    inj_pin = len(_rule_a_block_injectivity_violations(m, uf_pin))
    assert inj_pin == 0

    cell18 = set(_stock_megacomponent_18_cells(m))
    mega_tm = _typed_direct_edges_among_cells(
        m, cell18, literal_min=5, iso_min_len=15, iso_min_reps=2,
    )
    mega_lit = sum(1 for mm in mega_tm.values() if mm == frozenset({'literal'}))
    mega_iso = sum(1 for mm in mega_tm.values() if mm == frozenset({'isomorph'}))
    mega_mix = sum(
        1 for mm in mega_tm.values() if mm == frozenset({'literal', 'isomorph'}))

    cuts = _observed_cuts_h4()
    payload = {
        'schema': 'uf_csp_shell_artifact_v1',
        'csp_hints_script': str(Path(__file__).resolve().parent / 'emit_uf_csp_hints.py'),
        'csp_hints_validate_script': str(
            Path(__file__).resolve().parent / 'validate_uf_csp_hints.py'),
        'tier_h_doc_and_harness': 'eye/CRYPTANALYSIS.md §26 (Tier H), eye/cryptanalysis_harness.py §47–§86',
        'union_find_stock': {
            'literal_min': 5,
            'isomorph_min_len': 15,
            'isomorph_min_reps': 2,
            'plaintext_class_count': n_stock,
        },
        'union_find_pos0_policy_all': {
            'plaintext_class_count': n_var,
        },
        'union_find_pos0_policy_all_with_section50_pins': {
            'plaintext_class_count': n_pin,
            'rule_a_injectivity_violations': inj_pin,
            'ct_pins': [
                {'cell_a': ['W2', 14], 'cell_b': ['E1', 0]},
                {'cell_a': ['W2', 15], 'cell_b': ['W1', 0]},
            ],
        },
        'stock_megacomponent_18_direct_edges': {
            'literal_only': mega_lit,
            'isomorph_only': mega_iso,
            'literal_and_isomorph': mega_mix,
            'total_direct_edges': len(mega_tm),
        },
        'rule_a_cuts': cuts,
        'message_lengths': {L: len(m[L]) for L in MSG_LABELS},
        'total_ciphertext_cells': sum(len(m[L]) for L in MSG_LABELS),
        'next_falsifiable_steps': [
            'Per-Rule-A-block σ injection consistent with pos0-split UF + §50 CT pins.',
            'Run `python eye/emit_uf_csp_hints.py` from the repo root to export merge components.',
            'Run `python eye/validate_uf_csp_hints.py path.json` round-trip sanity.',
            'Cross-check §81 typed mega-edges vs candidate σ overlaps (§86).',
        ],
    }

    out_path = Path(__file__).resolve().parent / 'uf_csp_shell_artifact_v1.json'
    with open(out_path, 'w') as fh:
        json.dump(payload, fh, indent=2, sort_keys=True)
    kv('wrote', str(out_path))

    return {'artifact_path': str(out_path), 'plaintext_classes_stock': n_stock}


def section_84_w2_singleton_vs_literal_threshold(m: dict[str, list[int]]) -> dict:
    """Tier H12: **W2 isolation** mirror of §82 — singleton cells vs **literal_min**."""
    banner(84, 'W2 ISOLATION vs LITERAL_MIN (Tier H12)')

    def n_w2_singleton(lm: int) -> int:
        uf = build_class_union_find(m, literal_min=lm)
        comp, br = _plaintext_class_partition(m, uf)
        return sum(
            1 for p in range(len(m['W2']))
            if len(br[comp[('W2', p)]]) == 1
        )

    for lm in (3, 4, 5, 6):
        kv(f'W2 positions in 1-cell components (literal_min={lm})',
           f'{n_w2_singleton(lm)} / {len(m["W2"])}')

    assert n_w2_singleton(3) == 52
    assert n_w2_singleton(6) == 57
    assert n_w2_singleton(6) > n_w2_singleton(5)

    print()
    print('  W2 reacts to **raising** literal_min (6) like W3→§82, but not to')
    print('    **lowering** 3—4 versus 5 (no new literal merges touch W2 there).')

    return {'w2_singletons_literal5': n_w2_singleton(5), 'w2_singletons_literal6': n_w2_singleton(6)}


def section_85_e1_w1_aligned_class_indices_vs_rule_a(m: dict[str, list[int]]) -> dict:
    """Tier H12: tabulate **`(E1,p)~(W1,p)` stock UF** merges with Rule-A block IDs.

    The **55** body indices flagged in §80 as sharing a plaintext class across
    the aligned Fam-A pair are enumerated with **distinct** `(block_E1,
    block_W1)` because Rule-A cuts differ between messages.
    """
    banner(85, 'ALIGNED E1/W1 SAME-CLASS INDICES × RULE-A (Tier H12)')

    uf = build_class_union_find(m)
    body_hi = min(len(m['E1']), len(m['W1'])) - 1
    expected_aligned = tuple(list(range(1, 25)) + list(range(28, 59)))
    rows = []
    for p in range(1, body_hi + 1):
        if uf.find(('E1', p)) != uf.find(('W1', p)):
            continue
        b1 = _rule_a_block_index(m, 'E1', p)
        bw = _rule_a_block_index(m, 'W1', p)
        rows.append((p, b1, bw))

    pts = tuple(r[0] for r in rows)
    kv('indices p with `(E1,p)~(W1,p)` in stock UF same class', len(rows))
    assert pts == expected_aligned

    print('  Tabular `(p | RuleA[E1], RuleA[W1])`:')
    for p, b1, bw in rows:
        kv(f'    p={p:3d}', f'E1 block {b1},  W1 block {bw}')

    print()
    print('  Gaps **25–27** correspond to divergent Fam-A plaintext / segment')
    print('    alignment (literal matches still cross-link nearby blocks).')

    return {'aligned_e1_w1_positions': len(rows), 'body_upper_p_exclusive': body_hi}


def section_86_rule_a_sigma_shell_variant_pinned_vs_mega18(
        m: dict[str, list[int]]) -> dict:
    """Tier H13: **Rule-A per-block σ shell** under **variant+pins** + §81 reading.

    Fix one plaintext letter per UF class.  For each Rule-A block, require
    pairwise distinct letters across its cells — equivalent to
    ``_rule_a_block_injectivity_violations`` being empty (QuadSolver's
    per-block coloring constraint, but with **Rule-A** blocks from
    ``_observed_cuts_h4`` rather than Tier C1's co-block partition).

    Combines with §58 ciphertext injectivity inside each block so a **per-block**
    bijection ``ciphertext_symbol → plaintext_letter`` exists combinatorially.

    §81 mega-18 **direct** edges classify *how* classes are glued: **literal**
    edges carry raw CT identity along a parallel segment; **isomorph-only**
    edges do not.
    """
    banner(86,
           'RULE-A σ SHELL (variant+pins) + §81 MEGA18 EDGE READING (Tier H13)')

    kind = 'variant-pinned'
    uf = union_find_from_uf_mode(m, kind)
    inj = _rule_a_block_injectivity_violations(m, uf)
    kv('union-find mode', kind)
    kv('Rule-A class injectivity violations', len(inj))
    assert len(inj) == 0

    dense = _normalized_uf_class_ids(m, uf)
    OBS = _observed_cuts_h4()
    n_blocks = 0
    bad_ct = 0
    bad_cls = 0
    for L in MSG_LABELS:
        bb = [0] + OBS[L] + [len(m[L])]
        for bi in range(len(bb) - 1):
            lo, hi_ex = bb[bi], bb[bi + 1]
            pts = list(range(lo, hi_ex))
            n_blocks += 1
            ct_set = {m[L][p] for p in pts}
            cl_set = {dense[(L, p)] for p in pts}
            if len(ct_set) != len(pts):
                bad_ct += 1
            if len(cl_set) != len(pts):
                bad_cls += 1

    kv('Rule-A blocks checked (OBS cuts)', n_blocks)
    assert n_blocks == 91
    assert bad_ct == 0
    assert bad_cls == 0

    cell18 = set(_stock_megacomponent_18_cells(m))
    typed = _typed_direct_edges_among_cells(
        m, cell18,
        literal_min=5, iso_min_len=15, iso_min_reps=2,
    )
    n_lit = sum(1 for mm in typed.values() if mm == frozenset({'literal'}))
    n_iso = sum(1 for mm in typed.values() if mm == frozenset({'isomorph'}))
    n_mix = sum(
        1 for mm in typed.values() if mm == frozenset({'literal', 'isomorph'}))
    assert len(typed) == 31
    assert (n_lit, n_iso, n_mix) == (0, 25, 6)

    kv('§81 mega18 direct edges (typed)', len(typed))
    kv('    literal-only witnesses', n_lit)
    kv('    isomorph-only witnesses', n_iso)
    kv('    literal+isomorph witnesses', n_mix)

    print()
    print('  Reading: variant+pins admits a **combinatorial** injective-assignment')
    print('    shell on Rule-A blocks (distinct CT + distinct class per slot).')
    print('    **Literal** mega-edges expose ``CT[i..]`` overlaps between messages;')
    print('    **isomorph-only** edges identify classes via pattern families without')
    print('    a length-witness that is a verbatim CT run on both sides.')

    return {
        'rule_a_blocks': n_blocks,
        'rule_a_ct_injective_blocks': 91 - bad_ct,
        'rule_a_class_injective_blocks': 91 - bad_cls,
        'mega18_edges': len(typed),
        'mega18_iso_only_edges': n_iso,
        'mega18_literal_plus_iso_edges': n_mix,
    }


def section_87_same_ct_cross_block_merge(m: dict[str, list[int]]) -> dict:
    """Tier H14: **same-ct cross-block merge** — the dist-4 resolution.

    Within a single message, two positions with the same ciphertext value
    must encode the same plaintext class IF they are in the same block
    (monoalphabetic within blocks).  When they are in DIFFERENT blocks, the
    isomorph detector cannot link them (different substitutions produce
    different ct for the same class, so no isomorph chain bridges them).

    This section proves that iteratively merging all within-message same-ct
    position pairs at empirically-safe distances converges to 53 blocks and
    402 classes (from 91/492), with zero σ-injectivity violations.

    This fully explains the dist-4 anomaly (§4/§20): all 26 dist-4
    ct-repeats were positions encoding the SAME plaintext symbol, separated
    into different classes only because the block boundary between them
    prevented the isomorph detector from linking them.

    After absorbing all safe merges, a residual cross-block ct-match signal
    survives at boundary offset (end-8, start+0) = dist-9: 10/43 transitions
    show ct agreement at 19.3x the independent baseline.  Merging those
    INCREASES block count, proving they are genuinely different plaintext
    symbols — this is real σ carry-over, not an under-merged class.
    """
    banner(87, 'SAME-CT CROSS-BLOCK MERGE — DIST-4 RESOLUTION (Tier H14)')

    # ── baseline: standard UF (91 blocks, 492 classes) ──
    uf_baseline = build_class_union_find(m)
    n_classes_baseline = len({uf_baseline.find((l, p))
                              for l in MSG_LABELS for p in range(len(m[l]))})
    assert n_classes_baseline == 492, n_classes_baseline
    kv('baseline classes', n_classes_baseline)

    # ── apply cumulative same-ct merges ──
    uf = build_class_union_find(m)
    n_merged = merge_same_ct_cross_block(m, uf)

    n_classes = len({uf.find((l, p))
                     for l in MSG_LABELS for p in range(len(m[l]))})
    kv('same-ct merge operations', n_merged)
    kv('classes after merge', n_classes)
    assert n_classes == 402, n_classes

    # ── rebuild blocks under the merged UF ──
    all_blocks: list[tuple[str, int, int]] = []
    for l in MSG_LABELS:
        ct = m[l]
        ct_to_class: dict[int, object] = {}
        class_to_ct: dict[object, int] = {}
        block_start = 0
        for pos in range(len(ct)):
            cls = uf.find((l, pos))
            v = ct[pos]
            contradicts = ((cls in class_to_ct and class_to_ct[cls] != v)
                           or (v in ct_to_class and ct_to_class[v] != cls))
            if contradicts:
                all_blocks.append((l, block_start, pos - 1))
                block_start = pos
                ct_to_class = {}
                class_to_ct = {}
            ct_to_class[v] = cls
            class_to_ct[cls] = v
        all_blocks.append((l, block_start, len(ct) - 1))

    n_blocks = len(all_blocks)
    kv('blocks after merge', n_blocks)
    assert n_blocks == 53, n_blocks

    # ── verify σ-injectivity: class→ct is functional within each block ──
    sigma_violations = 0
    for l, s, e in all_blocks:
        sigma: dict[object, int] = {}
        for p in range(s, e + 1):
            cls = uf.find((l, p))
            v = m[l][p]
            if cls in sigma and sigma[cls] != v:
                sigma_violations += 1
            sigma[cls] = v
    kv('σ-injectivity violations', sigma_violations)
    assert sigma_violations == 0

    # ── verify ct→class injectivity within each block ──
    ct_inj_violations = 0
    for l, s, e in all_blocks:
        ct_to_cls: dict[int, object] = {}
        for p in range(s, e + 1):
            cls = uf.find((l, p))
            v = m[l][p]
            if v in ct_to_cls and ct_to_cls[v] != cls:
                ct_inj_violations += 1
            ct_to_cls[v] = cls
    kv('CT→class injectivity violations', ct_inj_violations)
    assert ct_inj_violations == 0

    # ── count new cross-message links gained from the merge ──
    new_cross_links = 0
    # For each class in the merged UF, count cross-message pairs
    # that weren't linked in the baseline UF.
    class_members: dict[object, list[tuple[str, int]]] = {}
    for l in MSG_LABELS:
        for p in range(len(m[l])):
            root = uf.find((l, p))
            if root not in class_members:
                class_members[root] = []
            class_members[root].append((l, p))

    for root, members in class_members.items():
        for i in range(len(members)):
            for j in range(i + 1, len(members)):
                l1, p1 = members[i]
                l2, p2 = members[j]
                if l1 != l2:
                    if uf_baseline.find((l1, p1)) != uf_baseline.find((l2, p2)):
                        new_cross_links += 1

    kv('new cross-message position links', new_cross_links)
    assert new_cross_links == 1077, new_cross_links

    # ── block length distribution ──
    lengths = [e - s + 1 for _, s, e in all_blocks]
    kv('mean block length', f'{sum(lengths) / len(lengths):.1f}')
    kv('min block length', min(lengths))
    kv('max block length', max(lengths))

    # ── σ-key uniqueness ──
    sigma_keys: set[frozenset] = set()
    for l, s, e in all_blocks:
        sigma = {}
        for p in range(s, e + 1):
            cls = uf.find((l, p))
            sigma[cls] = m[l][p]
        sigma_keys.add(frozenset(sigma.items()))
    kv('distinct σ-keys', len(sigma_keys))
    assert len(sigma_keys) == n_blocks  # each block has a unique σ

    print()
    print('  The dist-4 anomaly is fully explained: every dist-4 ct-repeat')
    print('  represents two positions encoding the SAME plaintext symbol,')
    print('  separated into different classes because the isomorph detector')
    print('  cannot bridge block boundaries (different substitutions mean')
    print('  different ct for the same class).')
    print()
    print('  After convergence, a residual cross-block signal survives at')
    print('  boundary offset (end-8, start+0) = dist-9: 19.3x baseline.')
    print('  Merging those INCREASES blocks → genuine σ carry-over, not')
    print('  under-merged classes. Adjacent σ tables share partial structure.')
    print()
    pct_blk = 100 * (91 - n_blocks) / 91
    pct_cls = 100 * (492 - n_classes) / 492
    print(f'  91 → {n_blocks} blocks  ({pct_blk:.0f}% reduction)')
    print(f'  492 → {n_classes} classes  ({pct_cls:.0f}% reduction)')
    print(f'  {new_cross_links} new cross-message links gained.')

    return {
        'uf_merged': uf,
        'n_classes': n_classes,
        'n_blocks': n_blocks,
        'n_merged': n_merged,
        'sigma_violations': sigma_violations,
        'new_cross_links': new_cross_links,
        'blocks': all_blocks,
    }


def _full_merge_pipeline(m: dict[str, list[int]]) -> tuple:
    """Shared helper: full merge pipeline producing the 357-class model.

    Returns (uf, blocks_dict) where blocks_dict maps msg_label → list of
    (start, end) tuples. Used by §88-§90 and the hill climber.
    """
    uf = build_class_union_find(m)
    merge_same_ct_cross_block(m, uf)

    # Explicit isomorph merges: same plaintext at aligned positions
    for l1, l2, i, j, L in [
        ('E4', 'E5', 0, 0, 28), ('E4', 'W4', 0, 0, 25),
        ('W4', 'E5', 0, 0, 25), ('W2', 'W3', 15, 20, 23),
        ('E2', 'W3', 16, 0, 21),
    ]:
        for k in range(L):
            uf.union((l1, i + k), (l2, j + k))

    # σ₀-derived within-family merges
    uf.union(('E3', 11), ('E3', 42))
    uf.union(('E5', 96), ('W3', 47))

    # Iterative cross-block σ propagation
    sigma_groups: dict = {0: [{'E1', 'W1', 'E2'}, {'E4', 'W4', 'E5'}]}
    for _iter in range(10):
        bks: dict[str, list[tuple[int, int]]] = {}
        for l in MSG_LABELS:
            ct = m[l]; c2c: dict = {}; cc: dict = {}
            blk: list = []; bs = 0
            for pos in range(len(ct)):
                cls = uf.find((l, pos)); v = ct[pos]
                if ((cls in cc and cc[cls] != v) or
                        (v in c2c and c2c[v] != cls)):
                    blk.append((bs, pos - 1)); bs = pos
                    c2c = {}; cc = {}
                c2c[v] = cls; cc[cls] = v
            blk.append((bs, len(ct) - 1)); bks[l] = blk

        nb = len({uf.find((l, p)) for l in MSG_LABELS
                  for p in range(len(m[l]))})
        ng: dict = {}
        for bi in sorted(sigma_groups.keys()):
            for group in sigma_groups[bi]:
                msgs = [l for l in group if bi + 1 < len(bks[l])]
                if len(msgs) < 2:
                    continue
                cg: dict = defaultdict(set)
                for l in msgs:
                    s1, e1 = bks[l][bi]; s2, e2 = bks[l][bi + 1]
                    m1 = {uf.find((l, p)): m[l][p]
                          for p in range(s1, e1 + 1)}
                    m2 = {uf.find((l, p)): m[l][p]
                          for p in range(s2, e2 + 1)}
                    sh = set(m1) & set(m2)
                    key = frozenset(
                        (uf.find(c), m1[c], m2[c])
                        for c in sh if m1[c] != m2[c])
                    cg[key].add(l)
                for key, sub in cg.items():
                    if len(sub) < 2:
                        continue
                    tc: dict = defaultdict(set)
                    for l in sub:
                        s, e = bks[l][bi + 1]
                        for p in range(s, e + 1):
                            tc[m[l][p]].add(uf.find((l, p)))
                    for ctv, classes in tc.items():
                        if len(classes) > 1:
                            cl = list(classes)
                            for c in cl[1:]:
                                uf.union(c, cl[0])
                    if bi + 1 not in ng:
                        ng[bi + 1] = []
                    ng[bi + 1].append(sub)
        merge_same_ct_cross_block(m, uf)
        na = len({uf.find((l, p)) for l in MSG_LABELS
                  for p in range(len(m[l]))})
        if na == nb:
            break
        sigma_groups = ng

    # Final block detection
    blocks: dict[str, list[tuple[int, int]]] = {}
    for l in MSG_LABELS:
        ct = m[l]; c2c = {}; cc = {}; blk = []; bs = 0
        for pos in range(len(ct)):
            cls = uf.find((l, pos)); v = ct[pos]
            if ((cls in cc and cc[cls] != v) or
                    (v in c2c and c2c[v] != cls)):
                blk.append((bs, pos - 1)); bs = pos; c2c = {}; cc = {}
            c2c[v] = cls; cc[cls] = v
        blk.append((bs, len(ct) - 1)); blocks[l] = blk

    return uf, blocks


def section_88_full_merge_pipeline(m: dict[str, list[int]]) -> dict:
    """Tier H15: **full merge pipeline** — 357 classes, 57 blocks.

    Consolidates all proven merges into a single verified pipeline:
    1. Base isomorph UF (492 classes)
    2. Same-ct cross-block merges (→ 402 classes)
    3. Explicit isomorph merges at known aligned positions
    4. σ₀-derived within-family merges
    5. Iterative cross-block σ propagation

    Converges to 357 classes in 57 blocks with zero σ-injectivity
    violations, ready for the autokey state machine analysis.
    """
    banner(88, 'FULL MERGE PIPELINE — 357 CLASSES (Tier H15)')

    uf, blocks = _full_merge_pipeline(m)

    n_classes = len({uf.find((l, p))
                     for l in MSG_LABELS for p in range(len(m[l]))})
    n_blocks = sum(len(blocks[l]) for l in MSG_LABELS)

    kv('classes after full pipeline', n_classes)
    kv('blocks after full pipeline', n_blocks)
    assert n_classes == 357, n_classes
    assert n_blocks == 57, n_blocks

    # Verify σ-injectivity within each block
    sigma_violations = 0
    for l in MSG_LABELS:
        for s, e in blocks[l]:
            sigma: dict = {}
            for p in range(s, e + 1):
                cls = uf.find((l, p))
                v = m[l][p]
                if cls in sigma and sigma[cls] != v:
                    sigma_violations += 1
                sigma[cls] = v
    kv('σ-injectivity violations', sigma_violations)
    assert sigma_violations == 0

    # Verify within-block ct→class injectivity
    ct_violations = 0
    for l in MSG_LABELS:
        for s, e in blocks[l]:
            ct_map: dict = {}
            for p in range(s, e + 1):
                cls = uf.find((l, p))
                v = m[l][p]
                if v in ct_map and ct_map[v] != cls:
                    ct_violations += 1
                ct_map[v] = cls
    kv('ct→class violations', ct_violations)
    assert ct_violations == 0

    # Block count per message
    for l in MSG_LABELS:
        kv(f'  {l} blocks', len(blocks[l]))

    # Family membership: which classes appear in which family?
    alpha_msgs = {'E1', 'W1', 'E2'}
    beta_msgs = {'E4', 'W4', 'E5'}
    bridge_msgs = {'W2', 'E3', 'W3'}

    alpha_cls = {uf.find((l, p)) for l in alpha_msgs
                 for p in range(len(m[l]))}
    beta_cls = {uf.find((l, p)) for l in beta_msgs
                for p in range(len(m[l]))}
    bridge_cls = {uf.find((l, p)) for l in bridge_msgs
                  for p in range(len(m[l]))}

    abc = alpha_cls & beta_cls & bridge_cls
    kv('classes in all 3 families (α∩β∩bridge)', len(abc))
    assert len(abc) == 16

    kv('α-only classes', len(alpha_cls - beta_cls - bridge_cls))
    kv('β-only classes', len(beta_cls - alpha_cls - bridge_cls))
    kv('bridge-only classes', len(bridge_cls - alpha_cls - beta_cls))

    return {
        'uf': uf,
        'blocks': blocks,
        'n_classes': n_classes,
        'n_blocks': n_blocks,
        'alpha_cls': alpha_cls,
        'beta_cls': beta_cls,
        'bridge_cls': bridge_cls,
    }


def section_89_motif_period_census(m: dict[str, list[int]]) -> dict:
    """Tier H16: **motif discovery, period structure, symbol census**.

    Proves:
    - A 15-class β-motif recurs in E4 (gap=84), W4 (gap=87), E5 (gap=85)
    - An 18-class α-motif recurs in E1 (gap=28), W1 (gap=30), E2 (gap=35)
    - The plaintext has a message-specific period holding for ~27 positions
    - E1 and W1 share 27/28 classes at positions 32–59 (convergence)
    - 27 of 28 symbols are identified across α/β/bridge families
    - W3_19 is constrained to exactly 2 candidates: E5_93 or E5_94
    """
    banner(89, 'MOTIF + PERIOD + SYMBOL CENSUS (Tier H16)')

    uf, blocks = _full_merge_pipeline(m)

    # ── β-motif: 15 classes at E4 positions 1-15 ──
    beta_motif = [uf.find(('E4', p)) for p in range(1, 16)]
    assert len(set(beta_motif)) == 14  # 15 positions, 14 unique (E3_41 repeats)

    # Verify β-motif recurrence in β-core messages
    beta_gaps: dict[str, int] = {}
    for l in ['E4', 'W4', 'E5']:
        starts = []
        for s in range(len(m[l]) - 14):
            if all(uf.find((l, s + i)) == beta_motif[i] for i in range(15)):
                starts.append(s)
        assert len(starts) == 2, f'{l}: {starts}'
        beta_gaps[l] = starts[1] - starts[0]

    kv('β-motif gap E4', beta_gaps['E4'])
    kv('β-motif gap W4', beta_gaps['W4'])
    kv('β-motif gap E5', beta_gaps['E5'])
    assert beta_gaps['E4'] == 84
    assert beta_gaps['W4'] == 87
    assert beta_gaps['E5'] == 85

    # ── α-motif: 18 classes at E1 positions 33-50 ──
    alpha_motif = [uf.find(('E1', p)) for p in range(33, 51)]
    assert len(alpha_motif) == 18
    assert len(set(alpha_motif)) == 15  # 18 positions, 15 unique (3 repeat)

    alpha_gaps: dict[str, int] = {}
    for l in ['E1', 'W1', 'E2']:
        starts = []
        for s in range(len(m[l]) - 17):
            if all(uf.find((l, s + i)) == alpha_motif[i] for i in range(18)):
                starts.append(s)
        assert len(starts) >= 2, f'{l}: {starts}'
        alpha_gaps[l] = starts[1] - starts[0]

    kv('α-motif gap E1', alpha_gaps['E1'])
    kv('α-motif gap W1', alpha_gaps['W1'])
    kv('α-motif gap E2', alpha_gaps['E2'])
    assert alpha_gaps['E1'] == 28
    assert alpha_gaps['W1'] == 30
    assert alpha_gaps['E2'] == 35

    # ── period verification: E1[p] = E1[p+28] for p in [32..58] ──
    e1_period_matches = sum(
        1 for p in range(32, 59)
        if uf.find(('E1', p)) == uf.find(('E1', p + 28))
    )
    kv('E1 period-28 matches (pos 32-58)', e1_period_matches)
    assert e1_period_matches == 27  # all 27 match

    # Period does NOT extend backward
    e1_backward = sum(
        1 for p in range(0, 32)
        if p + 28 < len(m['E1']) and
        uf.find(('E1', p)) == uf.find(('E1', p + 28))
    )
    kv('E1 period-28 backward (pos 0-31)', e1_backward)
    assert e1_backward == 0  # zero backward matches

    # ── cross-message convergence ──
    e1_w1_same = sum(
        1 for p in range(32, 60)
        if uf.find(('E1', p)) == uf.find(('W1', p))
    )
    kv('E1 vs W1 same-class (pos 32-59)', e1_w1_same)
    assert e1_w1_same == 27  # 27 of 28 agree

    # Pre-divergence: same repeat structure
    pre_div_agree = 0
    pre_div_disagree = 0
    e4_syms = defaultdict(set)
    w4_syms = defaultdict(set)
    max_p = min(len(m['E4']), len(m['W4']), 25)
    for p in range(max_p):
        e4_syms[uf.find(('E4', p))].add(p)
        w4_syms[uf.find(('W4', p))].add(p)
    for cls, positions in e4_syms.items():
        if len(positions) < 2:
            continue
        pos_list = sorted(positions)
        for i in range(len(pos_list)):
            for j in range(i + 1, len(pos_list)):
                p1, p2 = pos_list[i], pos_list[j]
                if p2 >= len(m['W4']):
                    continue
                if uf.find(('W4', p1)) == uf.find(('W4', p2)):
                    pre_div_agree += 1
                else:
                    pre_div_disagree += 1
    kv('pre-divergence agree', pre_div_agree)
    kv('pre-divergence disagree', pre_div_disagree)
    assert pre_div_agree == 4
    assert pre_div_disagree == 0

    # ── symbol census ──
    # 27 known symbol representatives
    known_reps = [
        # 16 αβ-bridge
        ('E3', 110), ('E4', 33), ('E5', 17), ('E5', 20),
        ('E5', 33), ('E5', 86), ('E5', 88), ('E5', 89),
        ('E5', 90), ('E5', 98), ('W2', 70), ('W2', 86),
        ('W3', 11), ('W3', 47), ('W4', 21), ('W4', 32),
        # 7 α-only motif
        ('E3', 108), ('E3', 102), ('E3', 106), ('E3', 104),
        ('W3', 20), ('E3', 107), ('W3', 15),
        # 4 β-only motif
        ('E3', 41), ('W3', 27), ('E5', 93), ('E5', 94),
    ]
    known_cls = set(uf.find(r) for r in known_reps)
    kv('known symbol representatives', len(known_reps))
    kv('unique known symbols', len(known_cls))
    assert len(known_cls) == 27

    # W3_19 candidate count
    anti_edges: dict = defaultdict(set)
    for l in MSG_LABELS:
        for bi, (s, e) in enumerate(blocks[l]):
            block_cls = {uf.find((l, p)) for p in range(s, e + 1)}
            block_known = block_cls & known_cls
            block_unknown = block_cls - known_cls
            for u in block_unknown:
                anti_edges[u].update(block_known)

    cls_w19 = uf.find(('W3', 19))
    w19_candidates = known_cls - anti_edges[cls_w19]
    kv('W3_19 candidate count', len(w19_candidates))
    assert len(w19_candidates) == 2
    # Verify they are E5_93 and E5_94
    assert uf.find(('E5', 93)) in w19_candidates
    assert uf.find(('E5', 94)) in w19_candidates

    # E3 contains both motifs: β at pos 76, α at pos 101-108
    # β-motif in E3
    e3_beta_starts = []
    for s in range(len(m['E3']) - 14):
        if all(uf.find(('E3', s + i)) == beta_motif[i] for i in range(15)):
            e3_beta_starts.append(s)
    kv('β-motif in E3 at', e3_beta_starts)
    assert 76 in e3_beta_starts

    # α-motif classes in E3
    e3_108_pos = [p for p in range(len(m['E3']))
                  if uf.find(('E3', p)) == uf.find(('E3', 108))]
    kv('E3_108 in E3 at', e3_108_pos)
    assert 101 in e3_108_pos and 108 in e3_108_pos

    # Repeating unit: 22 unique classes in 28 positions
    unit_cls = [uf.find(('E1', p)) for p in range(32, 60)]
    n_unique = len(set(unit_cls))
    kv('repeating unit unique classes', n_unique)
    assert n_unique == 22

    # Six classes repeat within the unit
    from collections import Counter as _Ctr
    unit_counts = _Ctr(str(c) for c in unit_cls)
    n_repeats = sum(1 for v in unit_counts.values() if v > 1)
    kv('classes repeating in unit', n_repeats)
    assert n_repeats == 6

    print()
    print('  The plaintext has a message-specific period (28/30/35 for α,')
    print('  84-87 for β) holding for ~27 consecutive positions. The')
    print('  repeating unit contains 22 unique classes with 6 duplicates.')
    print('  27 of 28 symbols are identified; W3_19 is constrained to')
    print('  E5_93 or E5_94 (2 candidates). The autokey state machine')
    print('  reconverges after brief pos-0 divergence.')

    return {
        'uf': uf,
        'blocks': blocks,
        'beta_motif': beta_motif,
        'alpha_motif': alpha_motif,
        'beta_gaps': beta_gaps,
        'alpha_gaps': alpha_gaps,
        'known_cls': known_cls,
        'w19_candidates': w19_candidates,
    }


def section_90_sigma_table_reconstruction(m: dict[str, list[int]]) -> dict:
    """Tier H17: **σ table reconstruction from periodic region**.

    Reconstructs partial σ tables for each block within E1's periodic
    region (pos 32-87). Key findings:
    - σ₃ covers 16/22 unit classes, σ₄ covers 21/22
    - b3→b4 transition: 14 changed entries, 1 unchanged (E5_17=49)
    - Deltas are non-uniform: transition is NOT additive/multiplicative
    - E2 σ₁ = W1 σ₁ (13/13 = 100% match): perfect σ agreement
    - E1 σ₁ vs W1 σ₁: 12/13 agree, W3_28 disagrees (40 vs 52)
    - The disagreement traces to different block boundary positions
      caused by pos-0 divergence at positions 25-27
    """
    banner(90, 'σ TABLE RECONSTRUCTION FROM PERIODIC REGION (Tier H17)')

    uf, blocks = _full_merge_pipeline(m)

    # Build σ tables for E1 blocks in the periodic region
    sigma_tables: dict[tuple[str, int], dict] = {}
    for l in ['E1', 'W1', 'E2']:
        for bi, (s, e) in enumerate(blocks[l]):
            sigma = {uf.find((l, p)): m[l][p] for p in range(s, e + 1)}
            sigma_tables[(l, bi)] = sigma

    # Unit classes (22 unique from E1 pos 32-59)
    unit_cls_list: list = []
    unit_cls_set: set = set()
    for p in range(32, 60):
        cls = uf.find(('E1', p))
        if cls not in unit_cls_set:
            unit_cls_list.append(cls)
            unit_cls_set.add(cls)

    # σ₃ coverage (E1 b3: pos 33-51)
    s3 = sigma_tables[('E1', 3)]
    s3_covered = sum(1 for c in unit_cls_set if c in s3)
    kv('σ₃ unit coverage', f'{s3_covered}/22')
    assert s3_covered == 16

    # σ₄ coverage (E1 b4: pos 52-76)
    s4 = sigma_tables[('E1', 4)]
    s4_covered = sum(1 for c in unit_cls_set if c in s4)
    kv('σ₄ unit coverage', f'{s4_covered}/22')
    assert s4_covered == 21

    # b3→b4 transition analysis
    shared = set(s3) & set(s4)
    changed = [(cls, s3[cls], s4[cls])
               for cls in shared if s3[cls] != s4[cls]]
    unchanged = [(cls, s3[cls])
                 for cls in shared if s3[cls] == s4[cls]]

    kv('b3→b4 shared entries', len(shared))
    kv('b3→b4 changed', len(changed))
    kv('b3→b4 unchanged', len(unchanged))
    assert len(changed) == 14
    assert len(unchanged) == 1

    # The unchanged entry is E5_17 at ct=49
    unch_cls, unch_ct = unchanged[0]
    assert unch_cls == uf.find(('E5', 17))
    assert unch_ct == 49
    kv('unchanged entry', f'E5_17 → {unch_ct}')

    # Deltas are all different (not constant, not multiplicative)
    deltas = sorted(set((s4[cls] - s3[cls]) % 83
                        for cls in shared if s3[cls] != s4[cls]))
    kv('unique delta values', len(deltas))
    assert len(deltas) == 13  # W3_19 and W4_32 share Δ=4

    # b3→b4 trigger: E4_33 at pos 52, Type A (ct changed 14→5)
    trigger_cls = uf.find(('E1', 52))
    assert trigger_cls == uf.find(('E4', 33))
    assert s3.get(trigger_cls) == 14
    assert s4.get(trigger_cls) == 5
    kv('b3→b4 trigger', f'E4_33: 14→5 (Type A)')

    # ── Cross-message σ₁ comparison ──
    s1_e1 = sigma_tables[('E1', 1)]
    s1_w1 = sigma_tables[('W1', 1)]
    s1_e2 = sigma_tables[('E2', 1)]

    # E2 σ₁ vs W1 σ₁: perfect match
    e2_w1_shared = set(s1_e2) & set(s1_w1)
    e2_w1_agree = sum(1 for c in e2_w1_shared if s1_e2[c] == s1_w1[c])
    kv('E2 σ₁ vs W1 σ₁', f'{e2_w1_agree}/{len(e2_w1_shared)} agree')
    assert e2_w1_agree == len(e2_w1_shared)  # 100% match

    # E1 σ₁ vs W1 σ₁: 12/13 agree, W3_28 disagrees
    e1_w1_shared = set(s1_e1) & set(s1_w1)
    e1_w1_agree = sum(1 for c in e1_w1_shared if s1_e1[c] == s1_w1[c])
    e1_w1_disagree = [c for c in e1_w1_shared if s1_e1[c] != s1_w1[c]]
    kv('E1 σ₁ vs W1 σ₁', f'{e1_w1_agree}/{len(e1_w1_shared)} agree')
    assert e1_w1_agree == 12
    assert len(e1_w1_shared) == 13

    # The disagreement is W3_28
    assert len(e1_w1_disagree) == 1
    assert e1_w1_disagree[0] == uf.find(('W3', 28))
    kv('σ₁ disagreement', f'W3_28: E1={s1_e1[e1_w1_disagree[0]]}, '
                           f'W1={s1_w1[e1_w1_disagree[0]]}')

    # ── σ replacement proof: W4_32 in β b1→b2 ──
    # σ₂[W4_32] = 1 in both E4 and W4 despite different σ₁ values
    cls_w4_32 = uf.find(('W4', 32))
    e4_w4_32_cts: dict[str, list] = {}
    for l in ['E4', 'W4']:
        cts = []
        for p in range(len(m[l])):
            if uf.find((l, p)) == cls_w4_32:
                cts.append(m[l][p])
        e4_w4_32_cts[l] = cts

    # Both E4 and W4 have ct=1 for W4_32 at pos 24 (block 2)
    assert m['E4'][24] == 1 and uf.find(('E4', 24)) == cls_w4_32
    assert m['W4'][24] == 1 and uf.find(('W4', 24)) == cls_w4_32
    kv('σ replacement proof', 'σ₂[W4_32]=1 in both E4 and W4')

    print()
    print('  σ tables reconstructed from periodic region. The b3→b4')
    print('  transition shows 14 entries changed with all-different')
    print('  deltas — the autokey is NOT additive or multiplicative.')
    print('  E2 σ₁ = W1 σ₁ perfectly despite different pos-0 ct values,')
    print('  confirming the transition is deterministic from shared σ₀.')
    print('  σ evolution is REPLACEMENT-based (not incremental).')

    return {
        'sigma_tables': sigma_tables,
        'unit_classes': unit_cls_list,
        'b3_b4_changed': len(changed),
        'b3_b4_unchanged_entry': ('E5_17', 49),
    }


