def _ct_uniqueness_intervals(ct: list[int]) -> list[tuple[int, int]]:
    """All adjacent same-ct must-cut intervals for a single message.

    Replicates 2quacks's §19 ct-injectivity logic in isolation: between every
    pair of consecutive same-ct positions, at least one block boundary must
    fall. Returns (lo, hi) closed-end intervals on cut positions.
    """
    pos_by_ct: dict[int, list[int]] = defaultdict(list)
    for p, v in enumerate(ct):
        pos_by_ct[v].append(p)
    ints: list[tuple[int, int]] = []
    for ps in pos_by_ct.values():
        for i in range(len(ps) - 1):
            ints.append((ps[i], ps[i + 1] - 1))
    return ints


def _greedy_min_cuts(intervals: list[tuple[int, int]]) -> int:
    """Optimal interval-stabbing min-cuts."""
    s = sorted(intervals, key=lambda x: x[1])
    n_cuts = 0
    last = -1
    for lo, hi in s:
        if last < lo:
            last = hi
            n_cuts += 1
    return n_cuts


def section_91_peer_review_reconciliation(m: dict[str, list[int]]) -> dict:
    """Peer-review reconciliation against 2quacks's independent re-derivation
    (cryptanalysis.md §1–§35 + RT audit, dated 2026-05-11).

    Asserts every numerical claim 2quacks cited that we accepted as agreeing
    with our own corpus. Exposes the 2quacks-specific framings of headline
    numbers that already appear elsewhere in the harness, so any auditor can
    cross-reference our work against theirs without re-running their tools.

    Reconciled claims:

      §15   Per-msg lengths {99,103,118,102,137,124,119,120,114} ≡ ours
      §19   Per-msg ct-injectivity LB {E1=8,W1=10,E2=9,W2=9,E3=11,
            W3=12,E4=10,W4=9,E5=10} totalling 88 ≡ §27.per_msg_ctu (ours)
      §11.4 5× repeating 15-char canonical pattern at the cited windows
            ≡ §14 (ours); plus 4 additional windows we found beyond theirs
      §15∪§19 91-block lower bound ≡ §27.combined_lower_bound (ours)
      §35   Finnish hillclimber 477/492 diffuse classes ≡ §40 (ours)

    Rejected/qualified claims (rebutted in prose elsewhere; this section
    documents the agreement on the *underlying numbers* even where we
    disagree with 2quacks's interpretation):

      §13.3 Within-window IoC ≈ uniform-83 — agree on numbers, reject
            interpretation (see §93 power analysis).
      §22   "2 σ-keys for 8 header blocks" — agree this is one cell of a
            tolerance grid (see §95 sweep).
      §24   pos-6/pos-7 4-way family ID — agree the partition is real
            but is a coarsening of our 3-3-3 grouping (see §94).
    """
    banner(91, 'PEER-REVIEW RECONCILIATION (vs 2quacks 2026-05-11)')

    # ── 2quacks §15: corpus shape ──
    print('  -- 2quacks §15: corpus shape --')
    expected_lengths = [99, 103, 118, 102, 137, 124, 119, 120, 114]
