    twoquacks_19 = {'E1': 8, 'W1': 10, 'E2': 9, 'W2': 9, 'E3': 11,
                    'W3': 12, 'E4': 10, 'W4': 9, 'E5': 10}
    ours_19: dict[str, int] = {}
    print(f'  {"msg":<5} {"ours":>5} {"2quacks":>8} {"agree":>6}')
    for l in MSG_LABELS:
        ints = _ct_uniqueness_intervals(m[l])
        n_blocks = _greedy_min_cuts(ints) + 1
        ours_19[l] = n_blocks
        agree = '✓' if n_blocks == twoquacks_19[l] else '✗'
        print(f'  {l:<5} {n_blocks:>5} {twoquacks_19[l]:>8} {agree:>6}')
    total_ours = sum(ours_19.values())
    total_2q = sum(twoquacks_19.values())
    print(f'  {"TOT":<5} {total_ours:>5} {total_2q:>8} '
          f'{"✓" if total_ours == total_2q else "✗":>6}')
    kv('§19-only LB (2quacks)', total_2q)
    kv('§19-only LB (ours, indep code path)', total_ours)
    assert ours_19 == twoquacks_19
    assert total_ours == 88

    # ── 2quacks §15 ∪ §19: combined LB (= our §11 UB) ──
    print()
    print('  -- 2quacks §15∪§19: combined LB = 91 (matches §11 upper bound) --')
    uf = build_class_union_find(m)
    combined_per_msg: dict[str, int] = {}
    for l in MSG_LABELS:
        cls_at = [uf.find((l, p)) for p in range(len(m[l]))]
        ints = set(_ct_uniqueness_intervals(m[l]))
        cls_pos: dict[object, list[int]] = defaultdict(list)
        for p, c in enumerate(cls_at):
            cls_pos[c].append(p)
        for ps in cls_pos.values():
            for a, b in combinations(ps, 2):
                if m[l][a] != m[l][b]:
                    ints.add((min(a, b), max(a, b) - 1))
