    prev_by_axis: dict[str, float] = {}
    print('  -- reduction ledger (dex = log10 problemspace) --')
    print(f'  {"axis":<12} {"stage":<40} {"dex":>10} {"Δdex":>10} '
          f'{"kind":<13} evidence')
    printed_rows: list[dict[str, object]] = []
    for row in rows:
        axis = str(row['axis'])
        dex = float(row['log10'])
        delta = None
        if axis in prev_by_axis:
            delta = prev_by_axis[axis] - dex
        prev_by_axis[axis] = dex
        delta_s = '-' if delta is None else f'{delta:,.1f}'
        print(f'  {axis:<12} {str(row["stage"]):<40} '
              f'{dex:>10,.1f} {delta_s:>10} {str(row["kind"]):<13} '
              f'{row["evidence"]}')
        out = dict(row)
        out['delta_from_previous_axis_row'] = delta
        printed_rows.append(out)

    schedule_reduction = schedule_unrestricted_log
    exact_count_log = sum(log10_int(c) for c in exact_count_counts)
    keyspace_reduction = independent_key_log - strict_key_log
    plaintext_reduction = (
        (total_chars - len(plaintext_classes)) * math.log10(MOD)
    )

    print()
    print('  -- current readout --')
    kv('schedule search removed by §115', f'{schedule_reduction:,.1f} dex')
    kv('pre-§115 exact-count schedule space',
       f'10^{exact_count_log:,.1f}')
    kv('σ-keyspace removed by strict topology',
       f'{keyspace_reduction:,.1f} dex (upper-bound accounting)')
