def _construction_sigma_tables_83key(
        ct: dict[str, list[int]],
        pt: dict[str, str],
) -> tuple[dict[int, dict[int, str]], dict[tuple[str, int], int], list[dict]]:
    """83-key schedule σ tables from aligned ciphertext + proposed plaintext."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS, STRICT_SIGMA_CLUSTERS

    bid = 0
    s2b: dict[tuple[str, int], int] = {}
    p2b: dict[tuple[str, int], int] = {}
    for label_l in MSG_LABELS:
        for si, (s_e, e_e) in enumerate(REALISTIC_BLOCK_SPANS[label_l]):
            s2b[(label_l, si)] = bid
            for p_p in range(s_e, e_e + 1):
                p2b[(label_l, p_p)] = bid
            bid += 1
    par = list(range(bid))

    def find(x: int) -> int:
        while par[x] != x:
            par[x] = par[par[x]]
            x = par[x]
        return x

    def union(a: int, b: int) -> None:
        a, b = find(a), find(b)
        if a != b:
            par[b] = a

    for _, grp in STRICT_SIGMA_CLUSTERS.items():
        f = s2b[grp[0]]
        for k in grp[1:]:
            union(f, s2b[k])

    r2k: dict[int, int] = {}
    nk = 0
    key_of: dict[tuple[str, int], int] = {}
    for pos_key, b in p2b.items():
        r = find(b)
        if r not in r2k:
            r2k[r] = nk
            nk += 1
        key_of[pos_key] = r2k[r]

    sigma: dict[int, dict[int, str]] = defaultdict(dict)
    conflicts: list[dict] = []
    for label_l in MSG_LABELS:
        for p_p in range(len(ct[label_l])):
            k = key_of[(label_l, p_p)]
            cv = ct[label_l][p_p]
            ch = pt[label_l][p_p]
            if cv in sigma[k] and sigma[k][cv] != ch:
                conflicts.append({
                    'sigma_key': k,
                    'ct_val': cv,
                    'position': f'{label_l}[{p_p}]',
                    'reason': f'ct {cv} -> {sigma[k][cv]} AND {ch}',
                })
            else:
                for existing_cv, existing_ch in sigma[k].items():
                    if existing_ch == ch and existing_cv != cv:
                        conflicts.append({
                            'sigma_key': k,
                            'ct_val': cv,
                            'position': f'{label_l}[{p_p}]',
                            'reason': f"pt '{ch}' -> {existing_cv} AND {cv}",
                        })
                        break
                sigma[k][cv] = ch
    return sigma, key_of, conflicts


def _audit_plaintext_json_against_skeleton(
        m: dict[str, list[int]],
        skel: dict[tuple[str, int], int],
        plain: dict[str, str],
) -> dict[str, int]:
    """§222-style hard checks on a construction ``best_plaintext.json``."""
    blocks = _skeleton_blocks(skel, m)
    period_classes, space_classes = _period_space_candidate_groups(skel)
    pin_violations = 0
    class_violations = 0
    injectivity_violations = 0
    for label_l in MSG_LABELS:
        text = plain[label_l]
        cls_to_char: dict[int, str] = {}
        for p_p, ch_p in enumerate(text):
            cls_p = skel[(label_l, p_p)]
            if cls_p in period_classes and ch_p != '.':
                pin_violations += 1
            if cls_p in space_classes and ch_p != ' ':
                pin_violations += 1
            prev = cls_to_char.get(cls_p)
            if prev is None:
                cls_to_char[cls_p] = ch_p
            elif prev != ch_p:
                class_violations += 1
        for s_e, e_e in blocks[label_l]:
            sym_to_cls: dict[str, int] = {}
            for p_p in range(s_e, e_e + 1):
                cls_p = skel[(label_l, p_p)]
                ch_p = text[p_p]
                if ch_p in sym_to_cls and sym_to_cls[ch_p] != cls_p:
                    injectivity_violations += 1
                    break
                sym_to_cls[ch_p] = cls_p
    return {
        'pin_violations': pin_violations,
        'class_violations': class_violations,
        'injectivity_violations': injectivity_violations,
    }


def _construction_83key_roundtrip_ok(
        m: dict[str, list[int]],
        plain: dict[str, str],
) -> tuple[bool, int, int]:
    """True when plaintext is consistent with the strict 83-key σ schedule."""
    sigma, key_of, conflicts = _construction_sigma_tables_83key(m, plain)
    if conflicts:
        return False, len(conflicts), 0
    mismatches = 0
    for label_l in MSG_LABELS:
        for p_p in range(len(m[label_l])):
            k = key_of[(label_l, p_p)]
            if sigma[k][m[label_l][p_p]] != plain[label_l][p_p]:
                mismatches += 1
    return mismatches == 0, len(conflicts), mismatches


def _corpus_dist4_ratio(m: dict[str, list[int]]) -> tuple[int, float, float]:
    """Observed dist-4 repeat count, expected, and ratio (§4)."""
    dist4 = 0
    expected = 0.0
    for label_l in MSG_LABELS:
        ct = m[label_l]
        if len(ct) > 4:
            dist4 += sum(1 for i in range(len(ct) - 4) if ct[i] == ct[i + 4])
            expected += (len(ct) - 4) / MOD
    ratio = dist4 / expected if expected else 0.0
    return dist4, expected, ratio


def _audit_plaintext_pattern_layers(
        plain: dict[str, str],
        *,
        max_examples: int = 1,
) -> dict[str, object]:
    """``validate_plaintext_patterns.py`` layers on a construction candidate."""
    from validate_plaintext_patterns import (
        validate_block_injectivity,
        validate_iso_windows,
        validate_lengths,
        validate_skeleton_classes,
        validate_w4_e5_window,
    )

    length_issues = validate_lengths(plain)
    skeleton_issues = validate_skeleton_classes(
        plain, max_examples=max_examples)
    block_issues = validate_block_injectivity(
        plain, max_examples=max_examples)
    iso_issues = validate_iso_windows(plain)
    w4_issues = validate_w4_e5_window(plain)
    return {
        'length_ok': len(length_issues) == 0,
        'skeleton_conflicts': len(skeleton_issues),
        'block_injectivity_conflicts': len(block_issues),
        'canonical_iso_conflicts': len(iso_issues) + len(w4_issues),
        'iso_window_conflicts': len(iso_issues),
        'w4_e5_conflicts': len(w4_issues),
        'strict_pattern_perfect': not (
            length_issues or skeleton_issues or block_issues),
        'skeleton_layer_perfect': not (length_issues or skeleton_issues),
    }


def _construction_check_artifact_rules(
        plain: dict[str, str],
        spec: dict[str, object],
) -> dict[str, object]:
    """Apply per-artifact artifact/heuristic rule fields from pinned spec."""
    counts = _construction_artifact_phrase_counts(plain)
    heur, _n = _construction_prose_heuristic_score(plain)
    violations: list[str] = []
    for phrase in spec.get('forbidden_zero', ()):
        n = counts.get(str(phrase), 0)
        if n:
            violations.append(f'forbidden {phrase!r}: {n}')
    for phrase, minimum in spec.get('min_phrase_counts', {}).items():
        n = counts.get(str(phrase), 0)
        if n < int(minimum):
            violations.append(
                f'expected >={minimum} of {phrase!r}, got {n}')
    max_total = spec.get('max_artifact_total')
    total = sum(counts.values())
    if max_total is not None and total > int(max_total):
        violations.append(f'artifact total {total} > max {max_total}')
    max_heur = spec.get('max_heuristic')
    if max_heur is not None and heur > int(max_heur):
        violations.append(f'heuristic {heur} > max {max_heur}')
    return {
        'artifact_phrase_counts': counts,
        'artifact_phrase_total': total,
        'heuristic_score': heur,
        'violations': violations,
    }


def _construction_artifact_phrase_counts(
        plain: dict[str, str]) -> dict[str, int]:
    """Surface template artifact substring counts (lower is better)."""
    from skeleton_pattern_generator import TEMPLATE_ARTIFACT_PENALTIES

    joined = '\n'.join(plain[label_l] for label_l in MSG_LABELS)
    return {
        phrase: joined.count(phrase)
        for phrase in TEMPLATE_ARTIFACT_PENALTIES
        if joined.count(phrase)
    }


def _construction_audit_snapshot(
        plain: dict[str, str],
        m: dict[str, list[int]],
) -> dict[str, object]:
    """Pattern + §222 pin + artifact + heuristic snapshot."""
    skel = _load_plaintext_skeleton()
    pat = _audit_plaintext_pattern_layers(plain)
    pins = _audit_plaintext_json_against_skeleton(m, skel, plain)
    heur, _n = _construction_prose_heuristic_score(plain)
    artifacts = _construction_artifact_phrase_counts(plain)
    return {
        **pat,
        **pins,
        'heuristic_score': heur,
        'artifact_phrase_counts': artifacts,
        'artifact_phrase_total': sum(artifacts.values()),
    }


def _construction_prose_heuristic_score(
        plain: dict[str, str]) -> tuple[int, int]:
    """Lower is better.  Template penalties + ``batch_runner.score_text``."""
    from batch_runner import score_text
    from skeleton_pattern_generator import TEMPLATE_ARTIFACT_PENALTIES

    base, _, _issues = score_text(plain)
    joined = '\n'.join(plain[label_l] for label_l in MSG_LABELS)
    extra = sum(weight * joined.count(phrase)
                for phrase, weight in TEMPLATE_ARTIFACT_PENALTIES.items())
    return base + extra, len(_issues)


def _construction_heuristic_null_baseline(
        plain: dict[str, str],
        *,
        mode: Literal['msg_shuffle', 'skel_permute'] = 'msg_shuffle',
        seed: int = 0,
) -> dict[str, str]:
    """Chance layout destroying prose signal while preserving coarse structure.

    ``msg_shuffle``: permute visible characters independently within each
    message (length + per-message character multiset preserved).

    ``skel_permute``: permute the visible character assigned to each skeleton
    class id (skeleton-layer equality preserved; allomorph collisions unchanged).
    """
    rng = random.Random(seed)
    if mode == 'msg_shuffle':
        out: dict[str, str] = {}
        for label_l in MSG_LABELS:
            chars = list(plain[label_l])
            rng.shuffle(chars)
            out[label_l] = ''.join(chars)
        return out

    skel = _load_plaintext_skeleton()
    cls_to_char: dict[int, str] = {}
    for label_l in MSG_LABELS:
        for pos, ch in enumerate(plain[label_l]):
            cls_to_char.setdefault(skel[(label_l, pos)], ch)
    class_ids = list(cls_to_char.keys())
    chars = [cls_to_char[cid] for cid in class_ids]
    rng.shuffle(chars)
    perm = dict(zip(class_ids, chars))
    return {
        label_l: ''.join(
            perm[skel[(label_l, pos)]]
            for pos in range(len(plain[label_l])))
        for label_l in MSG_LABELS
    }


def _scan_space_template_reports(eye_dir: Path) -> list[dict[str, object]]:
    """All ``space_template_*/space_template_report.json`` under ``eye/``."""
    rows: list[dict[str, object]] = []
    for report_path in sorted(eye_dir.glob('space_template_*/space_template_report.json')):
        report = json.loads(report_path.read_text())
        dirname = report_path.parent.name
        solved = int(report['solved_count'])
        rows.append({
            'dir': dirname,
            'solved_count': solved,
            'allowlisted': dirname in _SPACE_TEMPLATE_SOLVED_ALLOWLIST,
        })
    return rows


def _construction_83key_schedule() -> ProposalSchedule:
    """REALISTIC_BLOCK_SPANS + STRICT_SIGMA_CLUSTERS → 83-key block schedule."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS, STRICT_SIGMA_CLUSTERS

    pos_to_bid: dict[tuple[str, int], int] = {}
    next_bid = 0
    shared: dict[tuple[str, int], int] = {}
    for _name, group in STRICT_SIGMA_CLUSTERS.items():
        bid = next_bid
        next_bid += 1
        for key in group:
            shared[key] = bid
    for label_l in MSG_LABELS:
        for bi, (s_e, e_e) in enumerate(REALISTIC_BLOCK_SPANS[label_l]):
            bid = shared.get((label_l, bi))
            if bid is None:
                bid = next_bid
                next_bid += 1
            for p_p in range(s_e, e_e + 1):
                pos_to_bid[(label_l, p_p)] = bid

    def schedule(label_l: str, pos: int) -> int:
        return pos_to_bid[(label_l, pos)]

    return schedule


def _construction_sigma_table_class_to_ct(
        m: dict[str, list[int]],
        skel: dict[tuple[str, int], int],
        schedule: ProposalSchedule,
) -> dict[int, dict[int, int]]:
    """Per σ-key skeleton-class → ct under ``schedule`` (for §96 C12/C13)."""
    sigma: dict[int, dict[int, int]] = defaultdict(dict)
    conflicts = 0
    for label_l in MSG_LABELS:
        for p_p in range(len(m[label_l])):
            bid = schedule(label_l, p_p)
            cls_p = skel[(label_l, p_p)]
            ct_p = m[label_l][p_p]
            tab = sigma[bid]
            prev = tab.get(cls_p)
            if prev is not None and prev != ct_p:
                conflicts += 1
            tab[cls_p] = ct_p
    if conflicts:
        raise AssertionError(
            f'skeleton class→ct conflicts under construction schedule: {conflicts}')
    return dict(sigma)


def _rule_a_block_schedule(
        skel: dict[tuple[str, int], int],
        m: dict[str, list[int]],
) -> ProposalSchedule:
    """Map each position to a monotonic Rule-A block id (91 blocks corpus-wide)."""
    blocks = _skeleton_blocks(skel, m)
    pos_to_bid: dict[tuple[str, int], int] = {}
    next_bid = 0
    for label_l in MSG_LABELS:
        for s_e, e_e in blocks[label_l]:
            for p_p in range(s_e, e_e + 1):
                pos_to_bid[(label_l, p_p)] = next_bid
            next_bid += 1

    def schedule(label_l: str, pos: int) -> int:
        return pos_to_bid[(label_l, pos)]

    return schedule


def section_233_gak_structural_verdict(
        m: dict[str, list[int]]) -> dict:
    """§233 — consolidated GAK/deck structural verdict (§22, §141, §227–232).

    Recomputes the pinned headline numbers from the GAK probe family in one
    place so a single section run certifies the Discord/Lymm closure narrative.
    """
    banner(233, 'GAK / DECK STRUCTURAL VERDICT (CONSOLIDATED)')

    skel = _load_plaintext_skeleton()
    c14_ok, c14_detail = _gak_rule_a_adjacent_different_sigma(m, skel)
    kv('adjacent Rule-A σ distinct', c14_detail)

    import importlib.util as _ilu
    _et_spec = _ilu.spec_from_file_location(
        'eye_trigrams', Path(__file__).parent / 'eye_trigrams.py')
    _et = _ilu.module_from_spec(_et_spec)
    _et_spec.loader.exec_module(_et)
    geom = {label_l: _et.build_stream_geometry(label_l) for label_l in MSG_LABELS}
    rp_bounds = _gak_row_pair_boundaries_from_json()
    iso_10 = _gak_isomorph_crossing_stats(m, geom, 10, 1, rp_bounds)
    iso_62 = _gak_isomorph_crossing_stats(m, geom, 15, 2, rp_bounds)

    separable_bad_33 = 0
    bucket_ct: dict[tuple[tuple[int, int], int], set[int]] = defaultdict(set)
    for label_l in MSG_LABELS:
        for p_p in range(len(m[label_l])):
            g_c = geom[label_l][p_p]
            key_rc = (g_c.row_global % 3, g_c.col % 3)
            bucket_ct[(key_rc, skel[(label_l, p_p)])].add(m[label_l][p_p])
    separable_bad_33 = sum(1 for vals in bucket_ct.values() if len(vals) > 1)

    trusted_uf = _gak_build_lit_iso_uf(m, 25, 3)
    ct_p1 = _gak_feedback_transition_conflicts(m, trusted_uf, 1, feedback='ct')
    pt_p1 = _gak_feedback_transition_conflicts(
        m, trusted_uf, 1, feedback='pt', skel=skel)

    artifact_path = Path(__file__).parent / 'reading_order_sweep.json'
    orth_adj_dupes = None
    if artifact_path.exists():
        pinned = {row['name']: row for row in json.loads(artifact_path.read_text())}
        orth_adj_dupes = pinned['orthodox_weave']['adjacent_dupes']

    print()
    print('  -- consolidated ledger --')
    kv('2D separable (3,3) bad buckets', separable_bad_33)
    kv('isomorph ≥10/≥1 cross digit-row', f'{iso_10["row_either"]}/{iso_10["total"]}')
    kv('isomorph ≥10/≥1 cross row-pair §22', f'{iso_10["row_pair_22_style"]}/{iso_10["total"]}')
    kv('isomorph ≥15/≥2 cross digit-row', f'{iso_62["row_either"]}/{iso_62["total"]}')
    kv('CT-feedback p=1 bad slots', f'{ct_p1["violating_slots"]}/{ct_p1["comparable_slots"]}')
    kv('PT-feedback p=1 bad slots', f'{pt_p1["violating_slots"]}/{pt_p1["comparable_slots"]}')
    if orth_adj_dupes is not None:
        kv('orthodox weave dist-1 dupes (artifact)', orth_adj_dupes)

    print()
    print('  → Closed: flat CT/PT feedback tables (§141/§232); fixed 2D row/col')
    print('    keys (§228/§231); adjacent-different σ at Rule-A boundaries (§227).')
    print('    Open: full GAK deck simulator (shuffle/draw/feedback), not refuted here.')

    assert c14_ok
    assert separable_bad_33 > 0
    assert iso_10['total'] == 781
    assert iso_10['row_either'] == 781
    assert iso_10['row_pair_22_style'] == 554
    assert iso_62['total'] == 62
    assert iso_62['row_either'] == 62
    assert (
        ct_p1['comparable_slots'], ct_p1['violating_slots'],
        pt_p1['comparable_slots'], pt_p1['violating_slots'],
    ) == (58, 4, 157, 113)
    if orth_adj_dupes is not None:
        assert orth_adj_dupes == 0

    return {
        'c14_detail': c14_detail,
        'iso_10': iso_10,
        'iso_62': iso_62,
        'separable_bad_33': separable_bad_33,
        'ct_p1': ct_p1,
        'pt_p1': pt_p1,
        'booked': True,
    }


def section_234_construction_output_audit(
        m: dict[str, list[int]]) -> dict:
    """§234 — audit construction pipelines vs structural decryption criteria.

    Pins space-template / word-CSP ``solved_count: 0`` (pinned + repo scan),
    audits ledger ``best_plaintext.json`` artifacts (§222 + 83-key σ round-trip),
    and checks diffusion-batch rank outputs when present.
    """
    banner(234, 'CONSTRUCTION OUTPUT AUDIT (≠ DECRYPTION)')

    eye_dir = Path(__file__).parent
    skel = _load_plaintext_skeleton()

    space_rows: list[dict[str, object]] = []
    for dirname in _PINNED_SPACE_TEMPLATE_REPORT_DIRS:
        report_path = eye_dir / dirname / 'space_template_report.json'
        assert report_path.is_file(), f'missing pinned report: {report_path}'
        solved = int(json.loads(report_path.read_text())['solved_count'])
        space_rows.append({'dir': dirname, 'solved_count': solved})
        kv(f'pinned {dirname} solved_count', solved)
        assert solved == 0, dirname

    scanned = _scan_space_template_reports(eye_dir)
    kv('space_template reports scanned', len(scanned))
    for row in scanned:
        if row['allowlisted']:
            continue
        assert int(row['solved_count']) == 0, row['dir']

    msg_report = (eye_dir / 'message_candidates_confirmation_bias_v1'
                  / 'message_candidate_report.json')
    msg_solved: int | None = None
    if msg_report.is_file():
        msg_solved = int(json.loads(msg_report.read_text())['solved_count'])
        kv('message_candidate_report solved_count', msg_solved)
        assert msg_solved == 0

    construction_rows: list[dict[str, object]] = []
    print('\n  -- pinned construction best_plaintext.json (σ + §222 pins) --')
    for spec in _PINNED_CONSTRUCTION_ARTIFACTS:
        dirname = str(spec['dir'])
        plain_path = eye_dir / dirname / 'best_plaintext.json'
        assert plain_path.is_file(), plain_path
        plain = json.loads(plain_path.read_text())
        for label_l in MSG_LABELS:
            assert len(plain[label_l]) == len(m[label_l]), dirname
        skel_audit = _audit_plaintext_json_against_skeleton(m, skel, plain)
        rt_ok, n_conf, n_mis = _construction_83key_roundtrip_ok(m, plain)
        row = {
            'dir': dirname,
            'tag': spec['tag'],
            'sigma_83key_roundtrip': rt_ok,
            'sigma_conflicts': n_conf,
            **skel_audit,
        }
        construction_rows.append(row)
        kv(f'{dirname}',
           (f'83-key RT={rt_ok}', skel_audit, f'σ-conflicts={n_conf}'))
        assert not all(
            plain[label_l] == ''.join(chr(v) for v in m[label_l])
            for label_l in MSG_LABELS), f'{dirname} is raw ct-as-char'

    schedule = _rule_a_block_schedule(skel, m)
    val = validate_cipher_proposal(
        m, schedule, name='Rule-A skeleton blocks', verbose=False, skeleton=skel)
    c14 = val['results']['C14_rule_a_adjacent_different_sigma']
    kv('C14 on real Rule-A schedule', f'{"PASS" if c14[0] else "FAIL"} — {c14[1]}')
    assert c14[0]

    diffusion_audited = 0
    rank_dirs = sorted(_DIFFUSION_RESULTS_DIR.glob('rank_*'))
    if not rank_dirs:
        print('\n  (no diffusion_batch_results/rank_* — skip rank audit)')
    else:
        print('\n  -- diffusion_batch_results rank_* --')
        for rank_dir in rank_dirs:
            plain_path = rank_dir / 'plaintext.json'
            frag_path = rank_dir / 'fragments.json'
            score_path = rank_dir / 'score.txt'
            assert plain_path.is_file(), plain_path
            story = json.loads(plain_path.read_text())
            for label_l in MSG_LABELS:
                assert label_l in story, rank_dir.name
                assert len(story[label_l]) == len(m[label_l])
                assert isinstance(story[label_l], str)
                assert story[label_l] != str(m[label_l])
            if frag_path.is_file():
                frags = json.loads(frag_path.read_text())
                assert set(frags).issubset(_DIFFUSION_FRAGMENT_SLOTS)
            if score_path.is_file():
                kv(f'{rank_dir.name} score header',
                   score_path.read_text().splitlines()[0][:60])
            diffusion_audited += 1
        kv('diffusion rank_* dirs audited', diffusion_audited)

    v3 = next(r for r in construction_rows
              if r['dir'] == 'skeleton_pattern_candidate_v3')
    v4 = next(r for r in construction_rows
              if r['dir'] == 'skeleton_pattern_allomorph_quality_v4')
    v8 = next(r for r in construction_rows
              if r['dir'] == 'noita_tone_manual_patch_v8')

    print()
    print('  → σ/§222 audit above; pattern-layer audit in §238 '
          '(validate_plaintext_patterns).')

    for r in construction_rows:
        dirname = r['dir']
        assert r['sigma_83key_roundtrip'] is True, f"{dirname}: 83-key roundtrip failed"
        assert dirname in _PINNED_CONSTRUCTION_PIN_AUDIT, dirname
        exp_pin, exp_cls, exp_inj = _PINNED_CONSTRUCTION_PIN_AUDIT[dirname]
        assert int(r['pin_violations']) == exp_pin, f"{dirname}: expected {exp_pin} pin violations, got {r['pin_violations']}"
        assert int(r['class_violations']) == exp_cls, f"{dirname}: expected {exp_cls} class violations, got {r['class_violations']}"
        assert int(r['injectivity_violations']) == exp_inj, f"{dirname}: expected {exp_inj} injectivity violations, got {r['injectivity_violations']}"

    return {
        'space_template_reports': space_rows,
        'space_template_scanned': len(scanned),
        'construction_rows': construction_rows,
        'message_candidate_solved': msg_solved,
        'diffusion_ranks_audited': diffusion_audited,
        'c14_pass': c14[0],
        'booked': True,
    }


def section_235_pt_feedback_skeleton_vs_uf(
        m: dict[str, list[int]]) -> dict:
    """§235 — PT-feedback: skeleton class at ``n−p`` vs UF class at ``n−p``.

    Discord/GAK PT-autokey could key on either raw skeleton coordinates or the
    trusted literal/isomorph UF component.  This section pins that both choices
    refute equally on violating-slot counts (feedback keys differ, refutation
    does not).
    """
    banner(235, 'PT-FEEDBACK SKELETON vs UF KEY CENSUS')

    skel = _load_plaintext_skeleton()
    trusted_uf = _gak_build_lit_iso_uf(m, 25, 3)
    table_rows: list[dict[str, int]] = []
    for p_len in (1, 2, 3, 4):
        skel_r = _gak_feedback_transition_conflicts(
            m, trusted_uf, p_len, feedback='pt', skel=skel)
        uf_r = _gak_feedback_transition_conflicts(
            m, trusted_uf, p_len, feedback='pt_uf', skel=skel)
        table_rows.append({
            'p': p_len,
            'skel_comparable': int(skel_r['comparable_slots']),
            'skel_violating': int(skel_r['violating_slots']),
            'uf_comparable': int(uf_r['comparable_slots']),
            'uf_violating': int(uf_r['violating_slots']),
        })
        kv(f'p={p_len} comparable (skel / uf)',
           (table_rows[-1]['skel_comparable'], table_rows[-1]['uf_comparable']))
        kv(f'p={p_len} violating (skel / uf)',
           (table_rows[-1]['skel_violating'], table_rows[-1]['uf_violating']))

    print()
    print('  → UF feedback keys differ from skeleton keys on many slots, but')
    print('    violating-slot counts match at every primer length tested.')
    print('    §232’s skeleton-PT refutation is not an artifact of key choice.')

    assert table_rows[0] == {
        'p': 1, 'skel_comparable': 157, 'skel_violating': 113,
        'uf_comparable': 156, 'uf_violating': 113}
    assert table_rows[1] == {
        'p': 2, 'skel_comparable': 153, 'skel_violating': 111,
        'uf_comparable': 152, 'uf_violating': 111}
    assert table_rows[2]['skel_violating'] == 109
    assert table_rows[2]['uf_violating'] == 109
    assert table_rows[3]['skel_violating'] == 107
    assert table_rows[3]['uf_violating'] == 107

    return {'table_rows': table_rows, 'booked': True}


def section_236_dist4_synthesis_screen(
        m: dict[str, list[int]]) -> dict:
    """§236 — dist-4 anomaly vs forward synthesis (GAK-adjacent screen).

    The real corpus shows ~2.16× dist-4 repeats (§4).      Forward synthesis — including ``adjacent_different_sigma`` — stays near
    chance (~0.33×), not the 2.16× corpus anomaly.
    """
    banner(236, 'DIST-4 SYNTHESIS SCREEN (CORPUS vs CONSTRUCTED)')

    dist4, expected, corpus_ratio = _corpus_dist4_ratio(m)
    kv('corpus dist-4 obs / exp / ratio', (dist4, f'{expected:.2f}', f'{corpus_ratio:.2f}x'))

    cs = _import_cipher_synthesis()
    synth_rows: list[dict[str, object]] = []
    for tag, params in (
        ('minimal', cs.SynthesisParams.minimal()),
        ('adjacent_different_sigma', cs.SynthesisParams.adjacent_different_sigma()),
    ):
        corpus = cs.synthesize(params, seed=236, label=tag)
        fp = cs.fingerprint(corpus)
        d1 = sum(
            1 for label_l in MSG_LABELS
            for p_p in range(len(corpus.ciphertext[label_l]) - 1)
            if corpus.ciphertext[label_l][p_p]
            == corpus.ciphertext[label_l][p_p + 1])
        max_d1 = 2 if tag == 'adjacent_different_sigma' else 1
        val = _synth_validate(
            corpus, name=tag, verbose=False, max_dist1_dupes=max_d1)
        c15 = val['results'].get('C15_adjacent_ct_distinct')
        ratio = float(fp['ct_dist4_ratio_vs_uniform'])
        synth_rows.append({
            'tag': tag,
            'dist4_ratio': ratio,
            'dist4_count': int(fp['ct_dist4_count']),
            'adjacent_dupes': d1,
            'total_blocks': int(fp['total_blocks']),
            'c15_pass': c15[0] if c15 else None,
        })
        kv(f'synthesis {tag}',
           f'dist4={ratio:.3f}x  count={fp["ct_dist4_count"]}  d1={d1}  C15={c15}')

    print()
    print('  → Adjacent-different σ is necessary for GAK narrative but synthesis')
    print('    does not reproduce the §4 dist-4 excess — structural fit needs more')
    print('    than block-boundary σ freshness alone.')

    assert 25 <= dist4 <= 27
    assert 2.0 <= corpus_ratio <= 2.3
    for row in synth_rows:
        assert 0.30 <= float(row['dist4_ratio']) <= 0.36
        assert int(row['adjacent_dupes']) <= 2
        assert float(row['dist4_ratio']) < 1.0
    assert all(float(row['dist4_ratio']) < corpus_ratio * 0.25 for row in synth_rows)
    assert synth_rows[0]['adjacent_dupes'] == 1
    assert synth_rows[0]['c15_pass'] is True
    assert synth_rows[1]['adjacent_dupes'] <= 2
    assert synth_rows[1]['c15_pass'] is True

    return {
        'corpus_dist4_ratio': corpus_ratio,
        'synth_rows': synth_rows,
        'booked': True,
    }


def section_237_strict_vs_relaxed_xgak_verdict(
        m: dict[str, list[int]]) -> dict:
    """§237 — strict (§141) vs relaxed (§151) deterministic XGAK tables.

    Confirms that family conditioning, block-index keys, and block-local
    primer reset never reduce violating slots to zero on the trusted graph.
    """
    banner(237, 'STRICT vs RELAXED XGAK TABLE VERDICT')

    skel = _load_plaintext_skeleton()
    trusted_uf = _gak_build_lit_iso_uf(m, 25, 3)
    strict_ct = {
        p_len: _gak_feedback_transition_conflicts(
            m, trusted_uf, p_len, feedback='ct')
        for p_len in (1, 2, 3, 4)
    }
    relaxed_specs: tuple[tuple[str, dict[str, object]], ...] = (
        ('ct_global', {'feedback': 'ct'}),
        ('ct_family_conditioned', {'feedback': 'ct', 'family_conditioned': True}),
        ('ct_block_reset', {'feedback': 'ct', 'block_reset': True}),
        ('ct_block_index', {
            'feedback': 'ct', 'block_index_conditioned': True}),
        ('ct_block_index_reset', {
            'feedback': 'ct',
            'block_index_conditioned': True,
            'block_reset': True,
        }),
        ('pt_uf_global', {'feedback': 'pt_uf', 'skel': skel}),
    )
    relaxed: dict[str, dict[int, dict[str, object]]] = {}
    for name, kw in relaxed_specs:
        relaxed[name] = {
            p_len: _gak_relaxed_transition_conflicts(
                m, trusted_uf, p_len, **kw)
            for p_len in (1, 2, 3, 4)
        }

    print('  -- strict §141 CT-feedback (trusted ≥25/≥3) --')
    print(f'  {"p":>3} {"bad/comparable":>14}')
    for p_len in (1, 2, 3, 4):
        row = strict_ct[p_len]
        print(f'  {p_len:>3} '
              f'{int(row["violating_slots"])}/{int(row["comparable_slots"]):>10}')

    print()
    print('  -- relaxed modes: violating slots (best effort) --')
    print(f'  {"mode":<26} {"p=1":>8} {"p=2":>8} {"p=3":>8} {"p=4":>8}')
    for name, _kw in relaxed_specs:
        cells = [
            str(int(relaxed[name][p_len]['violating_slots']))
            for p_len in (1, 2, 3, 4)
        ]
        print(f'  {name:<26} {cells[0]:>8} {cells[1]:>8} '
              f'{cells[2]:>8} {cells[3]:>8}')

    print()
    print('  → No tested relaxation rescues the flat deterministic table.')
    print('    Block-index conditioning lowers p=1 to 2/56 bad slots but does')
    print('    not reach zero; PT-feedback remains far worse (§232/§235).')

    assert strict_ct[1]['violating_slots'] == 4
    assert strict_ct[2]['violating_slots'] == 5
    assert relaxed['ct_global'][1]['violating_slots'] == 4
    assert relaxed['ct_block_index'][1]['violating_slots'] == 2
    assert relaxed['ct_block_index_reset'][1]['violating_slots'] == 2
    assert relaxed['pt_uf_global'][1]['violating_slots'] == 113
    for name in relaxed:
        for p_len in (1, 2, 3, 4):
            assert int(relaxed[name][p_len]['violating_slots']) > 0

    return {
        'strict_ct': strict_ct,
        'relaxed': relaxed,
        'booked': True,
    }


def section_238_construction_plaintext_pattern_audit(
        m: dict[str, list[int]]) -> dict:
    """§238 — construction quality via ``validate_plaintext_patterns``.

    Distinguishes strict pattern-perfect prose (skeleton + combined-class
    block injectivity) from allomorph-aware constructions that intentionally
    allow surface letter collisions across classes.  Also records canonical-ISO
    diagnostics and prose heuristic scores.
    """
    banner(238, 'CONSTRUCTION PLAINTEXT PATTERN AUDIT')

    eye_dir = Path(__file__).parent
    pattern_rows: list[dict[str, object]] = []

    print('  -- validate_plaintext_patterns layers (pinned artifacts) --')
    print(f'  {"artifact":<42} {"skel":>5} {"block":>6} {"strict":>7} '
          f'{"heur":>6} {"canon":>6}')
    print('  ' + '-' * 78)

    for spec in _PINNED_CONSTRUCTION_ARTIFACTS:
        dirname = str(spec['dir'])
        plain_path = eye_dir / dirname / 'best_plaintext.json'
        plain = json.loads(plain_path.read_text())
        pat = _audit_plaintext_pattern_layers(plain)
        heur, _n_issues = _construction_prose_heuristic_score(plain)
        score_path = eye_dir / dirname / 'score.json'
        pinned_heur: int | None = None
        if score_path.is_file():
            pinned_heur = int(json.loads(score_path.read_text())['score'])
        row = {
            'dir': dirname,
            'tag': spec['tag'],
            **pat,
            'heuristic_score': heur,
            'pinned_score_json': pinned_heur,
        }
        pattern_rows.append(row)
        print(f'  {dirname:<42} '
              f'{int(pat["skeleton_conflicts"]):>5} '
              f'{int(pat["block_injectivity_conflicts"]):>6} '
              f'{str(pat["strict_pattern_perfect"]):>7} '
              f'{heur:>6} '
              f'{int(pat["canonical_iso_conflicts"]):>6}')

        assert int(pat['skeleton_conflicts']) == int(spec['expect_skeleton_conflicts']), (
            dirname, pat['skeleton_conflicts'])
        assert int(pat['block_injectivity_conflicts']) == int(
            spec['expect_block_conflicts']), dirname
        assert pat['strict_pattern_perfect'] == spec['expect_strict_pattern']
        if spec['expect_canonical_iso'] is not None:
            assert int(pat['canonical_iso_conflicts']) == int(
                spec['expect_canonical_iso']), dirname
        if spec['expect_heuristic_score'] is not None:
            assert pinned_heur == spec['expect_heuristic_score'], dirname
        if dirname == 'skeleton_pattern_allomorph_quality_v4':
            assert 700 < heur < 800, heur

    v3 = next(r for r in pattern_rows
              if r['dir'] == 'skeleton_pattern_candidate_v3')
    v4 = next(r for r in pattern_rows
              if r['dir'] == 'skeleton_pattern_allomorph_quality_v4')

    print()
    print('  → v3 is strict pattern-perfect (readable constraints satisfied).')
    print('    v4 is skeleton-perfect with 237 surface block collisions — the')
    print('    intended allomorph reading; canonical-ISO literals are diagnostic')
    print('    only (§238 does not require them).  v8 fails skeleton layer.')
    print('    Use: python3 eye/validate_plaintext_patterns.py <path>')
    print('         python3 eye/audit_construction_plaintext.py <path>')

    assert v3['skeleton_layer_perfect'] is True
    assert v3['strict_pattern_perfect'] is True
    assert v4['skeleton_layer_perfect'] is True
    assert v4['strict_pattern_perfect'] is False
    assert int(v4['block_injectivity_conflicts']) == 237

    v5 = next((r for r in pattern_rows
               if r['dir'] == 'skeleton_pattern_allomorph_quality_v5'), None)
    if v5 is not None:
        assert v5['skeleton_layer_perfect'] is True
        assert v5['strict_pattern_perfect'] is False

    return {
        'pattern_rows': pattern_rows,
        'booked': True,
    }


def section_240_construction_artifact_regression_gate(
        m: dict[str, list[int]]) -> dict:
    """§240 — rule in/out for construction artifacts (forbidden shards, caps).

    Negative control: v4 must still contain ``carrs`` / ``hat wit``.
    Promoted v5: forbidden shards zero, artifact total and heuristic capped.
    Lineage: v5 strictly better than v4 on artifact total and heuristic.
    """
    banner(240, 'CONSTRUCTION ARTIFACT REGRESSION GATE')

    eye_dir = Path(__file__).parent
    rows: list[dict[str, object]] = []
    audits: dict[str, dict[str, object]] = {}

    print(f'  {"artifact":<42} {"total":>6} {"heur":>6} {"viol":>5}')
    print('  ' + '-' * 65)
    for spec in _PINNED_CONSTRUCTION_ARTIFACTS:
        dirname = str(spec['dir'])
        plain = json.loads(
            (eye_dir / dirname / 'best_plaintext.json').read_text())
        chk = _construction_check_artifact_rules(plain, spec)
        audits[dirname] = chk
        rows.append({'dir': dirname, **chk})
        print(f'  {dirname:<42} '
              f'{int(chk["artifact_phrase_total"]):>6} '
              f'{int(chk["heuristic_score"]):>6} '
              f'{len(chk["violations"]):>5}')
        assert not chk['violations'], (dirname, chk['violations'])

    v4_a = audits['skeleton_pattern_allomorph_quality_v4']
    v5_a = audits['skeleton_pattern_allomorph_quality_v5']
    kv('v4 → v5 artifact total', (v4_a['artifact_phrase_total'], v5_a['artifact_phrase_total']))
    kv('v4 → v5 heuristic', (v4_a['heuristic_score'], v5_a['heuristic_score']))
    kv('v5 forbidden-zero phrases', _CONSTRUCTION_FORBIDDEN_ARTIFACT_PHRASES)

    print()
    print('  → RULED IN: v5 (template-repaired allomorph) beats v4 on artifacts/heuristic,')
    print('    keeps skeleton-layer perfect, forbids regressed template shards.')
    print('  → RULED OUT: treating v4/v5 as decryption (§234/§238); v3 remains strict-perfect.')

    assert int(v4_a['artifact_phrase_total']) > int(v5_a['artifact_phrase_total'])
    assert int(v4_a['heuristic_score']) > int(v5_a['heuristic_score'])
    assert v4_a['artifact_phrase_counts'].get('carrs', 0) >= 10
    assert v5_a['artifact_phrase_counts'].get('carrs', 0) == 0
    assert v5_a['artifact_phrase_counts'].get('hat wit', 0) == 0

    return {
        'rows': rows,
        'forbidden_phrases': _CONSTRUCTION_FORBIDDEN_ARTIFACT_PHRASES,
        'booked': True,
    }


