    kv('repaired artifact phrase total', rep_a['artifact_phrase_total'])
    kv('base / repaired heuristic', (base_a['heuristic_score'], rep_a['heuristic_score']))
    kv('template search candidates', ts['candidate_count'])
    kv('repaired block-injectivity conflicts',
       rep_a['block_injectivity_conflicts'])

    print()
    print('  → Shared 27-char template repair cuts visible artifact phrases')
    print('    (carrs, hat wit, youndoo, …) while keeping skeleton-layer perfect.')
    print('    Block-injectivity collisions stay high — still allomorph surface.')
    print('    CLI: python3 eye/construction_quality_loop.py')

    assert int(base_a['skeleton_conflicts']) == 0
    assert int(base_a['block_injectivity_conflicts']) == 237
    assert int(base_a['artifact_phrase_total']) == 44
    assert base_a['artifact_phrase_counts'].get('carrs', 0) >= 10
    assert int(ts['candidate_count']) == 1500
    assert int(rep_a['skeleton_conflicts']) == 0
    assert int(rep_a['block_injectivity_conflicts']) == 233
    assert int(rep_a['artifact_phrase_total']) == 16
    assert int(rep_a['heuristic_score']) < int(base_a['heuristic_score'])
    assert int(rep_a['artifact_phrase_total']) < int(base_a['artifact_phrase_total'])

    # Promoted baseline must match §240 pinned v5 file.
