_PINNED_221_FAMILY_SUMMARY: tuple[tuple[str, int, int, int], ...] = (
    ('alpha', 32, 3, 2),
    ('bridge', 26, 3, 0),
    ('beta', 39, 4, 2),
)


def section_221_family_body_template_inventory(
        m: dict[str, list[int]]) -> dict:
    """§221 — inventory family-local clause templates after the crib atom."""
    banner(221, 'FAMILY/BODY TEMPLATE INVENTORY FOR LM SEARCH')
    skel = _load_plaintext_skeleton()
    cls_to_cells = _skeleton_class_to_cells(skel)
    nonsing = {cl_x for cl_x, cs_x in cls_to_cells.items() if len(cs_x) >= 2}
    period_classes, space_classes = _period_space_candidate_groups(skel)
    atom_positions = _period_space_atom_positions(
        skel, m, period_classes, space_classes)
    families: tuple[tuple[str, tuple[str, ...]], ...] = (
        ('alpha', ('E1', 'W1', 'E2')),
        ('bridge', ('W2', 'E3', 'W3')),
        ('beta', ('E4', 'W4', 'E5')),
    )

    bodies: dict[tuple[str, int], tuple[int, ...]] = {}
    for label_l in MSG_LABELS:
        seq = _msg_class_seq(skel, m, label_l)
        atoms_l = atom_positions[label_l]
        for idx_a, p_atom in enumerate(atoms_l):
            body_start = p_atom + 2
            body_end = (atoms_l[idx_a + 1] - 1
                        if idx_a + 1 < len(atoms_l) else len(seq) - 1)
            bodies[(label_l, p_atom)] = seq[body_start:body_end + 1]

    family_rows: list[tuple[str, int, int, int, tuple[tuple[int, str, int, str, int], ...]]] = []
    for fam_name, labels in families:
        fam_keys = [key for key in bodies if key[0] in labels]
        pair_lcs: list[tuple[int, str, int, str, int]] = []
        for i_a, key_a in enumerate(fam_keys):
            for key_b in fam_keys[i_a + 1:]:
                lcs_len, _sa, _sb = _longest_common_substring(
                    bodies[key_a], bodies[key_b])
                pair_lcs.append((lcs_len, key_a[0], key_a[1], key_b[0], key_b[1]))
        pair_lcs.sort(reverse=True)
        max_lcs = pair_lcs[0][0] if pair_lcs else 0
        ge20 = sum(1 for row in pair_lcs if row[0] >= 20)
        ge30 = sum(1 for row in pair_lcs if row[0] >= 30)
        family_rows.append((fam_name, max_lcs, ge20, ge30, tuple(pair_lcs[:8])))

    print('  -- family-local body template summary --')
    for fam_name, max_lcs, ge20, ge30, top_rows in family_rows:
        kv(fam_name, f'max_lcs={max_lcs}  pairs≥20={ge20}  pairs≥30={ge30}')
        for row in top_rows[:5]:
            print(f'      LCS={row[0]:2d}: {row[1]}@{row[2]} ↔ {row[3]}@{row[4]}')

    print()
    print('  -- canonical body starts per family (first 40 tokens) --')
    for fam_name, labels in families:
        print(f'  {fam_name}:')
        for label_l in labels:
            for p_atom in atom_positions[label_l]:
                body = bodies[(label_l, p_atom)]
                toks = ' '.join(_class_grid_token(c_x, nonsing) for c_x in body[:40])
                more = ' ...' if len(body) > 40 else ''
                print(f'      {label_l}@{p_atom}: len={len(body):3d}  {toks}{more}')

    print()
    print('  → These are the body templates a Finnish/text-source search')
    print('    should score: compare bodies within each family first, then')
    print('    align cross-family where §217 reports LCS ≥20.')

    assert len(family_rows) == 3
    live_summary = {
        row[0]: (row[1], row[2], row[3]) for row in family_rows}
    for fam, max_lcs, ge20, ge30 in _PINNED_221_FAMILY_SUMMARY:
        assert live_summary[fam] == (max_lcs, ge20, ge30), (
            fam, live_summary[fam], (max_lcs, ge20, ge30))
    assert max(row[1] for row in family_rows) >= 30

    return {
        'family_rows': family_rows,
        'pinned_summary': _PINNED_221_FAMILY_SUMMARY,
        'booked': True,
    }


def section_222_crib_aware_candidate_scoring_hooks(
        m: dict[str, list[int]]) -> dict:
    """§222 — executable constraints any candidate plaintext must satisfy.

    This is not a language model.  It emits and checks the hard constraints
    that a future candidate plaintext scorer should enforce:

    1. all classes in the period group map to one symbol,
    2. all classes in the space-after-period group map to a second symbol,
    3. the two symbols are distinct,
    4. within every 91-block, no two skeleton classes share a plaintext
       symbol (Rule-A / σ-injectivity).
    """
    banner(222, 'CRIB-AWARE CANDIDATE SCORING HOOKS')
    skel = _load_plaintext_skeleton()
    cls_to_cells = _skeleton_class_to_cells(skel)
    blocks = _skeleton_blocks(skel, m)
    period_classes, space_classes = _period_space_candidate_groups(skel)

    # Minimal pinned assignment used as a self-test for the hook:
    # every unpinned class gets its own private symbol, so only pin
    # constraints can fail.
    assignment: dict[int, str] = {}
    for cls_id in cls_to_cells:
        if cls_id in period_classes:
            assignment[cls_id] = 'PERIOD'
        elif cls_id in space_classes:
            assignment[cls_id] = 'SPACE_AFTER_PERIOD'
        else:
            assignment[cls_id] = f'X{cls_id:03d}'

    def score_assignment(assign: dict[int, str]) -> tuple[int, list[str]]:
        violations: list[str] = []
        per_syms = {assign[c_x] for c_x in period_classes}
        sp_syms = {assign[c_x] for c_x in space_classes}
        if len(per_syms) != 1:
            violations.append('period group not unified')
        if len(sp_syms) != 1:
            violations.append('space-after-period group not unified')
        if per_syms and sp_syms and next(iter(per_syms)) == next(iter(sp_syms)):
            violations.append('period and space symbols collide')
        for label_l in MSG_LABELS:
            for s_e, e_e in blocks[label_l]:
                seen: dict[str, int] = {}
                for p_p in range(s_e, e_e + 1):
                    cls_p = skel[(label_l, p_p)]
                    sym_p = assign[cls_p]
                    if sym_p in seen and seen[sym_p] != cls_p:
                        violations.append(
                            f'block injectivity fail {label_l}[{s_e}..{e_e}] '
                            f'{seen[sym_p]} vs {cls_p} -> {sym_p}')
                        break
                    seen[sym_p] = cls_p
        return len(violations), violations

    n_bad, violations = score_assignment(assignment)
    constraints_json = {
        'period_classes': sorted(period_classes),
        'space_after_period_classes': sorted(space_classes),
        'distinct_symbol_groups': [
            ['period_classes', 'space_after_period_classes'],
        ],
        'block_injectivity': {
            label_l: blocks[label_l] for label_l in MSG_LABELS
        },
    }

    kv('constraint groups emitted',
       ('period_classes unified', 'space_after_period_classes unified',
        'period != space', 'per-block injectivity'))
    kv('self-test assignment violations', n_bad)
    kv('constraint summary JSON keys', tuple(sorted(constraints_json)))
    kv('period/space classes',
       (tuple(sorted(period_classes)), tuple(sorted(space_classes))))

    print()
    print('  → A candidate plaintext scorer should first enforce these hard')
    print('    constraints, then use an LM only to rank assignments that pass.')
    print('    This avoids letting language-model plausibility override the')
    print('    clean skeleton + crib evidence.')

    assert n_bad == 0, violations[:3]

    return {
        'self_test_violations': n_bad,
        'period_classes': tuple(sorted(period_classes)),
        'space_after_period_classes': tuple(sorted(space_classes)),
        'constraint_keys': tuple(sorted(constraints_json)),
        'booked': False,
    }


def _candidate_window_score(
        seq: tuple[int, ...],
        text: str,
        period_classes: set[int],
        space_classes: set[int]) -> tuple[int, int, int, int]:
    """Score a candidate plaintext window against a skeleton sequence.

    Returns ``(pin_violations, class_consistency_violations,
    injectivity_collisions, total_weighted_penalty)``.  Lower is better.
    """
    cls_to_char: dict[int, str] = {}
    char_to_cls: dict[str, int] = {}
    pin_viol = 0
    class_viol = 0
    collision_viol = 0
    for cls_p, ch_p in zip(seq, text):
        if cls_p in period_classes and ch_p != '.':
            pin_viol += 1
        if cls_p in space_classes and ch_p != ' ':
            pin_viol += 1
        prev_ch = cls_to_char.get(cls_p)
        if prev_ch is None:
            cls_to_char[cls_p] = ch_p
        elif prev_ch != ch_p:
            class_viol += 1
        prev_cls = char_to_cls.get(ch_p)
        if prev_cls is None:
            char_to_cls[ch_p] = cls_p
        elif prev_cls != cls_p:
            collision_viol += 1
    total = pin_viol * 1000 + class_viol * 100 + collision_viol
    return pin_viol, class_viol, collision_viol, total


def _iter_repo_text_corpus_files(root: Path) -> list[Path]:
    """Small deterministic text corpus scan, excluding environments/builds."""
    suffixes = {'.txt', '.md', '.xml', '.lua', '.json', '.csv', '.cfg',
                '.ini', '.po'}
    skip_dirs = {
        '.git', '.github', '.cursor', '__pycache__', 'venv', 'venv-py313',
        'node_modules', 'target', '.mypy_cache', '.pytest_cache',
    }
    skip_names = {
        'cryptanalysis_harness.py',
        'CRYPTANALYSIS.md',
        'THIRD_PARTY.md',
        'crib_pinned_skeleton_artifact_v1.json',
        'uf_csp_shell_artifact_v1.json',
    }
    out: list[Path] = []
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = sorted(d for d in dirnames if d not in skip_dirs)
        base = Path(dirpath)
        for name in sorted(filenames):
            pth = base / name
            if name in skip_names:
                continue
            if pth.suffix.lower() not in suffixes:
                continue
            out.append(pth)
    priority = {
        'game': 0,
        'extracted': 1,
        'data': 2,
        'ca_data': 3,
        'mods': 4,
        'eye': 5,
        'engine': 6,
        're': 7,
    }

    def sort_key(pth: Path) -> tuple[int, str]:
        try:
            first = pth.relative_to(root).parts[0]
        except ValueError:
            first = ''
        return (priority.get(first, 99), str(pth))

    return sorted(out, key=sort_key)


def section_223_repo_corpus_pattern_search(
        m: dict[str, list[int]]) -> dict:
    """§223 — scan local repo text assets for skeleton-compatible windows.

    This is a cheap high-upside external-text test.  For every candidate
    text window with the same length as a message, score whether it can map
    to the message's skeleton classes while respecting the `". "` pins.
    Exact hits would be dramatic; near misses tell us whether local game
    text resembles the skeleton at all.
    """
    banner(223, 'REPO CORPUS PATTERN SEARCH')
    root = Path(__file__).resolve().parents[1]
    skel = _load_plaintext_skeleton()
    period_classes, space_classes = _period_space_candidate_groups(skel)
    seqs = {label_l: _msg_class_seq(skel, m, label_l) for label_l in MSG_LABELS}

    top_rows: list[tuple[int, int, int, int, str, int, str, str]] = []
    exact_hits: list[tuple[str, int, str]] = []
    scanned_files = 0
    scanned_chars = 0
    scanned_windows = 0
    max_total_chars = 3_000_000
    max_file_chars = 250_000

    for pth in _iter_repo_text_corpus_files(root):
        if scanned_chars >= max_total_chars:
            break
        try:
            raw = pth.read_text(encoding='utf-8', errors='ignore')
        except OSError:
            continue
        if not raw.strip():
            continue
        text = ' '.join(raw.split())
        if len(text) < min(len(seq) for seq in seqs.values()):
            continue
        if len(text) > max_file_chars:
            text = text[:max_file_chars]
        scanned_files += 1
        scanned_chars += len(text)
        rel = str(pth.relative_to(root))
        # The crib says every message window must have ". " at relative
        # offsets 1..2.  Score only such windows; brute-force all windows is
        # both slower and less relevant to this external-text test.
        dot_space_offsets: list[int] = []
        start = 0
        while True:
            idx = text.find('. ', start)
            if idx < 0:
                break
            off = idx - 1
            if off >= 0:
                dot_space_offsets.append(off)
            start = idx + 1
        for label_l, seq in seqs.items():
            L = len(seq)
            if len(text) < L:
                continue
            for off in dot_space_offsets:
                if off + L > len(text):
                    continue
                window = text[off:off + L]
                pin_v, cls_v, inj_v, total = _candidate_window_score(
                    seq, window, period_classes, space_classes)
                scanned_windows += 1
                if total == 0:
                    exact_hits.append((rel, off, label_l))
                row = (total, pin_v, cls_v, inj_v, label_l, off,
                       rel, window[:80])
                if len(top_rows) < 20:
                    top_rows.append(row)
                    top_rows.sort()
                elif row < top_rows[-1]:
                    top_rows[-1] = row
                    top_rows.sort()

    kv('files / chars / windows scanned',
       (scanned_files, scanned_chars, scanned_windows))
    kv('exact skeleton-compatible hits', len(exact_hits))
    kv('top-10 corpus windows (penalty,pin,class,collision,label,offset,path,snippet)',
       tuple(top_rows[:10]))

    print()
    print('  → Exact hit = local corpus likely contains a plaintext message.')
    print('    No exact hit means local text assets do not trivially explain')
    print('    the skeleton under the period-space crib.')

    assert scanned_files > 0
    assert scanned_windows > 0

    return {
        'scanned_files': scanned_files,
        'scanned_chars': scanned_chars,
        'scanned_windows': scanned_windows,
        'exact_hits': tuple(exact_hits[:10]),
        'top_rows': tuple(top_rows[:10]),
        'booked': False,
    }


def section_224_crib_pinned_sa_readiness_audit(
        m: dict[str, list[int]]) -> dict:
    """§224 — audit existing SA scripts for crib-pinning readiness."""
    banner(224, 'CRIB-PINNED SA READINESS AUDIT')
    eye_dir = Path(__file__).parent
    files = {
        'tier_c6_pinned_solver.py': eye_dir / 'tier_c6_pinned_solver.py',
        'tier_c11_finnish_deep.py': eye_dir / 'tier_c11_finnish_deep.py',
        'tier_c13_finnish_consensus.py': eye_dir / 'tier_c13_finnish_consensus.py',
        'hill_climber.py': eye_dir / 'hill_climber.py',
    }
    checks: dict[str, dict[str, bool]] = {}
    for name, pth in files.items():
        txt = pth.read_text(errors='ignore') if pth.exists() else ''
        checks[name] = {
            'exists': pth.exists(),
            'uses_PinnedSolver': 'PinnedSolver' in txt,
            'pins_E1_only': "('E1', 1)" in txt and "('E1', 2)" in txt,
            'uses_full_period_group': 'period_classes' in txt,
            'uses_skeleton_artifact': 'crib_pinned_skeleton_artifact' in txt,
            'has_block_injectivity': 'block' in txt.lower() and (
                'inject' in txt.lower() or 'class_nbrs' in txt),
        }

    ready_files = [
        name for name, ck in checks.items()
        if ck['uses_skeleton_artifact'] or ck['uses_full_period_group']
    ]
    legacy_pin_files = [name for name, ck in checks.items() if ck['pins_E1_only']]

    kv('SA/readiness file checks', checks)
    kv('files already using full crib group or artifact', tuple(ready_files))
    kv('files with legacy E1-only pins', tuple(legacy_pin_files))

    print()
    print('  → Existing Finnish SA pins only E1[1]/E1[2].  To use the')
    print('    skeleton crib correctly, update PinnedSolver input to pin all')
    print('    5 period classes and all 5 space-after-period classes, or load')
    print('    crib_pinned_skeleton_artifact_v1.json and enforce §222 hooks.')

    assert checks['tier_c6_pinned_solver.py']['uses_PinnedSolver']
    assert legacy_pin_files

    return {
        'checks': checks,
        'ready_files': tuple(ready_files),
        'legacy_pin_files': tuple(legacy_pin_files),
        'booked': False,
    }


def section_225_pinned_baseline_scorer(
        m: dict[str, list[int]]) -> dict:
    """§225 — baseline hard-constraint scorer for candidate assignments."""
    banner(225, 'PINNED BASELINE SCORER')
    skel = _load_plaintext_skeleton()
    cls_to_cells = _skeleton_class_to_cells(skel)
    period_classes, space_classes = _period_space_candidate_groups(skel)
    blocks = _skeleton_blocks(skel, m)

    def assignment_violations(assign: dict[int, str]) -> tuple[int, Counter[str]]:
        by_kind: Counter[str] = Counter()
        if len({assign[c_x] for c_x in period_classes}) != 1:
            by_kind['period_not_unified'] += 1
        if len({assign[c_x] for c_x in space_classes}) != 1:
            by_kind['space_not_unified'] += 1
        if next(iter({assign[c_x] for c_x in period_classes})) == next(
                iter({assign[c_x] for c_x in space_classes})):
            by_kind['period_space_collision'] += 1
        for label_l in MSG_LABELS:
            for s_e, e_e in blocks[label_l]:
                seen: dict[str, int] = {}
                for p_p in range(s_e, e_e + 1):
                    cls_p = skel[(label_l, p_p)]
                    sym_p = assign[cls_p]
                    if sym_p in seen and seen[sym_p] != cls_p:
                        by_kind['block_injectivity'] += 1
                        break
                    seen[sym_p] = cls_p
        return sum(by_kind.values()), by_kind

    good_assign = {
        cls_id: (
            'PERIOD' if cls_id in period_classes else
            'SPACE_AFTER_PERIOD' if cls_id in space_classes else
            f'X{cls_id:03d}'
        )
        for cls_id in cls_to_cells
    }
    collapsed_assign = {cls_id: 'A' for cls_id in cls_to_cells}
    e1_only_assign = {
        cls_id: f'X{cls_id:03d}' for cls_id in cls_to_cells
    }
    for cls_id in period_classes:
        e1_only_assign[cls_id] = f'X{cls_id:03d}'
    for cls_id in space_classes:
        e1_only_assign[cls_id] = f'X{cls_id:03d}'
    # Simulate the old weak pin: only the E1 classes get period/space.
    e1_only_assign[skel[('E1', 1)]] = 'PERIOD'
    e1_only_assign[skel[('E1', 2)]] = 'SPACE_AFTER_PERIOD'

    good_n, good_k = assignment_violations(good_assign)
    collapsed_n, collapsed_k = assignment_violations(collapsed_assign)
    e1_only_n, e1_only_k = assignment_violations(e1_only_assign)

    kv('valid private-symbol witness violations', (good_n, dict(good_k)))
    kv('collapsed all-A witness violations', (collapsed_n, dict(collapsed_k)))
    kv('legacy E1-only pin witness violations', (e1_only_n, dict(e1_only_k)))

    print()
    print('  → This is the minimal hard scorer: candidate assignments with')
    print('    nonzero violations should be rejected before any language-model')
    print('    scoring.  The old E1-only pin does not enforce the full crib.')

    assert good_n == 0
    assert collapsed_n > 0
    assert e1_only_n > 0

    return {
        'valid_witness_violations': good_n,
        'collapsed_witness_violations': collapsed_n,
        'legacy_e1_only_violations': e1_only_n,
        'booked': False,
    }


