def section_347_family_frequency_divergence(m: dict[str, list[int]]) -> dict:
    """§347: Family A vs B frequency divergence (KL divergence)."""
    banner(347, 'FAMILY FREQUENCY DIVERGENCE')
    from math import log2 as _log2
    fam_a = ['E1', 'W1', 'E2']
    fam_b = ['E4', 'W4', 'E5']
    freq_a = Counter(v for l in fam_a for v in m[l])
    freq_b = Counter(v for l in fam_b for v in m[l])
    n_a = sum(freq_a.values())
    n_b = sum(freq_b.values())
    # Symmetrized KL (Jensen-Shannon divergence)
    jsd = 0.0
    for v in range(MOD):
        p = freq_a.get(v, 0) / n_a
        q = freq_b.get(v, 0) / n_b
        m_v = (p + q) / 2
        if p > 0 and m_v > 0:
            jsd += 0.5 * p * _log2(p / m_v)
        if q > 0 and m_v > 0:
            jsd += 0.5 * q * _log2(q / m_v)
    kv('JSD(Family A, Family B)', f'{jsd:.6f} bits')
    kv('max possible JSD', '1.0 bits')
    assert jsd < 0.15, f'JSD too high: {jsd:.4f}'
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  JSD = {jsd:.4f} bits — families have similar frequency profiles.')
    print('  ══════════════════════════════════════════════════════════')
    return {'jsd': jsd}


def section_348_cross_message_bigram_sharing(m: dict[str, list[int]]) -> dict:
    """§348: Cross-message bigram sharing."""
    banner(348, 'CROSS-MESSAGE BIGRAM SHARING')
    msg_bigrams: dict[str, set] = {}
    for label in MSG_LABELS:
        vals = m[label]
        msg_bigrams[label] = {(vals[i], vals[i+1]) for i in range(len(vals)-1)}
    print()
    print(f'  {"pair":>8s} {"shared":>7s} {"A_size":>7s} {"B_size":>7s} {"Jaccard":>8s}')
    jaccards = []
    for la, lb in [('E1','W1'),('E1','E2'),('E4','W4'),('E1','E4'),('E3','W3')]:
        shared = len(msg_bigrams[la] & msg_bigrams[lb])
        union = len(msg_bigrams[la] | msg_bigrams[lb])
        j = shared / union if union > 0 else 0
        jaccards.append(j)
        print(f'  {la+"-"+lb:>8s} {shared:7d} {len(msg_bigrams[la]):7d} '
              f'{len(msg_bigrams[lb]):7d} {j:8.3f}')
    avg_j = sum(jaccards) / len(jaccards)
    kv('avg Jaccard', f'{avg_j:.3f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BIGRAM SHARING: avg Jaccard = {avg_j:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_jaccard': avg_j}


