def section_351_message_centroid(m: dict[str, list[int]]) -> dict:
    """§351: Message centroid and dispersion."""
    banner(351, 'MESSAGE CENTROID AND DISPERSION')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    means = []
    variances = []
    for j in range(min_len):
        vals = [m[l][j] for l in MSG_LABELS]
        mean = sum(vals) / len(vals)
        var = sum((v - mean) ** 2 for v in vals) / len(vals)
        means.append(mean)
        variances.append(var)
    avg_mean = sum(means) / len(means)
    avg_var = sum(variances) / len(variances)
    kv('avg position mean', f'{avg_mean:.2f}')
    kv('avg position variance', f'{avg_var:.1f}')
