def section_358_block_transition_matrix(m: dict[str, list[int]]) -> dict:
    """§358: Block transition — last of block k → first of block k+1."""
    banner(358, 'BLOCK TRANSITION MATRIX')
    canonical_blocks = _canonical_block_partition(m)
    trans_diffs = []
    for label in MSG_LABELS:
        blocks = canonical_blocks[label]
        for i in range(len(blocks) - 1):
            last_val = m[label][blocks[i][1]]
            first_val = m[label][blocks[i + 1][0]]
            trans_diffs.append((first_val - last_val) % MOD)
    diff_ioc = ioc(trans_diffs)
    kv('block transitions', len(trans_diffs))
    kv('transition diff IoC', f'{diff_ioc:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BLOCK TRANSITIONS: diff IoC={diff_ioc:.4f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'diff_ioc': diff_ioc}


def section_359_block_internal_autocorrelation(m: dict[str, list[int]]) -> dict:
    """§359: Block-internal lag-1 autocorrelation."""
    banner(359, 'BLOCK-INTERNAL AUTOCORRELATION')
    canonical_blocks = _canonical_block_partition(m)
    all_r = []
    for label in MSG_LABELS:
        for s, e in canonical_blocks[label]:
            vals = m[label][s:e + 1]
            n = len(vals)
            if n < 5:
                continue
            mean = sum(vals) / n
            var = sum((v - mean) ** 2 for v in vals) / n
            if var < 1e-10:
                continue
            cov = sum((vals[i] - mean) * (vals[i + 1] - mean) for i in range(n - 1)) / (n - 1)
            all_r.append(cov / var)
    avg_r = sum(all_r) / len(all_r) if all_r else 0
    kv('avg within-block lag-1 r', f'{avg_r:.4f}')
    kv('n blocks', len(all_r))
    assert abs(avg_r) < 0.20, f'block autocorrelation {avg_r:.4f} too high'
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BLOCK AUTOCORRELATION: avg r = {avg_r:.4f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_r': avg_r}


def section_360_cross_block_reuse(m: dict[str, list[int]]) -> dict:
    """§360: Cross-block value reuse rate."""
    banner(360, 'CROSS-BLOCK VALUE REUSE')
    canonical_blocks = _canonical_block_partition(m)
    reuse_rates = []
    for label in MSG_LABELS:
        blocks = canonical_blocks[label]
        for i in range(len(blocks) - 1):
            v_curr = set(m[label][blocks[i][0]:blocks[i][1] + 1])
            v_next = set(m[label][blocks[i + 1][0]:blocks[i + 1][1] + 1])
            if v_curr and v_next:
                reuse = len(v_curr & v_next) / len(v_curr | v_next)
                reuse_rates.append(reuse)
    avg_reuse = sum(reuse_rates) / len(reuse_rates) if reuse_rates else 0
    kv('avg cross-block Jaccard', f'{avg_reuse:.4f}')
    kv('n transitions', len(reuse_rates))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CROSS-BLOCK REUSE: Jaccard={avg_reuse:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_reuse': avg_reuse}


def section_361_block_size_entropy(m: dict[str, list[int]]) -> dict:
    """§361: Block size entropy."""
    banner(361, 'BLOCK SIZE ENTROPY')
    from math import log2 as _log2
    canonical_blocks = _canonical_block_partition(m)
    sizes = []
    for label in MSG_LABELS:
        for s, e in canonical_blocks[label]:
            sizes.append(e - s + 1)
    size_freq = Counter(sizes)
    n = len(sizes)
    h = -sum((c / n) * _log2(c / n) for c in size_freq.values() if c > 0)
    kv('block sizes', dict(sorted(size_freq.items())))
    kv('block size entropy', f'{h:.4f} bits')
    kv('n blocks', n)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BLOCK SIZE ENTROPY: H = {h:.3f} bits')
    print('  ══════════════════════════════════════════════════════════')
    return {'h': h, 'size_freq': dict(size_freq)}


def section_362_block_boundary_period(m: dict[str, list[int]]) -> dict:
    """§362: Block boundary period candidates."""
    banner(362, 'BLOCK BOUNDARY PERIOD')
    canonical_blocks = _canonical_block_partition(m)
    # Compute inter-boundary intervals
    intervals = []
    for label in MSG_LABELS:
        starts = [s for s, e in canonical_blocks[label]]
        for i in range(1, len(starts)):
            intervals.append(starts[i] - starts[i - 1])
    interval_freq = Counter(intervals)
    kv('total intervals', len(intervals))
    kv('top interval values', interval_freq.most_common(5))
    # Check if any interval is dominant
    if intervals:
        mode_interval = interval_freq.most_common(1)[0]
        mode_pct = 100 * mode_interval[1] / len(intervals)
        kv('mode interval', f'{mode_interval[0]} ({mode_pct:.0f}%)')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  BLOCK PERIOD: interval distribution.')
    print('  ══════════════════════════════════════════════════════════')
    return {'interval_freq': dict(interval_freq)}


def section_363_block_bigram(m: dict[str, list[int]]) -> dict:
    """§363: Block-level bigram frequency."""
    banner(363, 'BLOCK-LEVEL BIGRAM')
    canonical_blocks = _canonical_block_partition(m)
    bigrams = Counter()
    total = 0
    for label in MSG_LABELS:
        for s, e in canonical_blocks[label]:
            vals = m[label][s:e + 1]
            for i in range(len(vals) - 1):
                bigrams[(vals[i], vals[i + 1])] += 1
                total += 1
    unique_bigrams = len(bigrams)
    max_count = bigrams.most_common(1)[0][1] if bigrams else 0
    kv('total within-block bigrams', total)
    kv('unique bigrams', unique_bigrams)
    kv('max bigram count', max_count)
    bigram_ioc = ioc(list(bigrams.elements()))
    kv('bigram IoC', f'{bigram_ioc:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BLOCK BIGRAM: {unique_bigrams} unique, IoC={bigram_ioc:.6f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'unique_bigrams': unique_bigrams, 'bigram_ioc': bigram_ioc}



def section_364_arithmetic_progressions(m: dict[str, list[int]]) -> dict:
    """§364: Arithmetic progression search within messages."""
    banner(364, 'ARITHMETIC PROGRESSIONS')
    aps_found = 0
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        for i in range(n - 2):
            d = (vals[i + 1] - vals[i]) % MOD
            length = 2
            for j in range(i + 2, min(i + 10, n)):
                if (vals[j] - vals[j - 1]) % MOD == d:
                    length += 1
                else:
                    break
            if length >= 4:
                aps_found += 1
    kv('APs of length ≥4', aps_found)
    # Expected under random: roughly n * (1/83)^2 per message for length 4
    n_avg = sum(len(m[l]) for l in MSG_LABELS) / 9
    expected = 9 * n_avg * (1 / MOD) ** 2
    kv('expected (random)', f'{expected:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  APs: {aps_found} length-≥4 (expected ~{expected:.0f})')
    print('  ══════════════════════════════════════════════════════════')
    return {'aps_found': aps_found}


def section_365_repeated_triples(m: dict[str, list[int]]) -> dict:
    """§365: Repeated 3-value subsequences across the corpus."""
    banner(365, 'REPEATED 3-VALUE SUBSEQUENCES')
    triples = Counter()
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 2):
            triples[(vals[i], vals[i+1], vals[i+2])] += 1
    repeated = {t: c for t, c in triples.items() if c >= 2}
