def section_367_value_clusters(m: dict[str, list[int]]) -> dict:
    """§367: Value cluster detection — spatially close high/low values."""
    banner(367, 'VALUE CLUSTER DETECTION')
    # Check if high values (>60) or low values (<20) cluster
    for threshold_name, condition in [('high (>60)', lambda v: v > 60),
                                       ('low (<20)', lambda v: v < 20)]:
        all_gaps = []
        for label in MSG_LABELS:
            positions = [i for i, v in enumerate(m[label]) if condition(v)]
            for i in range(1, len(positions)):
                all_gaps.append(positions[i] - positions[i - 1])
        if all_gaps:
            avg_gap = sum(all_gaps) / len(all_gaps)
            min_gap = min(all_gaps)
            kv(f'{threshold_name} avg gap', f'{avg_gap:.1f}')
            kv(f'{threshold_name} min gap', min_gap)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  VALUE CLUSTERS: no anomalous clustering detected.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_368_position_value_chi2(m: dict[str, list[int]]) -> dict:
    """§368: Position × value chi-squared test."""
    banner(368, 'POSITION-VALUE CHI-SQUARED')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    # Group positions mod 26 (row pair period)
    bins = defaultdict(list)
    for label in MSG_LABELS:
        for i in range(min_len):
            bins[i % 26].append(m[label][i])
    chi2_vals = {}
    for b in range(26):
        vals = bins[b]
        n = len(vals)
        freq = Counter(vals)
        expected = n / MOD
        chi2 = sum((freq.get(v, 0) - expected) ** 2 / expected for v in range(MOD))
        chi2_vals[b] = chi2
    avg_chi2 = sum(chi2_vals.values()) / len(chi2_vals)
    max_chi2 = max(chi2_vals.values())
    kv('avg pos-mod-26 χ²', f'{avg_chi2:.1f}')
    kv('max pos-mod-26 χ²', f'{max_chi2:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  POSITION-VALUE: avg χ²={avg_chi2:.0f}, max={max_chi2:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_chi2': avg_chi2, 'max_chi2': max_chi2}


def section_369_near_miss_isomorphs(m: dict[str, list[int]]) -> dict:
    """§369: Near-miss isomorphs — differ by 1-2 positions."""
    banner(369, 'NEAR-MISS ISOMORPHS')
    near_misses = 0
    for la, lb in [('E1','W1'), ('E1','E2'), ('E4','W4')]:
        min_len = min(len(m[la]), len(m[lb]))
        for L in range(8, 15):
            for i in range(min_len - L):
                s1 = m[la][i:i+L]
                s2 = m[lb][i:i+L]
                p1 = canonical_pattern(s1)
                p2 = canonical_pattern(s2)
                diffs = sum(1 for a, b in zip(p1, p2) if a != b)
                if 1 <= diffs <= 2:
                    near_misses += 1
    kv('near-miss isomorphs (1-2 diffs)', near_misses)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  NEAR-MISS: {near_misses} found.')
    print('  ══════════════════════════════════════════════════════════')
    return {'near_misses': near_misses}


def section_370_skip_grams(m: dict[str, list[int]]) -> dict:
    """§370: Skip-gram patterns (every other position)."""
    banner(370, 'SKIP-GRAM PATTERNS')
    even_iocs = []
    odd_iocs = []
    for label in MSG_LABELS:
        vals = m[label]
        evens = [vals[i] for i in range(0, len(vals), 2)]
        odds = [vals[i] for i in range(1, len(vals), 2)]
        even_iocs.append(ioc(evens))
        odd_iocs.append(ioc(odds))
    avg_even = sum(even_iocs) / len(even_iocs)
    avg_odd = sum(odd_iocs) / len(odd_iocs)
    full_iocs = [ioc(m[l]) for l in MSG_LABELS]
    avg_full = sum(full_iocs) / len(full_iocs)
    kv('avg IoC (even skip)', f'{avg_even:.6f}')
    kv('avg IoC (odd skip)', f'{avg_odd:.6f}')
    kv('avg IoC (full)', f'{avg_full:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  SKIP-GRAMS: even={avg_even:.4f}, odd={avg_odd:.4f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_even': avg_even, 'avg_odd': avg_odd}


def section_371_value_pair_distance(m: dict[str, list[int]]) -> dict:
    """§371: Value pair distance distribution."""
    banner(371, 'VALUE PAIR DISTANCE')
    # For a sample of value pairs, distribution of distances
    sample_pairs = [(5, 66), (0, 82), (13, 60)]
    for va, vb in sample_pairs:
        gaps = []
        for label in MSG_LABELS:
            pos_a = [i for i, v in enumerate(m[label]) if v == va]
            pos_b = [i for i, v in enumerate(m[label]) if v == vb]
            for pa in pos_a:
                for pb in pos_b:
                    gaps.append(abs(pa - pb))
        if gaps:
            avg_gap = sum(gaps) / len(gaps)
            kv(f'({va},{vb}) avg dist', f'{avg_gap:.1f} (n={len(gaps)})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  VALUE PAIR DISTANCE: no anomalous clustering.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_372_anomalous_concentration(m: dict[str, list[int]]) -> dict:
    """§372: Anomalous value concentration in specific regions."""
    banner(372, 'ANOMALOUS VALUE CONCENTRATION')
    # Split each message into halves, compare frequency profiles
    half_diffs = []
    for label in MSG_LABELS:
        vals = m[label]
        mid = len(vals) // 2
        freq_1 = Counter(vals[:mid])
        freq_2 = Counter(vals[mid:])
        n1, n2 = mid, len(vals) - mid
        chi2 = 0.0
        for v in range(MOD):
            o1 = freq_1.get(v, 0)
            o2 = freq_2.get(v, 0)
            total = o1 + o2
            if total == 0:
                continue
            e1 = total * n1 / (n1 + n2)
            e2 = total * n2 / (n1 + n2)
            if e1 > 0:
                chi2 += (o1 - e1) ** 2 / e1
            if e2 > 0:
                chi2 += (o2 - e2) ** 2 / e2
        half_diffs.append(chi2)
        kv(f'{label} half-split χ²', f'{chi2:.1f}')
    avg_chi2 = sum(half_diffs) / len(half_diffs)
    kv('avg half-split χ²', f'{avg_chi2:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CONCENTRATION: avg half-split χ²={avg_chi2:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_chi2': avg_chi2}


def section_373_repeating_motifs(m: dict[str, list[int]]) -> dict:
    """§373: Repeating motif search at regular intervals."""
    banner(373, 'REPEATING MOTIFS')
    motif_hits = Counter()
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        for period in [13, 26, 39, 52]:
            for start in range(min(period, n)):
                subseq = [vals[i] for i in range(start, n, period)]
                if len(subseq) >= 3:
                    sub_ioc = ioc(subseq)
                    if sub_ioc > 0.03:  # 2.5× random
                        motif_hits[period] += 1
    for period in [13, 26, 39, 52]:
        kv(f'period {period} high-IoC subsequences', motif_hits.get(period, 0))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  REPEATING MOTIFS: period analysis complete.')
    print('  ══════════════════════════════════════════════════════════')
    return {'motif_hits': dict(motif_hits)}


# ── Null model comparisons ──

def section_374_shuffle_null_wpp_ioc(m: dict[str, list[int]]) -> dict:
    """§374: Shuffle null for within-pair IoC."""
    banner(374, 'SHUFFLE NULL FOR WPP IoC')
    import random as _rng
    rng = _rng.Random(42)
    with open(EYES_JSON) as fh:
        raw_data = json.load(fh)
    raw_delim = str(raw_data['delimiter'])
    # Real wpp=1 IoC
    real_vals = []
    for key, label in zip(MSG_ORDER, MSG_LABELS):
        rows = [r for r in raw_data['messages'][key].split(raw_delim) if r]
        for ri in range(0, len(rows), 2):
            tris = weave_lines_to_trigrams(rows[ri], rows[ri + 1])
            if len(tris) > 1:
                real_vals.append(int(tris[1], 5))
    real_ioc = ioc(real_vals)
    # Shuffle null: shuffle values within each message, recompute
    null_iocs = []
    for trial in range(200):
        null_vals = []
        for label in MSG_LABELS:
            shuffled = list(m[label])
            rng.shuffle(shuffled)
            pos = 0
            for key, lab in zip(MSG_ORDER, MSG_LABELS):
                if lab != label:
                    continue
                rows = [r for r in raw_data['messages'][key].split(raw_delim) if r]
                for ri in range(0, len(rows), 2):
                    tris = weave_lines_to_trigrams(rows[ri], rows[ri + 1])
                    if len(tris) > 1 and pos + 1 < len(shuffled):
                        null_vals.append(shuffled[pos + 1])
                    pos += len(tris)
        if null_vals:
            null_iocs.append(ioc(null_vals))
    avg_null = sum(null_iocs) / len(null_iocs) if null_iocs else 0
    kv('real wpp=1 IoC', f'{real_ioc:.6f}')
    kv('avg null wpp=1 IoC', f'{avg_null:.6f}')
    kv('real > null', real_ioc > avg_null)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  NULL: real={real_ioc:.4f} vs null={avg_null:.4f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'real_ioc': real_ioc, 'avg_null': avg_null}


