def section_377_block_boundary_null(m: dict[str, list[int]]) -> dict:
    """§377: Block boundary null — alignment with pair boundaries under random."""
    banner(377, 'BLOCK BOUNDARY NULL')
    import random as _rng
    rng = _rng.Random(42)
    boundaries = {26, 52, 78, 104, 130}
    canonical_blocks = _canonical_block_partition(m)
    # Real alignment
    real_align = 0
    total_blocks = 0
    for label in MSG_LABELS:
        for s, e in canonical_blocks[label]:
            total_blocks += 1
            if s in boundaries or (e + 1) in boundaries:
                real_align += 1
    # Random null: random block starts
    null_aligns = []
    for trial in range(500):
        count = 0
        for label in MSG_LABELS:
            n = len(m[label])
            n_blocks = len(canonical_blocks[label])
            starts = sorted(rng.sample(range(n), min(n_blocks, n)))
            for s in starts:
                if s in boundaries:
                    count += 1
        null_aligns.append(count)
    avg_null = sum(null_aligns) / len(null_aligns)
    kv('real boundary alignments', f'{real_align}/{total_blocks}')
    kv('avg null alignments', f'{avg_null:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  BOUNDARY NULL: real={real_align} vs null={avg_null:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'real_align': real_align, 'avg_null': avg_null}


