def section_379_adjacent_distinct_null(m: dict[str, list[int]]) -> dict:
    """§379: Adjacent-distinct null."""
    banner(379, 'ADJACENT-DISTINCT NULL')
    import random as _rng
    rng = _rng.Random(42)
    n_trials = 1000
    avg_len = sum(len(m[l]) for l in MSG_LABELS) / 9
    zero_adj_dup = 0
    for _ in range(n_trials):
        seq = [rng.randint(0, MOD - 1) for _ in range(int(avg_len))]
        has_dup = any(seq[i] == seq[i+1] for i in range(len(seq) - 1))
        if not has_dup:
            zero_adj_dup += 1
    kv('trials with 0 adjacent dups', f'{zero_adj_dup}/{n_trials}')
    # P(no adjacent dup) = ((82/83)^(n-1)) ≈ exp(-n/83)
    from math import exp as _exp
    p = _exp(-(avg_len - 1) / MOD)
    kv('theoretical P(0 adj dups)', f'{p:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  ADJACENT-DISTINCT: P ≈ {p:.4f}, but ALL messages have 0')
    print('  ══════════════════════════════════════════════════════════')
    return {'zero_adj_dup': zero_adj_dup, 'p_theory': p}


