def section_390_mirror_symmetry(m: dict[str, list[int]]) -> dict:
    """§390: Mirror symmetry — ct[n-1-i] related to ct[i]?"""
    banner(390, 'MIRROR SYMMETRY')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        # Check constant sum: ct[i] + ct[n-1-i] = c?
        sums = [(vals[i] + vals[n-1-i]) % MOD for i in range(n//2)]
        # Check constant diff: ct[i] - ct[n-1-i] = c?
        diffs = [(vals[i] - vals[n-1-i]) % MOD for i in range(n//2)]
        sum_ioc = ioc(sums)
        diff_ioc = ioc(diffs)
        kv(f'{label} mirror sum IoC', f'{sum_ioc:.6f}')
        kv(f'{label} mirror diff IoC', f'{diff_ioc:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  MIRROR SYMMETRY: no constant relationship found.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_391_rotation_symmetry(m: dict[str, list[int]]) -> dict:
    """§391: Rotation symmetry — shift by k produces related sequence?"""
    banner(391, 'ROTATION SYMMETRY')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        best_k = 0
        best_match = 0
        for k in range(1, min(n, 50)):
            matches = sum(1 for i in range(n - k) if vals[i] == vals[i + k])
            if matches > best_match:
                best_match = matches
                best_k = k
        expected = (n - best_k) / MOD
        kv(f'{label} best shift', f'k={best_k}, matches={best_match} (expected ~{expected:.1f})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  ROTATION: no shift produces significant self-similarity.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_392_value_pair_order(m: dict[str, list[int]]) -> dict:
    """§392: Value pair symmetry — P(a before b) = P(b before a)?"""
    banner(392, 'VALUE PAIR ORDER SYMMETRY')
    # For top 10 most frequent values, check pairwise ordering
    all_vals = [v for l in MSG_LABELS for v in m[l]]
    freq = Counter(all_vals)
    top10 = [v for v, _ in freq.most_common(10)]
    asymmetries = []
    for va, vb in combinations(top10, 2):
        a_before_b = 0
        b_before_a = 0
        for label in MSG_LABELS:
            last_a = last_b = -1
            for i, v in enumerate(m[label]):
                if v == va:
                    if last_b >= 0:
                        b_before_a += 1
                    last_a = i
                elif v == vb:
                    if last_a >= 0:
                        a_before_b += 1
                    last_b = i
        total = a_before_b + b_before_a
        if total > 0:
            asym = abs(a_before_b - b_before_a) / total
            asymmetries.append(asym)
    avg_asym = sum(asymmetries) / len(asymmetries) if asymmetries else 0
    kv('avg pairwise order asymmetry', f'{avg_asym:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  PAIR ORDER: avg asymmetry = {avg_asym:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_asym': avg_asym}


def section_393_fixed_points(m: dict[str, list[int]]) -> dict:
    """§393: Fixed point analysis — ct[i] = i (mod 83)."""
    banner(393, 'FIXED POINT ANALYSIS')
    fixed_points = Counter()
    for label in MSG_LABELS:
        vals = m[label]
        for i, v in enumerate(vals):
            if v == i % MOD:
                fixed_points[label] += 1
    total_fp = sum(fixed_points.values())
    total_pos = sum(len(m[l]) for l in MSG_LABELS)
    expected = total_pos / MOD
    kv('total fixed points', total_fp)
    kv('expected (random)', f'{expected:.1f}')
    for label in MSG_LABELS:
        kv(f'{label}', fixed_points.get(label, 0))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  FIXED POINTS: {total_fp} (expected ~{expected:.0f})')
    print('  ══════════════════════════════════════════════════════════')
    return {'total_fp': total_fp, 'expected': expected}


