def section_394_frequency_rank_correlation(m: dict[str, list[int]]) -> dict:
    """§394: Spearman rank correlation of frequency rankings between messages."""
    banner(394, 'FREQUENCY RANK CORRELATION')
    ranks = {}
    for label in MSG_LABELS:
        freq = Counter(m[label])
        sorted_vals = sorted(range(MOD), key=lambda v: -freq.get(v, 0))
        ranks[label] = {v: r for r, v in enumerate(sorted_vals)}
    correlations = []
    for la, lb in [('E1','W1'), ('E1','E4'), ('E1','E3')]:
        d2_sum = sum((ranks[la][v] - ranks[lb][v]) ** 2 for v in range(MOD))
        n = MOD
        rho = 1 - 6 * d2_sum / (n * (n*n - 1))
        correlations.append((la, lb, rho))
        kv(f'ρ({la},{lb})', f'{rho:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  RANK CORRELATION: frequency ranks compared.')
    print('  ══════════════════════════════════════════════════════════')
    return {'correlations': [(a,b,r) for a,b,r in correlations]}


def section_395_value_neighborhood(m: dict[str, list[int]]) -> dict:
    """§395: Value neighborhood — what values appear near value v?"""
    banner(395, 'VALUE NEIGHBORHOOD')
    target_vals = [5, 66, 0]  # universal constants + zero
    for tv in target_vals:
        neighbors = Counter()
        for label in MSG_LABELS:
            vals = m[label]
            for i, v in enumerate(vals):
                if v == tv:
                    for d in [-2, -1, 1, 2]:
                        j = i + d
                        if 0 <= j < len(vals):
                            neighbors[vals[j]] += 1
        if neighbors:
            top3 = neighbors.most_common(3)
            kv(f'v={tv} neighbors', top3)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  NEIGHBORHOODS: no anomalous neighbor patterns.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_396_inter_arrival_time(m: dict[str, list[int]]) -> dict:
    """§396: Inter-arrival time distribution."""
    banner(396, 'INTER-ARRIVAL TIME')
    all_gaps = defaultdict(list)
    for label in MSG_LABELS:
        last_seen = {}
        for i, v in enumerate(m[label]):
            if v in last_seen:
                all_gaps[v].append(i - last_seen[v])
            last_seen[v] = i
    # Aggregate statistics
    flat_gaps = [g for gaps in all_gaps.values() for g in gaps]
    avg_gap = sum(flat_gaps) / len(flat_gaps) if flat_gaps else 0
    # Per-value: values with most consistent inter-arrival
    cv_per_val = {}
    for v, gaps in all_gaps.items():
        if len(gaps) >= 3:
            avg = sum(gaps) / len(gaps)
            std = (sum((g - avg)**2 for g in gaps) / len(gaps)) ** 0.5
            cv_per_val[v] = std / avg if avg > 0 else 0
    if cv_per_val:
        most_regular = min(cv_per_val, key=cv_per_val.get)
        kv('most regular value', f'{most_regular} (CV={cv_per_val[most_regular]:.3f})')
    kv('avg inter-arrival', f'{avg_gap:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  INTER-ARRIVAL: avg={avg_gap:.0f} ≈ {MOD}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_gap': avg_gap}


def section_397_twin_values(m: dict[str, list[int]]) -> dict:
    """§397: Twin value detection — values always near each other."""
    banner(397, 'TWIN VALUES')
    # For each pair of frequent values, min distance when both appear
    all_vals = [v for l in MSG_LABELS for v in m[l]]
    freq = Counter(all_vals)
    top20 = [v for v, _ in freq.most_common(20)]
    min_dists = {}
    for va, vb in combinations(top20, 2):
        dists = []
        for label in MSG_LABELS:
            pos_a = [i for i, v in enumerate(m[label]) if v == va]
            pos_b = [i for i, v in enumerate(m[label]) if v == vb]
            if pos_a and pos_b:
                for pa in pos_a:
                    dists.append(min(abs(pa - pb) for pb in pos_b))
        if dists:
            min_dists[(va,vb)] = min(dists)
    # Values that are always within distance 3
    twins = [(k, v) for k, v in min_dists.items() if v <= 2]
    kv('value pairs always within 2', len(twins))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  TWINS: {len(twins)} pairs always within distance 2.')
    print('  ══════════════════════════════════════════════════════════')
    return {'n_twins': len(twins)}


def section_398_length_vs_flatness(m: dict[str, list[int]]) -> dict:
    """§398: Message length vs frequency flatness."""
    banner(398, 'LENGTH VS FREQUENCY FLATNESS')
    print()
    print(f'  {"msg":>4s} {"len":>5s} {"IoC":>10s} {"unique":>7s}')
    for label in MSG_LABELS:
        vals = m[label]
        ic = ioc(vals)
        u = len(set(vals))
        print(f'  {label:>4s} {len(vals):5d} {ic:10.6f} {u:7d}')
    # Correlation between length and IoC
    lengths = [len(m[l]) for l in MSG_LABELS]
    iocs = [ioc(m[l]) for l in MSG_LABELS]
    n = len(lengths)
    mx = sum(lengths) / n
    my = sum(iocs) / n
    cov = sum((lengths[i]-mx)*(iocs[i]-my) for i in range(n)) / n
    vx = sum((l-mx)**2 for l in lengths) / n
    vy = sum((i-my)**2 for i in iocs) / n
    r = cov / (vx*vy)**0.5 if vx > 0 and vy > 0 else 0
    kv('length-IoC correlation', f'{r:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  LENGTH-IoC: r = {r:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'r': r}


