def section_410_sliding_bigram_ioc(m: dict[str, list[int]]) -> dict:
    """§410: Sliding-window bigram IoC with window size 30."""
    banner(410, 'SLIDING BIGRAM IoC')
    window = 30
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        max_bic = 0
        max_pos = 0
        for start in range(n - window):
            w = vals[start:start + window]
            bigrams = [(w[i], w[i+1]) for i in range(len(w)-1)]
            freq = Counter(bigrams)
            bic = sum(c*(c-1) for c in freq.values()) / (len(bigrams)*(len(bigrams)-1)) if len(bigrams) > 1 else 0
            if bic > max_bic:
                max_bic = bic
                max_pos = start
        kv(f'{label} max window bigram IoC', f'{max_bic:.6f} at pos {max_pos}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  SLIDING BIGRAM IoC: windowed analysis complete.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


