def section_414_lz_complexity(m: dict[str, list[int]]) -> dict:
    """§414: Lempel-Ziv complexity estimate."""
    banner(414, 'LZ COMPLEXITY')
    def _lz_complexity(seq):
        n = len(seq)
        i = 0
        c = 1
        l = 1
        while i + l <= n:
            sub = tuple(seq[i:i+l])
            if sub in set(tuple(seq[j:j+l]) for j in range(i)):
                l += 1
            else:
                c += 1
                i += l
                l = 1
        return c
    # Simplified: count distinct new substrings
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        seen = set()
        c = 0
        i = 0
        while i < n:
            l = 1
            while i + l <= n and tuple(vals[i:i+l]) in seen:
                l += 1
            seen.add(tuple(vals[i:i+l]))
            c += 1
            i += l
        kv(f'{label} LZ phrases', f'{c} (n={n})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  LZ COMPLEXITY: phrase counts computed.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_415_transition_graph_properties(m: dict[str, list[int]]) -> dict:
    """§415: Transition graph properties — in/out degree distribution."""
    banner(415, 'TRANSITION GRAPH')
    out_deg = defaultdict(set)
    in_deg = defaultdict(set)
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            out_deg[vals[i]].add(vals[i+1])
            in_deg[vals[i+1]].add(vals[i])
    out_degrees = [len(out_deg.get(v, set())) for v in range(MOD)]
    in_degrees = [len(in_deg.get(v, set())) for v in range(MOD)]
    avg_out = sum(out_degrees) / MOD
    avg_in = sum(in_degrees) / MOD
    max_out = max(out_degrees)
    max_in = max(in_degrees)
    kv('avg out-degree', f'{avg_out:.1f}')
    kv('avg in-degree', f'{avg_in:.1f}')
    kv('max out-degree', max_out)
    kv('max in-degree', max_in)
    # Self-loops should be 0 (adjacent distinct)
    self_loops = sum(1 for v in range(MOD) if v in out_deg.get(v, set()))
    kv('self-loops', self_loops)
    assert self_loops == 0, 'adjacent-distinct means no self-loops'
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  GRAPH: avg degree={avg_out:.1f}, 0 self-loops.')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_out': avg_out, 'self_loops': self_loops}


def section_416_strongly_connected(m: dict[str, list[int]]) -> dict:
    """§416: Is the transition graph strongly connected?"""
    banner(416, 'STRONG CONNECTIVITY')
    edges = defaultdict(set)
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            edges[vals[i]].add(vals[i+1])
    # BFS from node 0
    visited = set()
    queue = [0]
    visited.add(0)
    while queue:
        v = queue.pop(0)
        for u in edges.get(v, set()):
            if u not in visited:
                visited.add(u)
                queue.append(u)
    forward_reach = len(visited)
    # Reverse BFS
    rev_edges = defaultdict(set)
    for v, neighbors in edges.items():
        for u in neighbors:
            rev_edges[u].add(v)
    visited_rev = set()
    queue = [0]
    visited_rev.add(0)
    while queue:
        v = queue.pop(0)
        for u in rev_edges.get(v, set()):
            if u not in visited_rev:
                visited_rev.add(u)
                queue.append(u)
    backward_reach = len(visited_rev)
    is_sc = forward_reach == MOD and backward_reach == MOD
    kv('forward reachable from 0', forward_reach)
    kv('backward reachable from 0', backward_reach)
    kv('strongly connected', is_sc)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CONNECTIVITY: {"strongly connected" if is_sc else "NOT strongly connected"}')
    print('  ══════════════════════════════════════════════════════════')
    return {'is_sc': is_sc}


def section_417_graph_diameter_estimate(m: dict[str, list[int]]) -> dict:
    """§417: Transition graph diameter estimate via BFS."""
    banner(417, 'GRAPH DIAMETER')
    edges = defaultdict(set)
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            edges[vals[i]].add(vals[i+1])
    # BFS from a sample of nodes
    max_dist = 0
    for start in [0, 20, 40, 60, 82]:
        dist = {start: 0}
        queue = [start]
        while queue:
            v = queue.pop(0)
            for u in edges.get(v, set()):
                if u not in dist:
                    dist[u] = dist[v] + 1
                    queue.append(u)
        if dist:
            d = max(dist.values())
            if d > max_dist:
                max_dist = d
    kv('estimated diameter', max_dist)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  DIAMETER: ≤ {max_dist}')
    print('  ══════════════════════════════════════════════════════════')
    return {'diameter': max_dist}


def section_418_graph_clustering(m: dict[str, list[int]]) -> dict:
    """§418: Transition graph clustering coefficient."""
    banner(418, 'GRAPH CLUSTERING')
    neighbors = defaultdict(set)
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            neighbors[vals[i]].add(vals[i+1])
            neighbors[vals[i+1]].add(vals[i])
    # Clustering coefficient for a sample
    ccs = []
    for v in range(MOD):
        nbrs = neighbors.get(v, set())
        k = len(nbrs)
        if k < 2:
            continue
        links = 0
        nbr_list = list(nbrs)
        for i in range(len(nbr_list)):
            for j in range(i+1, len(nbr_list)):
                if nbr_list[j] in neighbors.get(nbr_list[i], set()):
                    links += 1
        cc = 2 * links / (k * (k-1))
        ccs.append(cc)
    avg_cc = sum(ccs) / len(ccs) if ccs else 0
    kv('avg clustering coefficient', f'{avg_cc:.4f}')
    kv('nodes measured', len(ccs))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CLUSTERING: avg CC = {avg_cc:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_cc': avg_cc}


def section_419_value_at_family_split(m: dict[str, list[int]]) -> dict:
    """§419: Value patterns at the family split point."""
    banner(419, 'VALUES AT FAMILY SPLIT')
    # Find where Family A (E1,W1,E2) diverges
    min_len_a = min(len(m[l]) for l in ['E1','W1','E2'])
