def section_434_row_pair_transition(m: dict[str, list[int]]) -> dict:
    """§434: Value transition at row pair boundaries (pos 25→26, 51→52, etc.)."""
    banner(434, 'ROW PAIR TRANSITION')
    boundaries = [25, 51, 77]  # last position of pairs 0,1,2
    for b in boundaries:
        diffs = []
        for label in MSG_LABELS:
            if b + 1 < len(m[label]):
                d = (m[label][b+1] - m[label][b]) % MOD
                diffs.append(d)
        if diffs:
            diff_ioc = ioc(diffs)
            kv(f'boundary {b}→{b+1} diff IoC', f'{diff_ioc:.6f}')
            # Are the cross-boundary diffs shared across messages?
            unique_diffs = len(set(diffs))
            kv(f'boundary {b}→{b+1} unique diffs', unique_diffs)
    print()
