def section_435_position_entropy_profile(m: dict[str, list[int]]) -> dict:
    """§435: Per-position entropy across messages."""
    banner(435, 'POSITION ENTROPY PROFILE')
    from math import log2 as _log2
    min_len = min(len(m[l]) for l in MSG_LABELS)
    entropies = []
    for j in range(min_len):
        vals = [m[l][j] for l in MSG_LABELS]
        freq = Counter(vals)
        n = len(vals)
        h = -sum((c/n)*_log2(c/n) for c in freq.values() if c > 0)
        entropies.append(h)
    # Positions with low entropy (high agreement)
    low_h = [(j, entropies[j]) for j in range(min_len) if entropies[j] < 1.0]
    kv('positions with H < 1.0 bit', len(low_h))
    for j, h in low_h[:5]:
        vals = [m[l][j] for l in MSG_LABELS]
        kv(f'  pos {j} H={h:.2f}', Counter(vals).most_common(2))
    high_h = [(j, entropies[j]) for j in range(min_len) if entropies[j] > 3.0]
    kv('positions with H > 3.0 bits', len(high_h))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  ENTROPY: {len(low_h)} low-entropy, {len(high_h)} high-entropy positions.')
    print('  ══════════════════════════════════════════════════════════')
    return {'n_low': len(low_h), 'n_high': len(high_h)}


def section_436_position_mean_profile(m: dict[str, list[int]]) -> dict:
    """§436: Per-position mean value across messages."""
    banner(436, 'POSITION MEAN PROFILE')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    means = []
    for j in range(min_len):
        vals = [m[l][j] for l in MSG_LABELS]
        means.append(sum(vals) / len(vals))
    overall_mean = sum(means) / len(means)
    kv('overall position-mean avg', f'{overall_mean:.2f} (expected 41)')
    # Positions deviating >15 from 41
    deviant = [(j, means[j]) for j in range(min_len) if abs(means[j] - 41) > 15]
    kv('positions with |mean-41| > 15', len(deviant))
    for j, m_j in deviant[:5]:
        kv(f'  pos {j}', f'mean={m_j:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  POSITION MEAN: avg={overall_mean:.1f}, {len(deviant)} deviant.')
    print('  ══════════════════════════════════════════════════════════')
    return {'overall_mean': overall_mean, 'n_deviant': len(deviant)}


def section_437_value_position_correlation(m: dict[str, list[int]]) -> dict:
    """§437: Correlation between value and position within each message."""
    banner(437, 'VALUE-POSITION CORRELATION')
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        positions = list(range(n))
        mx = sum(positions) / n
        my = sum(vals) / n
        cov = sum((positions[i]-mx)*(vals[i]-my) for i in range(n)) / n
        vx = sum((p-mx)**2 for p in positions) / n
        vy = sum((v-my)**2 for v in vals) / n
        r = cov / (vx*vy)**0.5 if vx > 0 and vy > 0 else 0
        kv(f'{label} r(position, value)', f'{r:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  VALUE-POSITION: no linear trend.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


