def section_439_position_conditional_value(m: dict[str, list[int]]) -> dict:
    """§439: P(value | position mod 13) distribution."""
    banner(439, 'P(VALUE | POS MOD 13)')
    # For each position mod 13, compute value distribution
    bins = defaultdict(list)
    for label in MSG_LABELS:
        for i, v in enumerate(m[label]):
            bins[i % 13].append(v)
    chi2_vals = []
    for b in range(13):
        vals = bins[b]
        n = len(vals)
        freq = Counter(vals)
        expected = n / MOD
        chi2 = sum((freq.get(v,0) - expected)**2 / expected for v in range(MOD))
        chi2_vals.append(chi2)
        kv(f'pos%13={b} χ²', f'{chi2:.1f} (n={n})')
    avg_chi2 = sum(chi2_vals) / len(chi2_vals)
    kv('avg χ²', f'{avg_chi2:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  POS MOD 13: avg χ²={avg_chi2:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_chi2': avg_chi2}


