def section_444_zlib_compressibility(m: dict[str, list[int]]) -> dict:
    """§444: Zlib compressibility of value sequences."""
    banner(444, 'ZLIB COMPRESSIBILITY')
    import zlib
    for label in MSG_LABELS[:3]:
        vals = m[label]
        raw = bytes(vals)
        compressed = zlib.compress(raw, 9)
        ratio = len(compressed) / len(raw)
        kv(f'{label} compression ratio', f'{ratio:.3f} ({len(raw)}→{len(compressed)})')
    # Combined
    all_raw = bytes(v for l in MSG_LABELS for v in m[l])
    all_comp = zlib.compress(all_raw, 9)
    combined_ratio = len(all_comp) / len(all_raw)
    kv('combined ratio', f'{combined_ratio:.3f}')
