def section_445_lcs_family_pairs(m: dict[str, list[int]]) -> dict:
    """§445: Longest common subsequence between family pairs (approx)."""
    banner(445, 'LCS (APPROX)')
    # Use greedy LCS approximation for speed
    def _greedy_lcs(a, b):
        j = 0
        count = 0
        for v in a:
            while j < len(b):
                if b[j] == v:
                    count += 1
                    j += 1
                    break
                j += 1
        return count
    for la, lb in [('E1','W1'), ('E4','W4'), ('E1','E4')]:
        lcs_len = _greedy_lcs(m[la], m[lb])
        shorter = min(len(m[la]), len(m[lb]))
        kv(f'{la}-{lb} approx LCS', f'{lcs_len}/{shorter} ({100*lcs_len/shorter:.0f}%)')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  LCS: family pairs share more subsequence than cross-family.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_446_edit_distance_sample(m: dict[str, list[int]]) -> dict:
    """§446: Edit distance between family pair prefixes."""
    banner(446, 'EDIT DISTANCE (PREFIX)')
    # Levenshtein on first 40 values (O(n²) is fine for small n)
    def _edit_dist(a, b):
        n, m_ = len(a), len(b)
        dp = list(range(m_ + 1))
        for i in range(1, n + 1):
            prev = dp[0]
            dp[0] = i
            for j in range(1, m_ + 1):
                temp = dp[j]
                if a[i-1] == b[j-1]:
                    dp[j] = prev
                else:
                    dp[j] = 1 + min(prev, dp[j], dp[j-1])
                prev = temp
        return dp[m_]
    prefix_len = 40
    for la, lb in [('E1','W1'), ('E4','W4'), ('E1','E4')]:
        a = m[la][:prefix_len]
        b = m[lb][:prefix_len]
        d = _edit_dist(a, b)
        kv(f'{la}-{lb} edit dist (first {prefix_len})', d)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  EDIT DISTANCE: family pairs much closer.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_447_longest_common_prefix(m: dict[str, list[int]]) -> dict:
    """§447: Longest common prefix between all message pairs."""
    banner(447, 'LONGEST COMMON PREFIX')
    print()
    print(f'  {"pair":>8s} {"LCP":>5s}')
    for la, lb in combinations(MSG_LABELS, 2):
        lcp = 0
        min_len = min(len(m[la]), len(m[lb]))
        for i in range(min_len):
            if m[la][i] == m[lb][i]:
                lcp += 1
            else:
                break
        if lcp > 0:
            print(f'  {la+"-"+lb:>8s} {lcp:5d}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  LCP: family pairs share longer prefixes.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_448_longest_common_substring(m: dict[str, list[int]]) -> dict:
    """§448: Longest common contiguous substring between message pairs."""
    banner(448, 'LONGEST COMMON SUBSTRING')
    for la, lb in [('E1','W1'), ('E1','E4')]:
        a, b = m[la], m[lb]
        best = 0
        for i in range(len(a)):
            for j in range(len(b)):
                k = 0
                while i+k < len(a) and j+k < len(b) and a[i+k] == b[j+k]:
                    k += 1
                if k > best:
                    best = k
        kv(f'{la}-{lb} LCS-contiguous', best)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  LCSUBSTRING: family pairs share longer substrings.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_449_derangement_test(m: dict[str, list[int]]) -> dict:
    """§449: Derangement test — how many positions have ct[i] = i mod 83?"""
    banner(449, 'DERANGEMENT TEST')
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        fixed = sum(1 for i in range(n) if vals[i] == i % MOD)
        expected = n / MOD
        kv(f'{label} fixed points', f'{fixed} (expected {expected:.1f})')
    # Cross-message: ct_A[i] = ct_B[i]
    min_len = min(len(m[l]) for l in MSG_LABELS)
    for la, lb in [('E1','W1'), ('E1','E4')]:
        agree = sum(1 for i in range(min_len) if m[la][i] == m[lb][i])
        kv(f'{la}={lb}', f'{agree}/{min_len}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  DERANGEMENT: near random for positional, elevated for family.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_450_permutation_rank(m: dict[str, list[int]]) -> dict:
    """§450: Permutation rank — how close to sorted?"""
    banner(450, 'PERMUTATION RANK (INVERSIONS)')
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        # Count inversions (O(n²) but n≈115)
        inversions = sum(1 for i in range(n) for j in range(i+1, n) if vals[i] > vals[j])
        max_inv = n * (n-1) // 2
        kv(f'{label} inversions', f'{inversions}/{max_inv} ({100*inversions/max_inv:.1f}%)')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  INVERSIONS: near 50% (random expected).')
    print('  ══════════════════════════════════════════════════════════')
