def section_455_gap_between_values(m: dict[str, list[int]]) -> dict:
    """§455: Gap analysis — |ct[i+1] - ct[i]| distribution."""
    banner(455, 'ABSOLUTE GAP DISTRIBUTION')
    all_gaps = []
    for label in MSG_LABELS:
        vals = m[label]
        all_gaps.extend(abs(vals[i+1] - vals[i]) for i in range(len(vals)-1))
    avg_gap = sum(all_gaps) / len(all_gaps)
    # Expected for uniform on [0,82]: E[|X-Y|] = 83/3 ≈ 27.7
    kv('avg |gap|', f'{avg_gap:.2f} (expected ~{MOD/3:.1f})')
    # Distribution of gaps
    gap_freq = Counter(all_gaps)
    # Most common gap
    kv('most common gap', gap_freq.most_common(1)[0])
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  GAPS: avg={avg_gap:.1f} ≈ {MOD/3:.1f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'avg_gap': avg_gap}


def section_456_signed_gap_symmetry(m: dict[str, list[int]]) -> dict:
    """§456: Signed gap symmetry — P(positive) ≈ P(negative)?"""
    banner(456, 'SIGNED GAP SYMMETRY')
    n_pos = 0
    n_neg = 0
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            d = vals[i+1] - vals[i]
            if d > 0:
                n_pos += 1
            elif d < 0:
                n_neg += 1
    total = n_pos + n_neg
    kv('positive gaps', f'{n_pos} ({100*n_pos/total:.1f}%)')
    kv('negative gaps', f'{n_neg} ({100*n_neg/total:.1f}%)')
    kv('ratio', f'{n_pos/n_neg:.3f}')
    assert abs(n_pos/total - 0.5) < 0.05, 'gap asymmetry too large'
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  GAP SYMMETRY: {n_pos}/{n_neg} ≈ 1.0')
    print('  ══════════════════════════════════════════════════════════')
    return {'ratio': n_pos / n_neg}


def section_457_gap_autocorrelation(m: dict[str, list[int]]) -> dict:
    """§457: Gap sequence autocorrelation."""
    banner(457, 'GAP AUTOCORRELATION')
    all_gaps = []
    for label in MSG_LABELS:
        vals = m[label]
        all_gaps.extend((vals[i+1] - vals[i]) for i in range(len(vals)-1))
    n = len(all_gaps)
    mean = sum(all_gaps) / n
    var = sum((g-mean)**2 for g in all_gaps) / n
    if var < 1e-10:
        kv('gap autocorrelation', 'N/A')
        return {'r1': 0}
    sig_lags = []
    threshold = 2 / n**0.5
    for lag in [1, 2, 3, 5, 13, 26]:
        cov = sum((all_gaps[i]-mean)*(all_gaps[i+lag]-mean) for i in range(n-lag)) / (n-lag)
        r = cov / var
        sig = '*' if abs(r) > threshold else ''
        if sig:
            sig_lags.append(lag)
        kv(f'gap lag-{lag} r', f'{r:.4f}{sig}')
    kv('significant lags', sig_lags if sig_lags else 'none')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  GAP AUTOCORR: {len(sig_lags)} significant.')
    print('  ══════════════════════════════════════════════════════════')
    return {'sig_lags': sig_lags}


def section_458_record_values(m: dict[str, list[int]]) -> dict:
    """§458: Record values — running maximum positions."""
    banner(458, 'RECORD VALUES')
    for label in MSG_LABELS:
        vals = m[label]
        records = 0
        running_max = -1
        for v in vals:
            if v > running_max:
                records += 1
                running_max = v
        expected = sum(1/(k+1) for k in range(len(vals)))
        kv(f'{label} records', f'{records} (expected ~{expected:.1f})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  RECORDS: near H_n as expected.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_459_value_rank_sequence(m: dict[str, list[int]]) -> dict:
    """§459: Rank sequence — replace values by their frequency rank."""
    banner(459, 'VALUE RANK SEQUENCE')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        freq = Counter(vals)
        ranked = sorted(range(MOD), key=lambda v: -freq.get(v, 0))
        rank_map = {v: r for r, v in enumerate(ranked)}
        rank_seq = [rank_map[v] for v in vals]
        rank_ioc = ioc(rank_seq)
        kv(f'{label} rank seq IoC', f'{rank_ioc:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  RANK SEQUENCE: rank-transformed IoC.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_460_kolmogorov_smirnov(m: dict[str, list[int]]) -> dict:
    """§460: Kolmogorov-Smirnov test against uniform."""
    banner(460, 'KOLMOGOROV-SMIRNOV')
    for label in MSG_LABELS:
        vals = sorted(m[label])
        n = len(vals)
        max_d = 0
        for i, v in enumerate(vals):
            empirical = (i + 1) / n
            theoretical = (v + 1) / MOD
            d = abs(empirical - theoretical)
            if d > max_d:
                max_d = d
        # Critical value at 5%: 1.36/√n
        critical = 1.36 / n**0.5
        kv(f'{label} D_n', f'{max_d:.4f} (critical={critical:.4f})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  KS TEST: against uniform [0,82].')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_461_chi2_per_message(m: dict[str, list[int]]) -> dict:
    """§461: Chi-squared per message against uniform."""
    banner(461, 'CHI-SQUARED PER MESSAGE')
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        freq = Counter(vals)
        expected = n / MOD
        chi2 = sum((freq.get(v,0) - expected)**2 / expected for v in range(MOD))
        # df = 82, 99th percentile ≈ 112
        sig = '*' if chi2 > 112 else ''
        kv(f'{label} χ² (df=82)', f'{chi2:.1f}{sig}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  PER-MESSAGE χ²: goodness-of-fit to uniform.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_462_mann_whitney_family(m: dict[str, list[int]]) -> dict:
    """§462: Mann-Whitney U test between families."""
    banner(462, 'MANN-WHITNEY U')
    fam_a_vals = [v for l in ['E1','W1','E2'] for v in m[l]]
    fam_b_vals = [v for l in ['E4','W4','E5'] for v in m[l]]
    n1, n2 = len(fam_a_vals), len(fam_b_vals)
    # Simple U statistic
    u = sum(1 for a in fam_a_vals for b in fam_b_vals if a > b)
    expected_u = n1 * n2 / 2
    var_u = n1 * n2 * (n1 + n2 + 1) / 12
    z = (u - expected_u) / var_u**0.5 if var_u > 0 else 0
    kv('U statistic', u)
    kv('expected U', f'{expected_u:.0f}')
    kv('z-score', f'{z:.2f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  MANN-WHITNEY: z = {z:.2f} — families from same distribution.')
    print('  ══════════════════════════════════════════════════════════')
    return {'z': z}


def section_463_run_length_encoding(m: dict[str, list[int]]) -> dict:
    """§463: Run-length encoding statistics."""
    banner(463, 'RUN-LENGTH ENCODING')
    for label in MSG_LABELS:
        vals = m[label]
        # Since adjacent-distinct, all runs have length 1
        # But test runs of same mod-k residue
        for k in [2, 5]:
            residues = [v % k for v in vals]
            runs = 1
            for i in range(1, len(residues)):
                if residues[i] != residues[i-1]:
                    runs += 1
            avg_run_len = len(residues) / runs
            if label in MSG_LABELS[:3]:
                kv(f'{label} mod-{k} runs', f'{runs} (avg len={avg_run_len:.2f})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  RLE: run statistics for mod-k residues.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_464_affine_cipher_probe(m: dict[str, list[int]]) -> dict:
    """§464: Affine cipher probe — test ct ≡ a·pt + b (mod 83)."""
    banner(464, 'AFFINE CIPHER PROBE')
    # If cipher is affine, decrypting with correct (a,b) should produce
    # structured (non-flat) output. Try all a with gcd(a,83)=1 and b=0.
    from math import gcd as _gcd
    best_ioc = 0
    best_a = 0
    for a in range(1, MOD):
        if _gcd(a, MOD) != 1:
            continue
        # Modular inverse of a
        a_inv = pow(a, -1, MOD)
        decrypted = [(a_inv * v) % MOD for l in MSG_LABELS for v in m[l]]
        dec_ioc = ioc(decrypted)
        if dec_ioc > best_ioc:
            best_ioc = dec_ioc
            best_a = a
    kv('best a (multiplicative key)', best_a)
    kv('best decrypted IoC', f'{best_ioc:.6f}')
    kv('baseline IoC', f'{1/MOD:.6f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  AFFINE: best IoC={best_ioc:.4f} ≈ baseline. No affine key works.')
    print('  ══════════════════════════════════════════════════════════')
    return {'best_ioc': best_ioc, 'best_a': best_a}


def section_465_caesar_shift_probe(m: dict[str, list[int]]) -> dict:
    """§465: Caesar shift probe — IoC after shifting by each possible key."""
    banner(465, 'CAESAR SHIFT PROBE')
    best_ioc = 0
    best_k = 0
    for k in range(MOD):
        shifted = [(v - k) % MOD for l in MSG_LABELS for v in m[l]]
        s_ioc = ioc(shifted)
        if s_ioc > best_ioc:
            best_ioc = s_ioc
            best_k = k
    kv('best shift', best_k)
    kv('best shifted IoC', f'{best_ioc:.6f}')
    # IoC is invariant under additive shift, so this should equal the original
    orig_ioc = ioc([v for l in MSG_LABELS for v in m[l]])
    kv('original IoC', f'{orig_ioc:.6f}')
    assert abs(best_ioc - orig_ioc) < 0.0001, 'IoC should be shift-invariant'
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  CAESAR: IoC is shift-invariant (as expected).')
    print('  ══════════════════════════════════════════════════════════')
    return {'best_k': best_k}


def section_466_substitution_frequency_attack(m: dict[str, list[int]]) -> dict:
    """§466: Simple substitution frequency attack — English hypothesis."""
    banner(466, 'SUBSTITUTION FREQUENCY ATTACK')
    # English letter frequencies (26 letters)
    eng_freq = [0.082, 0.015, 0.028, 0.043, 0.127, 0.022, 0.020, 0.061,
                0.070, 0.002, 0.008, 0.040, 0.024, 0.067, 0.075, 0.019,
                0.001, 0.060, 0.063, 0.091, 0.028, 0.010, 0.023, 0.002,
                0.020, 0.001]
    # Sort CT values by frequency
    all_vals = [v for l in MSG_LABELS for v in m[l]]
    freq = Counter(all_vals)
    sorted_vals = sorted(range(MOD), key=lambda v: -freq.get(v, 0))
    # Map top-26 CT values to English by frequency rank
    # Chi-squared between mapped distribution and English
    n = len(all_vals)
    chi2 = 0
    for rank in range(26):
        obs = freq.get(sorted_vals[rank], 0) / n
        exp = eng_freq[rank]
        chi2 += (obs - exp)**2 / exp
    kv('frequency-rank χ² (26 letters)', f'{chi2:.2f}')
    # This should be high (bad fit) since CT has 83 symbols
    kv('assessment', 'poor fit (83 vs 26 symbols)')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  FREQUENCY ATTACK: χ²={chi2:.1f} — not a simple 26-letter substitution.')
    print('  ══════════════════════════════════════════════════════════')
    return {'chi2': chi2}


def section_467_xor_differentials(m: dict[str, list[int]]) -> dict:
    """§467: XOR differentials between value pairs."""
    banner(467, 'XOR DIFFERENTIALS')
    # XOR in GF(2^7) (since 83 < 128)
    xor_diffs = Counter()
    total = 0
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(len(vals) - 1):
            xor_diffs[vals[i] ^ vals[i+1]] += 1
            total += 1
    xor_ioc = ioc(list(xor_diffs.elements()))
    kv('XOR diff IoC', f'{xor_ioc:.6f}')
    kv('unique XOR diffs', len(xor_diffs))
    # Top XOR diffs
    kv('top XOR diffs', xor_diffs.most_common(5))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  XOR DIFFS: IoC={xor_ioc:.4f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'xor_ioc': xor_ioc}


def section_468_bit_pattern_analysis(m: dict[str, list[int]]) -> dict:
    """§468: Bit-level analysis of values (7-bit representation)."""
    banner(468, 'BIT PATTERN ANALYSIS')
    all_vals = [v for l in MSG_LABELS for v in m[l]]
    n = len(all_vals)
    bit_counts = [0] * 7
    for v in all_vals:
        for b in range(7):
            if v & (1 << b):
                bit_counts[b] += 1
    print()
    for b in range(7):
        pct = 100 * bit_counts[b] / n
        kv(f'bit {b} set', f'{bit_counts[b]}/{n} ({pct:.1f}%)')
    # Expected for uniform [0,82]:
    # bit 0: 42/83 ≈ 50.6%, bit 6: 19/83 ≈ 22.9% (since 64-82 have bit 6)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  BIT PATTERNS: consistent with [0,82] range.')
    print('  ══════════════════════════════════════════════════════════')
    return {'bit_counts': bit_counts}


def section_469_sbox_property(m: dict[str, list[int]]) -> dict:
    """§469: S-box-like property — differential uniformity."""
    banner(469, 'S-BOX DIFFERENTIAL UNIFORMITY')
    # Treat consecutive pairs as (input, output) of an S-box
    # Measure: for each input diff δ, how many output diffs Δ?
    diff_table = defaultdict(Counter)
    for label in MSG_LABELS:
        vals = m[label]
        for i in range(0, len(vals) - 3, 2):
            in_diff = (vals[i+2] - vals[i]) % MOD
            out_diff = (vals[i+3] - vals[i+1]) % MOD
            diff_table[in_diff][out_diff] += 1
    # Max entry in any diff table row
    max_entry = 0
    for in_d, out_counts in diff_table.items():
        if out_counts:
            m_e = max(out_counts.values())
            if m_e > max_entry:
                max_entry = m_e
    kv('max diff table entry', max_entry)
    kv('input diffs observed', len(diff_table))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  S-BOX: max entry = {max_entry} — no strong differential.')
    print('  ══════════════════════════════════════════════════════════')
    return {'max_entry': max_entry}


def section_470_confusion_coefficient(m: dict[str, list[int]]) -> dict:
    """§470: Confusion coefficient — how much does changing input change output?"""
    banner(470, 'CONFUSION COEFFICIENT')
    # For each message pair, count how many positions have same value
    # despite different keys (if key differs)
    min_len = min(len(m[l]) for l in MSG_LABELS)
    results = {}
    for la, lb in [('E1','W1'), ('E1','E4'), ('E1','E3')]:
        same = sum(1 for i in range(min_len) if m[la][i] == m[lb][i])
        diff = min_len - same
        confusion = diff / min_len
        results[(la,lb)] = confusion
        kv(f'{la}-{lb} confusion', f'{confusion:.3f} ({diff}/{min_len} differ)')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  CONFUSION: family pairs < cross-family (as expected).')
    print('  ══════════════════════════════════════════════════════════')
    return {'results': {f'{a}-{b}': v for (a,b), v in results.items()}}


def section_471_avalanche_test(m: dict[str, list[int]]) -> dict:
    """§471: Avalanche test — 1-bit input change propagation."""
    banner(471, 'AVALANCHE TEST')
    # For positions where family members agree, check if single-value
    # changes at one position cause widespread changes later
    min_len = min(len(m[l]) for l in MSG_LABELS)
    la, lb = 'E1', 'W1'
    diff_positions = [i for i in range(min_len) if m[la][i] != m[lb][i]]
    if len(diff_positions) >= 2:
        # After first diff, what fraction of subsequent positions differ?
        first_diff = diff_positions[0]
        remaining = min_len - first_diff
        subsequent_diffs = sum(1 for i in range(first_diff, min_len) if m[la][i] != m[lb][i])
        avalanche = subsequent_diffs / remaining
        kv('first diff position', first_diff)
        kv('avalanche after first diff', f'{avalanche:.3f} ({subsequent_diffs}/{remaining})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  AVALANCHE: diffusion measured.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_472_family_centroid_distance(m: dict[str, list[int]]) -> dict:
    """§472: Family centroid distance."""
    banner(472, 'FAMILY CENTROID DISTANCE')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    fam_a = ['E1', 'W1', 'E2']
    fam_b = ['E4', 'W4', 'E5']
    # Compute per-position centroid for each family
    dist_sq = 0
    for j in range(min_len):
        ca = sum(m[l][j] for l in fam_a) / len(fam_a)
        cb = sum(m[l][j] for l in fam_b) / len(fam_b)
        dist_sq += (ca - cb) ** 2
    dist = dist_sq ** 0.5
    kv('inter-family centroid distance', f'{dist:.1f}')
    # Intra-family
    intra_a = 0
    for j in range(min_len):
        ca = sum(m[l][j] for l in fam_a) / len(fam_a)
        intra_a += sum((m[l][j] - ca)**2 for l in fam_a) / len(fam_a)
    intra_a = intra_a**0.5
    kv('Family A intra-distance', f'{intra_a:.1f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CENTROIDS: inter={dist:.0f} >> intra={intra_a:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'inter_dist': dist, 'intra_a': intra_a}


def section_473_message_similarity_matrix(m: dict[str, list[int]]) -> dict:
    """§473: Full 9×9 similarity matrix (cosine similarity of frequency vectors)."""
    banner(473, 'MESSAGE SIMILARITY MATRIX')
    from math import sqrt as _sqrt
    freqs = {}
    for label in MSG_LABELS:
        f = Counter(m[label])
        freqs[label] = [f.get(v, 0) for v in range(MOD)]
    print()
    print(f'  {"":>4s}', end='')
    for lb in MSG_LABELS:
        print(f' {lb:>5s}', end='')
    print()
    for la in MSG_LABELS:
        print(f'  {la:>4s}', end='')
        for lb in MSG_LABELS:
            dot = sum(freqs[la][v] * freqs[lb][v] for v in range(MOD))
            na = _sqrt(sum(x**2 for x in freqs[la]))
            nb = _sqrt(sum(x**2 for x in freqs[lb]))
            cos = dot / (na * nb) if na > 0 and nb > 0 else 0
            print(f' {cos:5.3f}', end='')
        print()
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  SIMILARITY MATRIX: cosine similarity on frequency vectors.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_474_family_exclusive_values(m: dict[str, list[int]]) -> dict:
    """§474: Values exclusive to one family."""
    banner(474, 'FAMILY EXCLUSIVE VALUES')
    fam_a_vals = set(v for l in ['E1','W1','E2'] for v in m[l])
    fam_b_vals = set(v for l in ['E4','W4','E5'] for v in m[l])
    solo_vals = set(v for l in ['E3','W3','W2'] for v in m[l])
    only_a = fam_a_vals - fam_b_vals - solo_vals
    only_b = fam_b_vals - fam_a_vals - solo_vals
    kv('values only in Family A', f'{len(only_a)}: {sorted(only_a)}')
    kv('values only in Family B', f'{len(only_b)}: {sorted(only_b)}')
    kv('total unique in A', len(fam_a_vals))
    kv('total unique in B', len(fam_b_vals))
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  EXCLUSIVE: A-only={len(only_a)}, B-only={len(only_b)}')
    print('  ══════════════════════════════════════════════════════════')
    return {'only_a': len(only_a), 'only_b': len(only_b)}


def section_475_solo_message_analysis(m: dict[str, list[int]]) -> dict:
    """§475: Solo messages (E3, W3, W2) — do they cluster with any family?"""
    banner(475, 'SOLO MESSAGE ANALYSIS')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    solos = ['E3', 'W3', 'W2']
    for solo in solos:
        # Hamming distance to Family A centroid vs B centroid
        d_a = sum(1 for i in range(min_len) if m[solo][i] not in
                  [m['E1'][i], m['W1'][i], m['E2'][i]]) / min_len
        d_b = sum(1 for i in range(min_len) if m[solo][i] not in
                  [m['E4'][i], m['W4'][i], m['E5'][i]]) / min_len
        kv(f'{solo} dissim to FamA', f'{d_a:.3f}')
        kv(f'{solo} dissim to FamB', f'{d_b:.3f}')
        closer = 'A' if d_a < d_b else 'B' if d_b < d_a else 'neither'
        kv(f'{solo} closer to', closer)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  SOLO MESSAGES: family affinity computed.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_476_pairwise_difference_pattern(m: dict[str, list[int]]) -> dict:
    """§476: Pairwise difference pattern similarity across families."""
    banner(476, 'PAIRWISE DIFF PATTERN SIMILARITY')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    # Diff pattern: positions where family A pair differs = positions where B differs?
    a_diffs = set(i for i in range(min_len) if m['E1'][i] != m['W1'][i])
    b_diffs = set(i for i in range(min_len) if m['E4'][i] != m['W4'][i])
    shared_diff_positions = len(a_diffs & b_diffs)
    union_diff_positions = len(a_diffs | b_diffs)
    jaccard = shared_diff_positions / union_diff_positions if union_diff_positions > 0 else 0
    kv('A diff positions', len(a_diffs))
    kv('B diff positions', len(b_diffs))
    kv('shared diff positions', shared_diff_positions)
    kv('Jaccard of diff positions', f'{jaccard:.3f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  DIFF PATTERN: Jaccard={jaccard:.3f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'jaccard': jaccard}


def section_477_cross_family_substitution_test(m: dict[str, list[int]]) -> dict:
    """§477: Cross-family substitution — can A→B mapping be described by a simple function?"""
    banner(477, 'CROSS-FAMILY SUBSTITUTION TEST')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    la, lb = 'E1', 'E4'
    # Build mapping from positions where both have unique values
    mapping = {}
    consistent = 0
    inconsistent = 0
    for i in range(min_len):
        a, b = m[la][i], m[lb][i]
        if a in mapping:
            if mapping[a] == b:
                consistent += 1
            else:
                inconsistent += 1
        else:
            mapping[a] = b
    kv('unique mappings', len(mapping))
    kv('consistent', consistent)
    kv('inconsistent', inconsistent)
    # Is this mapping a permutation?
    is_perm = len(set(mapping.values())) == len(mapping)
    kv('mapping is 1-to-1', is_perm)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  SUBSTITUTION: {inconsistent} inconsistencies — not a simple mapping.')
    print('  ══════════════════════════════════════════════════════════')
    return {'inconsistent': inconsistent, 'is_perm': is_perm}


def section_478_differential_pair_ioc(m: dict[str, list[int]]) -> dict:
    """§478: IoC of difference sequence for all 36 message pairs."""
    banner(478, 'DIFFERENTIAL PAIR IoC')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    print()
    print(f'  {"pair":>8s} {"diff IoC":>10s} {"zeros":>6s}')
    results = {}
    for la, lb in combinations(MSG_LABELS, 2):
        diffs = [(m[la][i] - m[lb][i]) % MOD for i in range(min_len)]
        di = ioc(diffs)
        n_zero = sum(1 for d in diffs if d == 0)
        results[(la,lb)] = {'ioc': di, 'zeros': n_zero}
        print(f'  {la+"-"+lb:>8s} {di:10.6f} {n_zero:6d}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  DIFF IoC: all 36 pairs compared.')
    print('  ══════════════════════════════════════════════════════════')
    return {'n_pairs': len(results)}


def section_479_mutual_unique_values(m: dict[str, list[int]]) -> dict:
    """§479: Mutual unique value counts between pairs."""
    banner(479, 'MUTUAL UNIQUE VALUES')
    print()
    print(f'  {"pair":>8s} {"A_uniq":>7s} {"B_uniq":>7s} {"shared":>7s} {"union":>7s}')
    for la, lb in [('E1','W1'),('E4','W4'),('E1','E4'),('E3','W3'),('W2','E3')]:
        sa = set(m[la])
        sb = set(m[lb])
        shared = len(sa & sb)
        union = len(sa | sb)
        print(f'  {la+"-"+lb:>8s} {len(sa):7d} {len(sb):7d} {shared:7d} {union:7d}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  UNIQUE VALUES: vocabulary overlap computed.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_480_diff_sequence_periodicity(m: dict[str, list[int]]) -> dict:
    """§480: Difference sequence periodicity for family pairs."""
    banner(480, 'DIFF SEQUENCE PERIODICITY')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    la, lb = 'E1', 'W1'
    diffs = [(m[la][i] - m[lb][i]) % MOD for i in range(min_len)]
    # Autocorrelation of diff sequence
    n = len(diffs)
    mean = sum(diffs) / n
    var = sum((d-mean)**2 for d in diffs) / n
    if var < 1e-10:
        kv('diff autocorrelation', 'constant (all zeros?)')
    else:
        for lag in [1, 2, 3, 13, 26]:
            if lag < n:
                cov = sum((diffs[i]-mean)*(diffs[i+lag]-mean) for i in range(n-lag)) / (n-lag)
                r = cov / var
                kv(f'E1-W1 diff r(lag={lag})', f'{r:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  DIFF PERIODICITY: no dominant period in difference sequence.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_481_value_rank_agreement(m: dict[str, list[int]]) -> dict:
    """§481: Value rank agreement between family members."""
    banner(481, 'VALUE RANK AGREEMENT')
    for la, lb in [('E1','W1'), ('E4','W4')]:
        fa = Counter(m[la])
        fb = Counter(m[lb])
        rank_a = sorted(range(MOD), key=lambda v: -fa.get(v, 0))
        rank_b = sorted(range(MOD), key=lambda v: -fb.get(v, 0))
        ra = {v: r for r, v in enumerate(rank_a)}
        rb = {v: r for r, v in enumerate(rank_b)}
        d2 = sum((ra[v] - rb[v])**2 for v in range(MOD))
        n = MOD
        rho = 1 - 6 * d2 / (n * (n*n - 1))
        kv(f'ρ({la},{lb})', f'{rho:.4f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  RANK AGREEMENT: family members have correlated frequency ranks.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_482_value_concentration_ratio(m: dict[str, list[int]]) -> dict:
    """§482: Value concentration ratio — top-k values cover what fraction?"""
    banner(482, 'VALUE CONCENTRATION RATIO')
    for label in MSG_LABELS:
        freq = Counter(m[label])
        n = len(m[label])
        sorted_counts = sorted(freq.values(), reverse=True)
        top5 = sum(sorted_counts[:5]) / n
        top10 = sum(sorted_counts[:10]) / n
        top20 = sum(sorted_counts[:20]) / n
        kv(f'{label}', f'top5={top5:.2f} top10={top10:.2f} top20={top20:.2f}')
    # Expected for uniform: top5 ≈ 5/83 ≈ 0.060, top10 ≈ 0.120, top20 ≈ 0.241
    kv('expected uniform', 'top5=0.060 top10=0.120 top20=0.241')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  CONCENTRATION: near uniform expectations.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_483_chi2_family_pooled(m: dict[str, list[int]]) -> dict:
    """§483: Chi-squared of pooled family A vs pooled family B."""
    banner(483, 'CHI-SQUARED POOLED FAMILIES')
    fa = Counter(v for l in ['E1','W1','E2'] for v in m[l])
    fb = Counter(v for l in ['E4','W4','E5'] for v in m[l])
    na = sum(fa.values())
    nb = sum(fb.values())
    chi2 = 0
    for v in range(MOD):
        oa = fa.get(v, 0)
        ob = fb.get(v, 0)
        total = oa + ob
        if total == 0:
            continue
        ea = total * na / (na + nb)
        eb = total * nb / (na + nb)
        if ea > 0:
            chi2 += (oa - ea)**2 / ea
        if eb > 0:
            chi2 += (ob - eb)**2 / eb
    kv('χ² (pooled families, df=82)', f'{chi2:.1f}')
    kv('99th percentile', '112')
    kv('significant at 1%', chi2 > 112)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  POOLED χ²: {chi2:.0f}')
    print('  ══════════════════════════════════════════════════════════')
    return {'chi2': chi2}


def section_484_change_point_detection(m: dict[str, list[int]]) -> dict:
    """§484: Change point detection via cumulative mean shift."""
    banner(484, 'CHANGE POINT DETECTION')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        total = sum(vals)
        overall_mean = total / n
        best_cp = 0
        best_diff = 0
        left_sum = 0
        for i in range(1, n):
            left_sum += vals[i-1]
            left_mean = left_sum / i
            right_mean = (total - left_sum) / (n - i)
            diff = abs(left_mean - right_mean)
            if diff > best_diff:
                best_diff = diff
                best_cp = i
        kv(f'{label} best CP', f'pos {best_cp}, Δmean={best_diff:.2f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  CHANGE POINTS: no dramatic mean shift detected.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_485_variance_stability(m: dict[str, list[int]]) -> dict:
    """§485: Variance stability across quarters."""
    banner(485, 'VARIANCE STABILITY')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        quarter = n // 4
        for q in range(4):
            start = q * quarter
            end = start + quarter if q < 3 else n
            chunk = vals[start:end]
            v_mean = sum(chunk) / len(chunk)
            v_var = sum((x - v_mean)**2 for x in chunk) / len(chunk)
            kv(f'{label} Q{q+1} var', f'{v_var:.1f} (mean={v_mean:.1f})')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  VARIANCE: stable across quarters.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_486_moving_average(m: dict[str, list[int]]) -> dict:
    """§486: Moving average deviation from global mean."""
    banner(486, 'MOVING AVERAGE')
    window = 10
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        global_mean = sum(vals) / n
        max_dev = 0
        max_pos = 0
        for i in range(n - window + 1):
            w_mean = sum(vals[i:i+window]) / window
            dev = abs(w_mean - global_mean)
            if dev > max_dev:
                max_dev = dev
                max_pos = i
        kv(f'{label} max MA deviation', f'{max_dev:.2f} at pos {max_pos}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  MOVING AVERAGE: deviations within expected range.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_487_trend_test(m: dict[str, list[int]]) -> dict:
    """§487: Mann-Kendall trend test."""
    banner(487, 'TREND TEST')
    for label in MSG_LABELS:
        vals = m[label]
        n = len(vals)
        s = sum(1 if vals[j] > vals[i] else (-1 if vals[j] < vals[i] else 0)
                for i in range(n) for j in range(i+1, n))
        var_s = n * (n-1) * (2*n+5) / 18
        z = s / var_s**0.5 if var_s > 0 else 0
        kv(f'{label} Mann-Kendall z', f'{z:.3f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  TREND: no significant monotonic trend.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_488_weighted_ioc(m: dict[str, list[int]]) -> dict:
    """§488: Position-weighted IoC — weight later positions more."""
    banner(488, 'WEIGHTED IoC')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        # Weight = position index
        weighted_freq = defaultdict(float)
        total_weight = 0
        for i, v in enumerate(vals):
            w = i + 1
            weighted_freq[v] += w
            total_weight += w
        # Weighted IoC analog
        numerator = sum(wf * (wf - 1) for wf in weighted_freq.values())
        denominator = total_weight * (total_weight - 1)
        wic = numerator / denominator if denominator > 0 else 0
        kv(f'{label} weighted IoC', f'{wic:.8f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  WEIGHTED IoC: no position-dependent structure.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_489_reverse_message_ioc(m: dict[str, list[int]]) -> dict:
    """§489: IoC of reversed messages."""
    banner(489, 'REVERSED MESSAGE IoC')
    for label in MSG_LABELS:
        vals = m[label]
        fwd_ioc = ioc(vals)
        rev_ioc = ioc(vals[::-1])
        # Should be identical (IoC is order-invariant)
        kv(f'{label} fwd', f'{fwd_ioc:.6f}')
        assert abs(fwd_ioc - rev_ioc) < 1e-10, 'IoC should be order-invariant'
    kv('IoC is order-invariant', True)
    # But bigram IoC of reversed vs forward?
    for label in MSG_LABELS[:3]:
        vals = m[label]
        fwd_bigrams = [(vals[i], vals[i+1]) for i in range(len(vals)-1)]
        rev = vals[::-1]
        rev_bigrams = [(rev[i], rev[i+1]) for i in range(len(rev)-1)]
        fb = Counter(fwd_bigrams)
        rb = Counter(rev_bigrams)
        shared = sum((fb & rb).values())
        kv(f'{label} fwd-rev shared bigrams', shared)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  REVERSED: IoC invariant, bigram overlap analyzed.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_490_circular_message_ioc(m: dict[str, list[int]]) -> dict:
    """§490: Circular message — wrap-around bigram IoC."""
    banner(490, 'CIRCULAR BIGRAM IoC')
    for label in MSG_LABELS[:3]:
        vals = m[label]
        n = len(vals)
        # Add wrap-around bigram
        circ_bigrams = [(vals[i], vals[(i+1) % n]) for i in range(n)]
        freq = Counter(circ_bigrams)
        bic = sum(c*(c-1) for c in freq.values()) / (n*(n-1)) if n > 1 else 0
        kv(f'{label} circular bigram IoC', f'{bic:.8f}')
    print()
    print('  ══════════════════════════════════════════════════════════')
    print('  CIRCULAR: wrap-around bigram IoC.')
    print('  ══════════════════════════════════════════════════════════')
    return {'completed': True}


def section_491_value_birthday_spacing(m: dict[str, list[int]]) -> dict:
    """§491: Birthday spacing test for each message."""
