def section_501_per_position_mode(m: dict[str, list[int]]) -> dict:
    """§501: Per-position mode value — synthetic "consensus" message."""
    banner(501, 'PER-POSITION MODE (CONSENSUS)')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    consensus = []
    mode_counts = []
    for j in range(min_len):
        vals = [m[l][j] for l in MSG_LABELS]
        freq = Counter(vals)
        mode_val, mode_count = freq.most_common(1)[0]
        consensus.append(mode_val)
        mode_counts.append(mode_count)
    avg_mode_count = sum(mode_counts) / len(mode_counts)
    kv('avg mode count', f'{avg_mode_count:.2f}/9')
    kv('consensus first 10', consensus[:10])
    kv('mode counts first 10', mode_counts[:10])
    # How many positions have mode count = 9 (all agree)?
    n_unanimous = sum(1 for c in mode_counts if c == 9)
    kv('unanimous positions', n_unanimous)
    print()
    print('  ══════════════════════════════════════════════════════════')
    print(f'  CONSENSUS: {n_unanimous} unanimous, avg mode = {avg_mode_count:.1f}/9')
    print('  ══════════════════════════════════════════════════════════')
    return {'n_unanimous': n_unanimous, 'avg_mode_count': avg_mode_count}


def section_502_consensus_vs_individual(m: dict[str, list[int]]) -> dict:
    """§502: How far is each message from the consensus?"""
    banner(502, 'CONSENSUS DISTANCE')
    min_len = min(len(m[l]) for l in MSG_LABELS)
    # Build consensus
    consensus = []
    for j in range(min_len):
        vals = [m[l][j] for l in MSG_LABELS]
        freq = Counter(vals)
        consensus.append(freq.most_common(1)[0][0])
