def section_543_post_soft_gap_profile(
        m: dict[str, list[int]]) -> dict:
    """§543: Re-profile remaining gaps after soft cascade.

    Same methodology as §539 but on the soft-cascade σ-table.
    Shows how the difficulty distribution shifted.
    """
    banner(543, 'POST-SOFT-CASCADE GAP PROFILE')

    rank_dir = Path(__file__).parent / 'rank_01'
    soft_path = rank_dir / 'sigma_soft_cascade.json'
    aug_path = rank_dir / 'sigma_cascade_augmented.json'
    orig_path = rank_dir / 'partial_sigma_injective.json'

    assert orig_path.is_file()
    key_of = _build_key_schedule(m)

    if soft_path.is_file():
        sigma = json.loads(soft_path.read_text())
        kv('using', 'soft-cascade σ-table')
    elif aug_path.is_file():
        sigma = json.loads(aug_path.read_text())
        kv('using', 'cascade-augmented σ-table')
    else:
        sigma = json.loads(orig_path.read_text())
        kv('using', 'original injective σ-table')

    decoded_all = _decode_corpus(m, key_of, sigma)
    bigram_freq = _get_bigram_freq(decoded_all)
    full_alpha, key_used = _get_alpha_and_key_used(sigma)

    gaps: list[dict] = []
    difficulty_counts = {'easy': 0, 'medium': 0, 'hard': 0, 'very_hard': 0}

    for label in MSG_LABELS:
        dec = decoded_all[label]
        for p in range(len(dec)):
            if dec[p] is not None:
                continue
            k = key_of[(label, p)]
            ct = m[label][p]
            used = key_used.get(k, set())
            injective_candidates = full_alpha - used

            left = dec[p - 1] if p > 0 and dec[p - 1] is not None else None
            right = (dec[p + 1] if p < len(dec) - 1
                     and dec[p + 1] is not None else None)

            if left is not None or right is not None:
                bigram_consistent = []
                for c in injective_candidates:
                    score = 0
                    if left is not None:
                        score += bigram_freq.get(left + c, 0)
                    if right is not None:
                        score += bigram_freq.get(c + right, 0)
                    if score > 0:
                        bigram_consistent.append(c)
                n_candidates = len(bigram_consistent)
            else:
                n_candidates = len(injective_candidates)

            if n_candidates <= 3:
                diff = 'easy'
            elif n_candidates <= 10:
                diff = 'medium'
            elif n_candidates <= 20:
                diff = 'hard'
            else:
                diff = 'very_hard'
            difficulty_counts[diff] += 1

            gaps.append({
                'message': label,
                'position': p,
                'key': k,
                'ct': ct,
                'injective_candidates': len(injective_candidates),
                'bigram_candidates': n_candidates,
                'difficulty': diff,
                'has_left': left is not None,
                'has_right': right is not None,
            })

    total_gaps = len(gaps)
    kv('remaining gaps', total_gaps)
    kv('easy (≤3)', f'{difficulty_counts["easy"]} '
       f'({difficulty_counts["easy"]/max(1,total_gaps)*100:.1f}%)')
    kv('medium (4-10)', f'{difficulty_counts["medium"]} '
       f'({difficulty_counts["medium"]/max(1,total_gaps)*100:.1f}%)')
    kv('hard (11-20)', f'{difficulty_counts["hard"]} '
       f'({difficulty_counts["hard"]/max(1,total_gaps)*100:.1f}%)')
    kv('very hard (>20)', f'{difficulty_counts["very_hard"]} '
       f'({difficulty_counts["very_hard"]/max(1,total_gaps)*100:.1f}%)')

    # Context availability
    both_ctx = sum(1 for g in gaps if g['has_left'] and g['has_right'])
    one_ctx = sum(1 for g in gaps
                  if (g['has_left'] or g['has_right'])
                  and not (g['has_left'] and g['has_right']))
    no_ctx = sum(1 for g in gaps
                 if not g['has_left'] and not g['has_right'])

    print()
    kv('gaps with both neighbors', both_ctx)
    kv('gaps with one neighbor', one_ctx)
    kv('isolated gaps (no neighbors)', no_ctx)

    # Per-message remaining gaps
    print()
    print('  -- remaining gaps by message --')
    for label in MSG_LABELS:
        msg_gaps = [g for g in gaps if g['message'] == label]
        print(f'    {label:8s}: {len(msg_gaps):3d} gaps')

    assert total_gaps > 0

    return {
        'total_gaps': total_gaps,
        'difficulty': dict(difficulty_counts),
        'context': {
            'both': both_ctx,
            'one': one_ctx,
            'none': no_ctx,
        },
    }


def section_544_trigram_cascade(
        m: dict[str, list[int]]) -> dict:
    """§544: Trigram cascade — use 3-char context windows.

    For each gap that has at least 2 decoded neighbors (both sides or
    2 on one side), score candidates using trigram scoring:
    - left2+left1+candidate
    - left1+candidate+right1
    - candidate+right1+right2

    Uses the decoded corpus to build a trigram frequency table, then
    resolves gaps where one candidate dominates.
    """
    banner(544, 'TRIGRAM CASCADE')

    rank_dir = Path(__file__).parent / 'rank_01'
    soft_path = rank_dir / 'sigma_soft_cascade.json'
    aug_path = rank_dir / 'sigma_cascade_augmented.json'
    orig_path = rank_dir / 'partial_sigma_injective.json'

    assert orig_path.is_file()
    key_of = _build_key_schedule(m)

    if soft_path.is_file():
        sigma = json.loads(soft_path.read_text())
        kv('starting from', 'soft-cascade σ-table')
    elif aug_path.is_file():
        sigma = json.loads(aug_path.read_text())
        kv('starting from', 'cascade-augmented σ-table')
    else:
        sigma = json.loads(orig_path.read_text())
        kv('starting from', 'original injective σ-table')

    total_resolved = 0
    rounds = 0
    DOMINANCE_RATIO = 2.0

    while True:
        rounds += 1
        decoded_all = _decode_corpus(m, key_of, sigma)

        # Build trigram frequency table from decoded corpus
        trigram_freq: Counter = Counter()
        for label in MSG_LABELS:
            dec = decoded_all[label]
            for i in range(len(dec) - 2):
                if (dec[i] is not None and dec[i+1] is not None
                        and dec[i+2] is not None):
                    trigram_freq[dec[i] + dec[i+1] + dec[i+2]] += 1

        bigram_freq = _get_bigram_freq(decoded_all)
        full_alpha, key_used = _get_alpha_and_key_used(sigma)

        found_this_round: list[dict] = []
        seen_kc: set[tuple[int, int]] = set()

        for label in MSG_LABELS:
            dec = decoded_all[label]
            for p in range(len(dec)):
                if dec[p] is not None:
                    continue
                k = key_of[(label, p)]
                ct = m[label][p]
                pair = (k, ct)
                if pair in seen_kc:
                    continue

                used = key_used.get(k, set())
                candidates = full_alpha - used

                # Gather context
                l2 = dec[p-2] if p >= 2 and dec[p-2] is not None else None
                l1 = dec[p-1] if p >= 1 and dec[p-1] is not None else None
                r1 = (dec[p+1] if p < len(dec)-1
                       and dec[p+1] is not None else None)
                r2 = (dec[p+2] if p < len(dec)-2
                       and dec[p+2] is not None else None)

                # Need at least 2 context chars for trigram scoring
                has_trigram_ctx = ((l2 is not None and l1 is not None) or
                                  (l1 is not None and r1 is not None) or
                                  (r1 is not None and r2 is not None))
                if not has_trigram_ctx:
                    continue

                scored = []
                for c in candidates:
                    score = 0
                    # Trigram scores (weighted higher)
                    if l2 is not None and l1 is not None:
                        score += trigram_freq.get(l2+l1+c, 0) * 3
                    if l1 is not None and r1 is not None:
                        score += trigram_freq.get(l1+c+r1, 0) * 3
                    if r1 is not None and r2 is not None:
                        score += trigram_freq.get(c+r1+r2, 0) * 3
                    # Bigram scores (base)
                    if l1 is not None:
                        score += bigram_freq.get(l1+c, 0)
                    if r1 is not None:
                        score += bigram_freq.get(c+r1, 0)

                    if score > 0:
                        scored.append((c, score))

                if not scored:
                    continue

                scored.sort(key=lambda x: -x[1])

                if len(scored) == 1:
                    found_this_round.append({
                        'key': k, 'ct': ct, 'char': scored[0][0],
                        'score': scored[0][1], 'method': 'trigram_strict',
                    })
                    seen_kc.add(pair)
                elif (len(scored) >= 2
                      and scored[0][1] >= DOMINANCE_RATIO * scored[1][1]):
                    found_this_round.append({
                        'key': k, 'ct': ct, 'char': scored[0][0],
                        'score': scored[0][1], 'method': 'trigram_soft',
                        'ratio': round(scored[0][1] / max(1, scored[1][1]), 1),
                    })
                    seen_kc.add(pair)

        if not found_this_round:
            break

        for r in found_this_round:
            k_str = str(r['key'])
            ct_str = str(r['ct'])
            if k_str not in sigma:
                sigma[k_str] = {}
            sigma[k_str][ct_str] = {
                'char': r['char'],
                'confidence': 0.90 if 'soft' in r['method'] else 0.95,
                'tier': f'trigram_cascade_r{rounds}',
            }

        round_count = len(found_this_round)
        total_resolved += round_count
        strict = sum(1 for r in found_this_round
                     if r['method'] == 'trigram_strict')
        soft = round_count - strict
        kv(f'round {rounds}', f'{round_count} resolved '
           f'(strict={strict}, soft={soft}, cumulative={total_resolved})')

        if rounds > 50:
            break

    kv('total rounds', rounds)
    kv('total gaps resolved', total_resolved)

    # Final decode
    final_decoded = _decode_corpus(m, key_of, sigma)
    total_pos = sum(len(m[l]) for l in MSG_LABELS)
    decoded_count = sum(
        1 for l in MSG_LABELS for c in final_decoded[l] if c is not None)
    kv('final decode rate', f'{decoded_count}/{total_pos} '
       f'({decoded_count/total_pos*100:.1f}%)')

    if total_resolved > 0:
        tri_path = rank_dir / 'sigma_trigram_cascade.json'
        tri_path.write_text(json.dumps(sigma, indent=1))
        kv('trigram-cascade σ-table written to', str(tri_path))

    # Print decode
    print()
    for label in MSG_LABELS:
        dec = final_decoded[label]
        text = ''.join(c if c is not None else '□' for c in dec)
        print(f'  {label:8s}: {text}')

    assert rounds >= 1

    return {
        'total_rounds': rounds,
        'total_resolved': total_resolved,
        'final_decoded': decoded_count,
        'final_total': total_pos,
        'final_decode_rate': round(decoded_count / total_pos * 100, 1),
    }


