        ('§523 Injective σ-table', 'partial_sigma_injective.json'),
        ('§535 Strict cascade', 'sigma_cascade_augmented.json'),
        ('§540 Soft cascade', 'sigma_soft_cascade.json'),
        ('§544 Trigram cascade', 'sigma_trigram_cascade.json'),
