# ──────────────────── HIGH-VALUE HARNESS ADDITIONS (§791–§810) ────────────────

def _load_collapsed_skeleton() -> dict[str, int]:
    """Load the 27-class collapsed skeleton from collapsed_skeleton.json."""
    import json
    p = Path(__file__).parent / 'collapsed_skeleton.json'
    with open(p) as f:
        return json.load(f)

def _flatten_collapsed_skeleton(skel: dict[str, int]) -> dict[str, str]:
    """Map collapsed skeleton (27 classes) to character strings A-Z + _."""
    import string
    alphabet = string.ascii_uppercase + '_'  # 27 chars
    result: dict[str, str] = {}
    # Group by message label
    from collections import defaultdict
    by_msg: dict[str, list[tuple[int, int]]] = defaultdict(list)
    for key, class_id in skel.items():
        label, pos_str = key.split(',')
        by_msg[label].append((int(pos_str), class_id))
    for label in MSG_LABELS:
        positions = sorted(by_msg[label])
        result[label] = ''.join(alphabet[cid] for _, cid in positions)
    return result

def _find_repeated_positions(all_text: str, min_len: int = 15) -> list[bool]:
    """Mark positions that are part of a repeated substring of length >= min_len."""
    n = len(all_text)
    covered = [False] * n
    # Check lengths from min_len up to a reasonable cap
    for length in range(min_len, min(n // 2 + 1, 50)):
        seen: dict[str, list[int]] = {}
        for i in range(n - length + 1):
            s = all_text[i:i + length]
            if s not in seen:
                seen[s] = []
            seen[s].append(i)
        for positions in seen.values():
            if len(positions) >= 2:
                for start in positions:
                    for j in range(start, start + length):
                        covered[j] = True
    return covered


def section_791_isomorph_free_ioc(m: dict[str, list[int]]) -> dict:
    """§791: Compute IoC on ONLY the non-repeated (unique) positions of the
    27-class flattened text. The global IoC (0.038) is dominated by massive
    structural repeats (58.8% of text). This tests whether the actual
    "content" regions show any natural language signal."""
    import math

    banner(791, 'ISOMORPH-FREE IoC (UNIQUE CONTENT ONLY)')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)
    all_text = ''.join(flat[l] for l in MSG_LABELS)

    covered = _find_repeated_positions(all_text)
    total = len(all_text)
    n_covered = sum(covered)
    unique_chars = [all_text[i] for i in range(total) if not covered[i]]
    n_unique = len(unique_chars)

    # Compute IoC on unique positions
    freq = Counter(unique_chars)
    ioc_unique = sum(f * (f - 1) for f in freq.values()) / (n_unique * (n_unique - 1)) if n_unique > 1 else 0.0

    # Compute IoC on full text for comparison
    full_freq = Counter(all_text)
    ioc_full = sum(f * (f - 1) for f in full_freq.values()) / (total * (total - 1))

    # Random expectation for 27 symbols: 1/27 ≈ 0.0370
    ioc_random_27 = 1.0 / 27

    print(f'  Total positions: {total}')
    print(f'  Repeated (isomorph) positions: {n_covered} ({100 * n_covered / total:.1f}%)')
    print(f'  Unique positions: {n_unique} ({100 * n_unique / total:.1f}%)')
    print(f'  IoC (full text): {ioc_full:.5f}')
    print(f'  IoC (unique only): {ioc_unique:.5f}')
    print(f'  IoC (random 27-char): {ioc_random_27:.5f}')
    print(f'  Ratio unique/random: {ioc_unique / ioc_random_27:.3f}')

    # The unique-content IoC should be close to random — confirming no simple
    # substitution signal survives even after stripping the scaffolding.
    assert ioc_unique < 0.045, (
        f'Unique-content IoC {ioc_unique:.5f} unexpectedly high (> 0.045)')
    print('  [OK] Unique content IoC is near-random — no monoalphabetic signal.')

    return {
        'n_covered': n_covered,
        'n_unique': n_unique,
        'ioc_full': round(ioc_full, 5),
        'ioc_unique': round(ioc_unique, 5),
    }


def section_794_offset28_autocorrelation_spike(m: dict[str, list[int]]) -> dict:
    """§794: Assert and quantify the anomalous autocorrelation spike at offset 28
    in the 27-class text. This spike (≈0.074) is roughly 2× the background level
    and is directly tied to the 15-char isomorph repeat distance in Family A."""

    banner(794, 'OFFSET-28 AUTOCORRELATION SPIKE')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)
    all_text = ''.join(flat[l] for l in MSG_LABELS)
    n = len(all_text)

    # Compute autocorrelation at offsets 1-40
    autocorr: dict[int, float] = {}
    for offset in range(1, 41):
        matches = sum(1 for i in range(n - offset)
                      if all_text[i] == all_text[i + offset])
        autocorr[offset] = matches / (n - offset)

    # Background level: median of offsets 1-40
    vals = sorted(autocorr.values())
    background = vals[len(vals) // 2]

    spike_28 = autocorr[28]
    ratio_28 = spike_28 / background if background > 0 else float('inf')

    print(f'  Background autocorrelation (median): {background:.5f}')
    print(f'  Autocorrelation at offset 28: {spike_28:.5f}')
    print(f'  Ratio (spike / background): {ratio_28:.2f}×')
    print(f'  Neighbors: offset 27 = {autocorr[27]:.5f}, offset 29 = {autocorr[29]:.5f}')

    # The spike should be at least 1.5× the background
    assert ratio_28 > 1.5, (
        f'Offset-28 spike ratio {ratio_28:.2f} not significant (< 1.5×)')
    print('  [OK] Offset-28 autocorrelation spike is significant.')

    return {
        'spike_28': round(spike_28, 5),
        'background': round(background, 5),
        'ratio': round(ratio_28, 2),
    }


