def section_853_constant_step_refutation(m: dict[str, list[int]]) -> dict:
    banner(853, 'CONSTANT-STEP WHEEL REFUTATION')
    print("  Asserting that a constant-step wheel offset forces step=0.")
    
    crib_pos1 = 1
    crib_pos12 = 12
    
    diff = crib_pos12 - crib_pos1
    modulus = 83
    
    valid_steps = [s for s in range(modulus) if (diff * s) % modulus == 0]
    
    kv('Valid steps for O[I[x]+1*s] = O[I[x]+12*s]', valid_steps)
    assert valid_steps == [0]
    print("  ✓ Asserted: Constant-step wheel forces step=0 (degenerate static cipher).")
    return {'valid_steps': valid_steps}

def section_854_linear_autokey_refutation(m: dict[str, list[int]]) -> dict:
    banner(854, 'LINEAR AUTOKEY WHEEL REFUTATION')
    print("  Asserting that f(x) = ax+b advance forces a=0 across families.")
    
    c0_vals = [27, 33, 34, 36, 50, 63, 76, 77, 80]
    modulus = 83
    
    valid_a = []
    for a in range(modulus):
        for b in range(modulus):
            outputs = set((a * c + b) % modulus for c in c0_vals)
            if len(outputs) == 1:
                valid_a.append(a)
                break
                
    valid_a = sorted(list(set(valid_a)))
    kv('Valid multipliers (a) for linear advance', valid_a)
    assert valid_a == [0]
    print("  ✓ Asserted: Linear autokey advance forces a=0 (collapsing to constant-step).")
    return {'valid_a': valid_a}

