# ── §811–§812: DEEP-DIVE FOLLOW-UPS FROM §810/§798 ──────────────────────


def section_811_block_injectivity_proof(m: dict[str, list[int]]) -> dict:
    """§811: Prove that every block has ALL-DISTINCT classes — i.e., within any
    single block, no class appears more than once. This is the foundational
    constraint that explains the autocorrelation suppression (§810) and the
    merge impossibility (§798).

    This is a stronger statement than "near-zero repeats" — it's EXACT ZERO
    for ALL offset distances within a block, not just offset 1."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS

    banner(811, 'BLOCK-INJECTIVITY PROOF (EACH CLASS APPEARS ≤ 1 PER BLOCK)')
    skel = _load_collapsed_skeleton()

    total_blocks = 0
    violations = 0
    max_block_size = 0
    max_unique_ratio = 0.0  # min ratio (worst case)

    per_msg_results: dict[str, list[str]] = {}

    for msg in MSG_LABELS:
        spans = REALISTIC_BLOCK_SPANS[msg]
        per_msg_results[msg] = []
        for bi, (start, end) in enumerate(spans):
            total_blocks += 1
            block_classes = []
            for pos in range(start, end + 1):
                key = f'{msg},{pos}'
                if key in skel:
                    block_classes.append(skel[key])
            block_size = len(block_classes)
            n_unique = len(set(block_classes))
            max_block_size = max(max_block_size, block_size)

            if n_unique < block_size:
                violations += 1
                # Find the duplicate(s)
                from collections import Counter as _C811
                dupes = {k: v for k, v in _C811(block_classes).items() if v > 1}
                per_msg_results[msg].append(
                    f'    VIOLATION B{bi} ({start}-{end}): '
                    f'{block_size} positions, {n_unique} unique, dupes={dupes}')

    print(f'  Total blocks scanned: {total_blocks}')
    print(f'  Largest block: {max_block_size} positions')
    print(f'  Violations (class repeats within block): {violations}')

    if violations > 0:
        for msg, results in per_msg_results.items():
            for r in results:
                print(r)

    # Also verify the within-block autocorrelation at ALL offsets
    total_within_pairs = 0
    total_within_matches = 0
    for msg in MSG_LABELS:
        spans = REALISTIC_BLOCK_SPANS[msg]
        for start, end in spans:
            block_classes = []
            for pos in range(start, end + 1):
                key = f'{msg},{pos}'
                if key in skel:
                    block_classes.append(skel[key])
            # Check all pairs within this block
            n = len(block_classes)
            for i in range(n):
                for j in range(i + 1, n):
                    total_within_pairs += 1
                    if block_classes[i] == block_classes[j]:
                        total_within_matches += 1

    print(f'  Within-block pairs (all offsets): {total_within_pairs}')
    print(f'  Within-block matches: {total_within_matches}')

    assert violations == 0, f'Found {violations} blocks with duplicate classes!'
    assert total_within_matches == 0, (
        f'Found {total_within_matches} within-block class matches!')
    print('  [OK] Block-injectivity is absolute: every class appears ≤1 time per block.')
    print('       This is a CONSTRUCTION CONSTRAINT, not a statistical observation.')

    return {
        'total_blocks': total_blocks,
        'max_block_size': max_block_size,
        'violations': violations,
        'within_block_pairs': total_within_pairs,
        'within_block_matches': total_within_matches,
    }


def section_812_merge_conflict_completeness(m: dict[str, list[int]]) -> dict:
    """§812: Prove that the 27-class system is maximally rigid by showing the
    MINIMUM number of block-conflicts for each class category.

    Key findings:
    - Classes 0–24 ("core"): every pair co-occurs in ≥5 blocks. Unmergeable.
    - Class 26 ("_"): closest merge has 2 conflicts. Still unmergeable.
    - Class 25 ("Z"): closest merge (with 26) has 4 conflicts.
    - Even allowing 1 violation: still 0 legal merges.
    - Allowing 2 violations: only 3 merges open, all involving Class 26."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS
    from itertools import combinations

    banner(812, 'MERGE CONFLICT COMPLETENESS (27-CLASS RIGIDITY)')
    skel = _load_collapsed_skeleton()

    # Build per-block class sets
    block_class_sets: list[set[int]] = []
    block_labels: list[tuple[str, int, int, int]] = []
    for msg in MSG_LABELS:
        spans = REALISTIC_BLOCK_SPANS[msg]
        for bi, (start, end) in enumerate(spans):
            classes_in_block = set()
            for pos in range(start, end + 1):
                key = f'{msg},{pos}'
                if key in skel:
                    classes_in_block.add(skel[key])
            block_class_sets.append(classes_in_block)
            block_labels.append((msg, bi, start, end))

    all_classes = sorted(set(skel.values()))

    # Compute conflict count for every pair
    pair_conflicts: dict[tuple[int, int], int] = {}
    for a, b in combinations(all_classes, 2):
        count = sum(1 for bset in block_class_sets if a in bset and b in bset)
        pair_conflicts[(a, b)] = count

    # Categorize
    core_pairs = [(a, b) for a, b in pair_conflicts
                  if a <= 24 and b <= 24]
    core_min = min(pair_conflicts[(a, b)] for a, b in core_pairs)
    core_max = max(pair_conflicts[(a, b)] for a, b in core_pairs)

    involving_26 = [(a, b) for a, b in pair_conflicts if 26 in (a, b)]
    min_26 = min(pair_conflicts[(a, b)] for a, b in involving_26)

    involving_25 = [(a, b) for a, b in pair_conflicts
                    if 25 in (a, b) and 26 not in (a, b)]
    min_25 = min(pair_conflicts[(a, b)] for a, b in involving_25)

    print(f'  Core classes (0-24):')
    print(f'    Minimum conflicts between any core pair: {core_min}')
    print(f'    Maximum conflicts between any core pair: {core_max}')
    min_core_pair = min(core_pairs, key=lambda p: pair_conflicts[p])
    print(f'    Closest core pair: {min_core_pair[0]}-{min_core_pair[1]} '
          f'with {pair_conflicts[min_core_pair]} conflicts')
    print(f'  Class 25 (Z):')
    print(f'    Minimum conflicts (excl. class 26): {min_25}')
    print(f'  Class 26 (_):')
    print(f'    Minimum conflicts: {min_26}')

    # Relaxation
    for max_v in range(4):
        n_legal = sum(1 for c in pair_conflicts.values() if c <= max_v)
        print(f'  Allowing {max_v} violations: {n_legal} legal merges')

    assert core_min >= 5, (
        f'Core pair with only {core_min} conflicts — alphabet may be reducible!')
    assert min_26 >= 2, (
        f'Class 26 merge with only {min_26} conflicts — suspiciously close!')

    print(f'  [OK] Core classes (0-24) have ≥{core_min} conflicts per pair.')
    print(f'       System is maximally rigid. No reduction from 27 is possible.')

    return {
        'core_min_conflicts': core_min,
        'core_max_conflicts': core_max,
        'class26_min_conflicts': min_26,
        'class25_min_conflicts': min_25,
    }


