    print(f'  Total Class 25 occurrences: {len(hits)}')
    print(f'  {"Msg":<4} {"Pos":>4} {"Blk":>4} {"Span":>10} {"Off":>4} {"BLen":>5}')
    print(f'  {"---":<4} {"---":>4} {"---":>4} {"--------":>10} {"---":>4} {"----":>5}')

    rows: list[dict] = []
    for msg, pos in hits:
        bi, bs, be, off, blen = _pos_to_block(msg, pos, REALISTIC_BLOCK_SPANS[msg])
        rows.append(dict(msg=msg, pos=pos, block=bi, span=(bs, be),
                         offset=off, block_len=blen))
        print(f'  {msg:<4} {pos:>4} {bi:>4} {f"{bs}-{be}":>10} {off:>4} {blen:>5}')

    assert len(hits) == 21, f'Expected 21 Class 25 occurrences, got {len(hits)}'
    print('  [OK] Class 25 census: 21 occurrences catalogued.')

    per_msg = Counter(msg for msg, _ in hits)
    print(f'  Per-message distribution: {dict(per_msg)}')

    return {
        'count': len(hits),
        'per_msg': dict(per_msg),
        'rows': rows,
    }


