# -- s835 ---------------------------------------------------------------------

def section_835_class25_26_boundary_correlation(m: dict[str, list[int]]) -> dict:
    """§835: For each Class 25/26 occurrence, compute distance to the nearest
    block boundary.  Compare to the expected distance under a uniform null
    model within each block."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS

    banner(835, 'CLASS 25/26 BLOCK-BOUNDARY CORRELATION')
    skel = _load_collapsed_skeleton()

    results: dict[int, dict] = {}
    for cls in (25, 26):
        hits = _class_positions(skel, cls)
        observed_dists: list[int] = []
        expected_dists: list[float] = []

        for msg, pos in hits:
            bi, bs, be, off, blen = _pos_to_block(msg, pos,
                                                   REALISTIC_BLOCK_SPANS[msg])
            # Distance to nearest boundary (start or end of block)
            dist = min(off, blen - 1 - off)
            observed_dists.append(dist)
            # Expected distance for a uniform position in a block of length L:
            # mean of min(k, L-1-k) for k in 0..L-1
            expected = sum(min(k, blen - 1 - k) for k in range(blen)) / blen
            expected_dists.append(expected)

        mean_obs = sum(observed_dists) / len(observed_dists)
        mean_exp = sum(expected_dists) / len(expected_dists)

        print(f'  Class {cls}:')
        print(f'    Occurrences: {len(hits)}')
        print(f'    Boundary distances: {observed_dists}')
        print(f'    Mean observed distance: {mean_obs:.2f}')
        print(f'    Mean expected (uniform): {mean_exp:.2f}')
        print(f'    Ratio obs/exp: {mean_obs / mean_exp:.2f}')

        results[cls] = {
            'count': len(hits),
            'mean_obs': round(mean_obs, 2),
            'mean_exp': round(mean_exp, 2),
            'ratio': round(mean_obs / mean_exp, 2),
            'dists': observed_dists,
        }

    # At least one class should show significant proximity (ratio < 0.8)
    # or significant avoidance (ratio > 1.2) -- either pattern is structural.
    any_significant = any(
        r['ratio'] < 0.8 or r['ratio'] > 1.2 for r in results.values()
    )
    if any_significant:
        print('  [OK] At least one class shows significant boundary proximity/avoidance.')
    else:
        print('  [OK] Neither class shows strong boundary correlation -- '
              'they may be interior-content symbols.')

    return {f'class_{k}': v for k, v in results.items()}


# -- s836 ---------------------------------------------------------------------

def section_836_class25_26_neighbor_analysis(m: dict[str, list[int]]) -> dict:
    """§836: For each Class 25/26 occurrence, record the class that immediately
    precedes and follows it.  Build predecessor/successor frequency tables."""
    from cipher_synthesis import MSG_LENGTHS

    banner(836, 'CLASS 25/26 NEIGHBOR ANALYSIS')
    skel = _load_collapsed_skeleton()

    results: dict[int, dict] = {}
    for cls in (25, 26):
        hits = _class_positions(skel, cls)
        predecessors: list[int | None] = []
        successors: list[int | None] = []

        for msg, pos in hits:
            # Predecessor
            if pos > 0:
                key_prev = f'{msg},{pos - 1}'
                predecessors.append(skel.get(key_prev))
            else:
                predecessors.append(None)
            # Successor
            if pos < MSG_LENGTHS[msg] - 1:
                key_next = f'{msg},{pos + 1}'
                successors.append(skel.get(key_next))
            else:
                successors.append(None)

        pred_freq = Counter(p for p in predecessors if p is not None)
        succ_freq = Counter(s for s in successors if s is not None)

        print(f'  Class {cls} ({len(hits)} occurrences):')
        print(f'    Predecessor classes (frequency):')
        for c, count in pred_freq.most_common():
            print(f'      class {c:>2}: {count}')
        print(f'    Successor classes (frequency):')
        for c, count in succ_freq.most_common():
            print(f'      class {c:>2}: {count}')

        # Check for over-representation: any neighbor appearing > 30% of time
        max_pred_frac = max(pred_freq.values()) / len(hits) if pred_freq else 0
        max_succ_frac = max(succ_freq.values()) / len(hits) if succ_freq else 0
        print(f'    Max predecessor concentration: {max_pred_frac:.0%}')
        print(f'    Max successor concentration: {max_succ_frac:.0%}')

        results[cls] = {
            'pred_freq': dict(pred_freq),
            'succ_freq': dict(succ_freq),
            'max_pred_frac': round(max_pred_frac, 3),
            'max_succ_frac': round(max_succ_frac, 3),
        }

    print('  [OK] Neighbor analysis complete for Classes 25 and 26.')
    return {f'class_{k}': v for k, v in results.items()}


# -- s837 ---------------------------------------------------------------------

def section_837_space_hypothesis_word_lengths(m: dict[str, list[int]]) -> dict:
    """§837: Treat Class 25 (then Class 26) as a space character.  Split each
    message at space positions to get "words".  Compare word-length distribution
    to Finnish (~6.5 chars) and English (~4.7 chars)."""
    import string
    from cipher_synthesis import MSG_LENGTHS

    banner(837, 'SPACE HYPOTHESIS: WORD LENGTH DISTRIBUTION')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)

    FINNISH_AVG = 6.5
    ENGLISH_AVG = 4.7

    results: dict[int, dict] = {}
    for space_cls in (25, 26):
        # Character used in flattened text
        space_char = string.ascii_uppercase[space_cls] if space_cls < 26 else '_'
        all_word_lens: list[int] = []

        print(f'\n  Testing Class {space_cls} ("{space_char}") as space:')
        for msg in MSG_LABELS:
            text = flat[msg]
            words = text.split(space_char)
            word_lens = [len(w) for w in words if len(w) > 0]
            all_word_lens.extend(word_lens)

        if all_word_lens:
            mean_wl = sum(all_word_lens) / len(all_word_lens)
            wl_freq = Counter(all_word_lens)
            print(f'    Total "words": {len(all_word_lens)}')
            print(f'    Mean word length: {mean_wl:.2f}')
            print(f'    Finnish expected: {FINNISH_AVG}')
            print(f'    English expected: {ENGLISH_AVG}')
            print(f'    Delta from Finnish: {abs(mean_wl - FINNISH_AVG):.2f}')
            print(f'    Delta from English: {abs(mean_wl - ENGLISH_AVG):.2f}')
            print(f'    Word-length distribution (length: count):')
            for length in sorted(wl_freq.keys()):
                bar = '#' * wl_freq[length]
                print(f'      {length:>3}: {wl_freq[length]:>3} {bar}')
        else:
            mean_wl = 0.0
            wl_freq = Counter()
            print(f'    No words found (class not present).')

        results[space_cls] = {
            'n_words': len(all_word_lens),
            'mean_wl': round(mean_wl, 2),
            'delta_finnish': round(abs(mean_wl - FINNISH_AVG), 2),
            'delta_english': round(abs(mean_wl - ENGLISH_AVG), 2),
            'distribution': dict(wl_freq),
        }

    # Determine which class is closer to plausible space
    if results[25]['n_words'] > 0 and results[26]['n_words'] > 0:
        closer = 25 if results[25]['delta_finnish'] < results[26]['delta_finnish'] else 26
        print(f'\n  Closer to Finnish word length: Class {closer} '
              f'(mean={results[closer]["mean_wl"]:.2f})')

    print('  [OK] Word-length distributions computed for both candidates.')
    return {f'class_{k}': v for k, v in results.items()}


# -- s838 ---------------------------------------------------------------------

def section_838_delimiter_segment_lengths(m: dict[str, list[int]]) -> dict:
    """§838: Treat Class 26 as a delimiter/separator.  Split messages at Class 26
    positions and report resulting segment lengths.  Check if segment lengths
    correspond to block sizes or other structural units."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS

    banner(838, 'DELIMITER HYPOTHESIS: SEGMENT LENGTHS (CLASS 26)')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)

    all_segments: list[int] = []
    per_msg_segments: dict[str, list[int]] = {}

    for msg in MSG_LABELS:
        text = flat[msg]
        # Find positions of '_' (class 26)
        delim_positions = [i for i, c in enumerate(text) if c == '_']
        # Build segments
        boundaries = [-1] + delim_positions + [len(text)]
        seg_lens = [boundaries[i + 1] - boundaries[i] - 1
                    for i in range(len(boundaries) - 1)]
        # Remove any -1 from consecutive delimiters
        seg_lens = [s for s in seg_lens if s > 0]
        per_msg_segments[msg] = seg_lens
        all_segments.extend(seg_lens)

        # Block lengths for comparison
        block_lens = [e - s + 1 for s, e in REALISTIC_BLOCK_SPANS[msg]]
        print(f'  {msg}: delimiters at {delim_positions}, '
              f'segments={seg_lens}, blocks={block_lens}')

    mean_seg = sum(all_segments) / len(all_segments) if all_segments else 0
    seg_freq = Counter(all_segments)

    print(f'\n  Total segments: {len(all_segments)}')
    print(f'  Mean segment length: {mean_seg:.1f}')
    print(f'  Segment-length distribution:')
    for length in sorted(seg_freq.keys()):
        print(f'    {length:>4}: {seg_freq[length]}')

    # Compare to block mean
    all_block_lens: list[int] = []
    for msg in MSG_LABELS:
        for s, e in REALISTIC_BLOCK_SPANS[msg]:
            all_block_lens.append(e - s + 1)
    mean_block = sum(all_block_lens) / len(all_block_lens)
    print(f'  Mean block length: {mean_block:.1f}')
    print(f'  Segment/block ratio: {mean_seg / mean_block:.2f}')

    print('  [OK] Segment analysis complete for Class 26 delimiter hypothesis.')
    return {
        'n_segments': len(all_segments),
        'mean_segment': round(mean_seg, 1),
        'mean_block': round(mean_block, 1),
        'per_msg': per_msg_segments,
    }


