def section_839_frequency_comparison(m: dict[str, list[int]]) -> dict:
    """§839: Compare frequencies of Classes 25 and 26 against expected frequencies
    of various plaintext candidates: space, Finnish special chars, punctuation."""
    from cipher_synthesis import MSG_LENGTHS

    banner(839, 'FREQUENCY COMPARISON: CLASSES 25/26 vs CANDIDATES')
    skel = _load_collapsed_skeleton()

    total = sum(MSG_LENGTHS.values())
    count_25 = sum(1 for v in skel.values() if v == 25)
    count_26 = sum(1 for v in skel.values() if v == 26)
    freq_25 = count_25 / total
    freq_26 = count_26 / total

    # Reference frequencies
    candidates = [
        ('Space (Finnish)',   0.15, 0.17),
        ('Space (English)',   0.15, 0.18),
        ('A-umlaut (Fi)',     0.034, 0.036),
        ('O-umlaut (Fi)',     0.003, 0.005),
        ('A-ring (Fi)',       0.00003, 0.00005),
        ('Period/punct.',     0.02, 0.05),
        ('Q (Finnish)',       0.0001, 0.0002),
        ('X (Finnish)',       0.0001, 0.0002),
        ('Z (Finnish)',       0.0001, 0.0002),
        ('W (Finnish)',       0.0001, 0.0002),
    ]

    print(f'  Class 25: {count_25} / {total} = {freq_25:.4f} ({freq_25*100:.2f}%)')
    print(f'  Class 26: {count_26} / {total} = {freq_26:.4f} ({freq_26*100:.2f}%)')
    print()
    print(f'  {"Candidate":<20} {"Range":>14}  {"Cls25 fit":>10} {"Cls26 fit":>10}')
    print(f'  {"-"*20} {"-"*14}  {"-"*10} {"-"*10}')

    for name, lo, hi in candidates:
        mid = (lo + hi) / 2
        fit25 = 'IN RANGE' if lo <= freq_25 <= hi else f'{freq_25/mid:.2f}x'
        fit26 = 'IN RANGE' if lo <= freq_26 <= hi else f'{freq_26/mid:.2f}x'
        print(f'  {name:<20} {lo*100:.2f}-{hi*100:.2f}%  {fit25:>10} {fit26:>10}')

    # Class 25 at ~2% is closest to punctuation (2-5%) or A-umlaut (3.4-3.6%)
    # Class 26 at ~1% is closest to O-umlaut (0.3-0.5%) or punctuation low end
    print()
    print(f'  Class 25 ({freq_25*100:.2f}%) best matches: punctuation or A-umlaut range')
    print(f'  Class 26 ({freq_26*100:.2f}%) best matches: O-umlaut or punctuation low end')

    assert count_25 == 21, f'Expected 21 Class 25, got {count_25}'
    assert count_26 == 10, f'Expected 10 Class 26, got {count_26}'
    print('  [OK] Frequency comparison table complete.')

    return {
        'count_25': count_25,
        'count_26': count_26,
        'freq_25': round(freq_25, 5),
        'freq_26': round(freq_26, 5),
        'total': total,
    }


# -- s840 ---------------------------------------------------------------------

def section_840_ioc_without_25_26(m: dict[str, list[int]]) -> dict:
    """§840: Compute IoC on the flattened text after removing Class 25, Class 26,
    or both.  If removing them improves IoC toward natural-language levels, that
    supports them being non-letter symbols (spaces, punctuation)."""
    import string

    banner(840, 'IoC WITH CLASSES 25/26 REMOVED')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)
    all_text = ''.join(flat[l] for l in MSG_LABELS)

    alphabet = string.ascii_uppercase + '_'

    def compute_ioc(text: str) -> float:
        n = len(text)
        if n < 2:
            return 0.0
        freq = Counter(text)
        return sum(f * (f - 1) for f in freq.values()) / (n * (n - 1))

    ioc_full = compute_ioc(all_text)
    n_full = len(all_text)
    n_classes_full = len(set(all_text))

    # Remove class 25 (char 'Z')
    char_25 = alphabet[25]  # 'Z'
    text_no25 = ''.join(c for c in all_text if c != char_25)
    ioc_no25 = compute_ioc(text_no25)

    # Remove class 26 (char '_')
    char_26 = alphabet[26]  # '_'
    text_no26 = ''.join(c for c in all_text if c != char_26)
    ioc_no26 = compute_ioc(text_no26)

    # Remove both
    text_no_both = ''.join(c for c in all_text if c not in (char_25, char_26))
    ioc_no_both = compute_ioc(text_no_both)

    # Reference IoC values
    ioc_random_27 = 1.0 / 27
    ioc_random_25 = 1.0 / 25
    ioc_finnish = 0.0716
    ioc_english = 0.0667

    print(f'  Full text: {n_full} chars, {n_classes_full} classes, IoC = {ioc_full:.5f}')
    print(f'  Without Class 25 ({char_25}): {len(text_no25)} chars, IoC = {ioc_no25:.5f}')
    print(f'  Without Class 26 ({char_26}): {len(text_no26)} chars, IoC = {ioc_no26:.5f}')
    print(f'  Without both:     {len(text_no_both)} chars, IoC = {ioc_no_both:.5f}')
    print()
    print(f'  Reference IoC values:')
    print(f'    Random 27-char: {ioc_random_27:.5f}')
    print(f'    Random 25-char: {ioc_random_25:.5f}')
    print(f'    Finnish:        {ioc_finnish:.5f}')
    print(f'    English:        {ioc_english:.5f}')
    print()
    print(f'  Delta from removing 25: {ioc_no25 - ioc_full:+.5f}')
    print(f'  Delta from removing 26: {ioc_no26 - ioc_full:+.5f}')
    print(f'  Delta from removing both: {ioc_no_both - ioc_full:+.5f}')

    print('  [OK] IoC analysis complete for Class 25/26 removal.')

    return {
        'ioc_full': round(ioc_full, 5),
        'ioc_no25': round(ioc_no25, 5),
        'ioc_no26': round(ioc_no26, 5),
        'ioc_no_both': round(ioc_no_both, 5),
        'delta_25': round(ioc_no25 - ioc_full, 5),
        'delta_26': round(ioc_no26 - ioc_full, 5),
    }


# -- s841 ---------------------------------------------------------------------

def section_841_class25_interarrival(m: dict[str, list[int]]) -> dict:
    """§841: Compute gaps between consecutive Class 25 occurrences within each
    message.  Compare gap distribution to Finnish word-length expectations
    (~6.5 chars between spaces).  Also compute gaps in unique (non-isomorph)
    regions only."""
    import string

    banner(841, 'CLASS 25 INTER-ARRIVAL DISTRIBUTION')
    skel = _load_collapsed_skeleton()
    flat = _flatten_collapsed_skeleton(skel)
    all_text = ''.join(flat[l] for l in MSG_LABELS)
    covered = _find_repeated_positions(all_text)

    alphabet = string.ascii_uppercase + '_'
    char_25 = alphabet[25]  # 'Z'

    all_gaps: list[int] = []
    unique_gaps: list[int] = []
    per_msg_gaps: dict[str, list[int]] = {}

    # Track global offset for covered[] indexing
    global_offset = 0

    for msg in MSG_LABELS:
        text = flat[msg]
        positions = [i for i, c in enumerate(text) if c == char_25]
        # Gaps between consecutive occurrences
        gaps = [positions[i + 1] - positions[i] for i in range(len(positions) - 1)]
        per_msg_gaps[msg] = gaps
        all_gaps.extend(gaps)

        # Unique-region gaps: positions where neither endpoint is isomorph-covered
        for i in range(len(positions) - 1):
            p1_global = global_offset + positions[i]
            p2_global = global_offset + positions[i + 1]
            if not covered[p1_global] and not covered[p2_global]:
                unique_gaps.append(positions[i + 1] - positions[i])

        global_offset += len(text)
        if positions:
            print(f'  {msg}: positions={positions}, gaps={gaps}')
        else:
            print(f'  {msg}: no Class 25 occurrences')

    if all_gaps:
        mean_gap = sum(all_gaps) / len(all_gaps)
        gap_freq = Counter(all_gaps)
        print(f'\n  Total gaps: {len(all_gaps)}')
        print(f'  Mean gap: {mean_gap:.2f}')
        print(f'  Finnish space gap expected: ~7.5 (word_len + 1)')
        print(f'  English space gap expected: ~5.7 (word_len + 1)')
        print(f'  Gap distribution:')
        for g in sorted(gap_freq.keys()):
            bar = '#' * gap_freq[g]
            print(f'    {g:>3}: {gap_freq[g]:>2} {bar}')
    else:
        mean_gap = 0.0
        gap_freq = Counter()
        print('  No inter-arrival gaps (fewer than 2 occurrences in any message).')

    if unique_gaps:
        mean_unique = sum(unique_gaps) / len(unique_gaps)
        print(f'\n  Unique-region gaps: {len(unique_gaps)}, mean={mean_unique:.2f}')
    else:
        mean_unique = 0.0
        print(f'\n  No unique-region gaps found.')

    print('  [OK] Class 25 inter-arrival analysis complete.')

    return {
        'n_gaps': len(all_gaps),
        'mean_gap': round(mean_gap, 2),
        'n_unique_gaps': len(unique_gaps),
        'mean_unique_gap': round(mean_unique, 2),
        'distribution': dict(gap_freq),
        'per_msg': per_msg_gaps,
    }


# -- s842 ---------------------------------------------------------------------

def section_842_null_test_rare_finnish(m: dict[str, list[int]]) -> dict:
    """§842: Test whether Classes 25 and 26 could be ordinary rare Finnish letters.
    (a) Position-within-block distribution -- random or concentrated?
    (b) Co-occurrence with other classes -- do they behave like regular letters?
    (c) Compare frequency to rare Finnish letters."""
    from cipher_synthesis import REALISTIC_BLOCK_SPANS, MSG_LENGTHS

    banner(842, 'NULL TEST: CLASSES 25/26 AS RARE FINNISH LETTERS')
    skel = _load_collapsed_skeleton()

    total = sum(MSG_LENGTHS.values())

    # Finnish rare-letter frequencies (fraction of all characters including space)
    rare_finnish = {
        'A-ring':   0.00003,
        'Q':        0.0001,
        'X':        0.0001,
        'Z':        0.0001,
        'W':        0.0001,
        'O-umlaut': 0.004,
    }

    freq_25 = 21 / total
    freq_26 = 10 / total

    print(f'  (c) Frequency comparison:')
    print(f'    Class 25: {freq_25*100:.3f}% ({21}/{total})')
    print(f'    Class 26: {freq_26*100:.3f}% ({10}/{total})')
    print(f'    Finnish rare letters:')
    for letter, freq in sorted(rare_finnish.items(), key=lambda x: -x[1]):
        expected_count = freq * total
        print(f'      {letter}: {freq*100:.4f}% -> expected {expected_count:.1f} in corpus')

    # (a) Position-within-block distribution
    print(f'\n  (a) Position-within-block distribution:')
    for cls in (25, 26):
        hits = _class_positions(skel, cls)
        norm_offsets: list[float] = []
        for msg, pos in hits:
            bi, bs, be, off, blen = _pos_to_block(msg, pos,
                                                   REALISTIC_BLOCK_SPANS[msg])
            norm_offsets.append(off / blen if blen > 1 else 0.5)

        mean_norm = sum(norm_offsets) / len(norm_offsets) if norm_offsets else 0
        var = sum((x - mean_norm) ** 2 for x in norm_offsets) / len(norm_offsets) if norm_offsets else 0
        std = var ** 0.5

        print(f'    Class {cls}: mean normalized offset = {mean_norm:.3f} '
              f'(expected 0.5), std = {std:.3f}')
        print(f'    Normalized offsets: {[round(x, 2) for x in norm_offsets]}')

        # Quartile distribution
        q_counts = [0, 0, 0, 0]
        for x in norm_offsets:
            qi = min(int(x * 4), 3)
            q_counts[qi] += 1
        print(f'    Quartile distribution: {q_counts} '
              f'(uniform expectation: ~{len(norm_offsets)/4:.1f} each)')

    # (b) Co-occurrence profile
    print(f'\n  (b) Co-occurrence profile:')

    block_contents: list[tuple[str, int, set[int]]] = []
    for msg in MSG_LABELS:
        for bi, (s, e) in enumerate(REALISTIC_BLOCK_SPANS[msg]):
            classes = set()
            for p in range(s, e + 1):
                key = f'{msg},{p}'
                if key in skel:
                    classes.add(skel[key])
            block_contents.append((msg, bi, classes))

    for cls in (25, 26):
        containing = [(msg, bi, cs) for msg, bi, cs in block_contents if cls in cs]
        cooccur: Counter = Counter()
        for _, _, cs in containing:
            for c in cs:
                if c != cls:
                    cooccur[c] += 1
        n_cooccur = len(cooccur)
        n_blocks_with = len(containing)
        print(f'    Class {cls} appears in {n_blocks_with} blocks, '
              f'co-occurs with {n_cooccur}/26 other classes')
        top5 = cooccur.most_common(5)
        print(f'    Top co-occurring: {top5}')

    # Verdict
    expected_rare = max(rare_finnish[c] for c in ('A-ring', 'Q', 'X', 'Z', 'W')) * total
    print(f'\n  Verdict:')
    print(f'    Expected count for rarest Finnish letters: < {expected_rare:.1f}')
    print(f'    Class 25 count ({21}) is {21/max(expected_rare,0.001):.0f}x too high for Q/X/Z/W')
    print(f'    Class 26 count ({10}) is {10/max(expected_rare,0.001):.0f}x too high for Q/X/Z/W')
    assert 21 > expected_rare * 10, 'Class 25 is too rare to rule out rare Finnish letters'
    assert 10 > expected_rare * 10, 'Class 26 is too rare to rule out rare Finnish letters'
    print('  [OK] Classes 25/26 are NOT rare Finnish letters (Q/X/Z/W) -- too frequent.')

    return {
        'freq_25_pct': round(freq_25 * 100, 3),
        'freq_26_pct': round(freq_26 * 100, 3),
        'expected_rare_count': round(expected_rare, 2),
    }

def section_855_community_refutation(m: dict[str, list[int]]) -> dict:
    '''
    Asserting that the widely accepted community `decrypted.json` forces
    a trivial (constant) solution when modeled as a GF(83) linear system
    under the autokey model.
    '''
    import json
    decrypted = json.load(open('decrypted.json'))
    
    NUM_VARS = 83 + 27 + 83
    FIN = 'abcdefghijklmnoprstuvyäö .-'
    fin_map = {c: i for i, c in enumerate(FIN)}
    def get_O_idx(c): return c
    def get_I_idx(char): return 83 + fin_map[char]
    def get_f_idx(c): return 83 + 27 + c
    
    eqs = []
    used_vars = set()
    
    for short_k, pt_str in decrypted.items():
        ct = m[short_k]
        f_counts = [0] * 83
        for pos in range(1, len(ct)):
            if pos >= len(pt_str) or pt_str[pos] not in fin_map:
                if pos > 1: f_counts[ct[pos-1]] += 1
                continue
                
            char = pt_str[pos]
            c_val = ct[pos]
            if pos > 1: f_counts[ct[pos-1]] += 1
            
            row = [0] * NUM_VARS
            row[get_O_idx(c_val)] = 1
            row[get_I_idx(char)] = -1
            used_vars.add(get_O_idx(c_val))
            used_vars.add(get_I_idx(char))
            
            for f_c, count in enumerate(f_counts):
                if count > 0:
                    row[get_f_idx(f_c)] = -count
                    used_vars.add(get_f_idx(f_c))
                    
            eqs.append([x % 83 for x in row])

    # Keep only columns of used vars
    used_vars = sorted(list(used_vars))
    compressed_eqs = []
    for row in eqs:
        c_row = [row[i] for i in used_vars]
        if any(x != 0 for x in c_row):
            compressed_eqs.append(c_row)

    def mod_inv(a, modulus): return pow(a, modulus - 2, modulus)
    def rank(matrix, modulus):
        rows = len(matrix); cols = len(matrix[0]) if rows else 0; r = 0
        for c in range(cols):
            pivot = -1
            for i in range(r, rows):
                if matrix[i][c] != 0:
                    pivot = i; break
            if pivot == -1: continue
            matrix[r], matrix[pivot] = matrix[pivot], matrix[r]
            inv = mod_inv(matrix[r][c], modulus)
            for i in range(cols): matrix[r][i] = (matrix[r][i] * inv) % modulus
            for i in range(rows):
                if i != r and matrix[i][c] != 0:
                    factor = matrix[i][c]
                    for j in range(c, cols):
                        matrix[i][j] = (matrix[i][j] - factor * matrix[r][j]) % modulus
            r += 1
        return r

    r = rank(compressed_eqs, 83)
    null_space_dim = len(used_vars) - r
    
    print(f"  Total used variables: {len(used_vars)}")
    print(f"  Rank of coefficient matrix: {r}")
    print(f"  Null space dimension: {null_space_dim}")
    
    assert null_space_dim == 1, f"Expected null space dimension to be exactly 1, but got {null_space_dim}"
    print("  ✓ Asserted: decrypted.json contains linear contradictions forcing trivial permutations.")
    
    return {
        "used_vars": len(used_vars),
        "rank": r,
        "null_space_dim": null_space_dim
    }


# ── §859–§862: Trie structure, state model, reconvergence, family tags ──

def section_859_trie_structure(m: dict[str, list[int]]) -> dict:
    """§859: Messages form a TRIE (prefix tree). Position 0 is a per-message seed.
    Positions 1-2 are universal. The tree branches at positions 3, 6, 10, and 21."""
    banner(859, 'CIPHERTEXT TRIE STRUCTURE')

    tree = {
        'root': (MSG_LABELS, 1, 2),
        'A': (['E1', 'W1', 'E2'], 1, 24),
        'B': (['W2', 'E3', 'W3', 'E4', 'W4', 'E5'], 1, 5),
        'C': (['E3', 'E4', 'W4', 'E5'], 1, 9),
        'D': (['E4', 'W4', 'E5'], 1, 20),
    }

    all_ok = True
    for name, (members, start, end) in tree.items():
        cts = [m[l] for l in members]
        for p in range(start, end + 1):
            vals = set(ct[p] for ct in cts)
            if len(vals) != 1:
                print(f'  FAIL: Group {name} disagrees at pos {p}: {vals}')
                all_ok = False

    p0_vals = [m[l][0] for l in MSG_LABELS]
    p0_unique = len(set(p0_vals)) == len(p0_vals)
    print(f'  Position 0 unique across all messages: {p0_unique}')
    print(f'  Trie structure verified: {all_ok}')
    assert all_ok and p0_unique, 'Trie structure violated'
    print('  \u2713 Asserted: Messages form a trie with per-message seed at position 0.')
    return {'trie_ok': all_ok, 'p0_unique': p0_unique}


def section_860_cipher_state_model(m: dict[str, list[int]]) -> dict:
    """§860: CT_n is a deterministic function of (seed, class[n-2], CT[n-2], CT[n-1], class[n])
    with ZERO conflicts across all 1018 observations from 9 messages."""
    import json as _json
    banner(860, 'CIPHER STATE MODEL: (SEED, CL[-2], CT[-2], CT[-1], CL[N])')

    skel = _json.load(open(str(Path(__file__).parent / 'collapsed_skeleton.json')))

    def _get_classes(label):
        classes = []
        for i in range(200):
            key = f'{label},{i}'
            if key in skel:
                classes.append(skel[key])
            else:
                break
        return classes

    state_to_ct = {}
    conflicts = 0
    total = 0
    for l in MSG_LABELS:
        ct = m[l]
        cl = _get_classes(l)
        seed = ct[0]
        for p in range(2, min(len(ct), len(cl))):
            state = (seed, cl[p-2], ct[p-2], ct[p-1], cl[p])
            total += 1
            if state not in state_to_ct:
                state_to_ct[state] = ct[p]
            elif state_to_ct[state] != ct[p]:
                conflicts += 1

    print(f'  Total observations: {total}')
    print(f'  Unique states: {len(state_to_ct)}')
    print(f'  Conflicts: {conflicts}')
    assert conflicts == 0, f'{conflicts} conflicts in state model'
    print('  \u2713 Asserted: ZERO conflicts. The cipher is deterministic over this state.')
    return {'total': total, 'unique_states': len(state_to_ct), 'conflicts': conflicts}


def section_861_reconvergence(m: dict[str, list[int]]) -> dict:
    """§861: Messages can RECONVERGE after divergence when plaintext classes re-align.
    E1 and W1 share a 13-position reconvergent run at positions 37-49."""
    banner(861, 'CIPHERTEXT RECONVERGENCE')

    ct_e1 = m['E1']
    ct_w1 = m['W1']
    overlap = min(len(ct_e1), len(ct_w1))

    first_div = None
    for p in range(overlap):
        if ct_e1[p] != ct_w1[p]:
            first_div = p
            break
    assert first_div is not None, 'E1 and W1 never diverge'

    runs = []
    run_start = None
    for p in range(first_div, overlap):
        if ct_e1[p] == ct_w1[p]:
            if run_start is None:
                run_start = p
        else:
            if run_start is not None:
                runs.append((run_start, p - 1, p - run_start))
                run_start = None
    if run_start is not None:
        runs.append((run_start, overlap - 1, overlap - run_start))

    longest = max(runs, key=lambda x: x[2]) if runs else (0, 0, 0)
    print(f'  First divergence: pos {first_div}')
    print(f'  Reconvergent runs: {len(runs)}')
    print(f'  Longest run: pos {longest[0]}-{longest[1]} (len {longest[2]})')
    assert longest[2] >= 10, f'Reconvergence too short: {longest[2]}'
    print('  \u2713 Asserted: E1/W1 reconverge for >=10 consecutive positions after divergence.')
    return {'first_div': first_div, 'num_runs': len(runs), 'longest_run_len': longest[2]}


def section_862_position0_family(m: dict[str, list[int]]) -> dict:
    """§862: Position-0 class encodes the message family:
    class 14 = {E1,W1,E2}, class 9 = {W2,E3,W3}, class 20 = {E4,W4,E5}."""
    import json as _json
    banner(862, 'POSITION-0 CLASS AS FAMILY TAG')

    skel = _json.load(open(str(Path(__file__).parent / 'collapsed_skeleton.json')))
    expected = {
        'E1': 14, 'W1': 14, 'E2': 14,
        'W2': 9, 'E3': 9, 'W3': 9,
        'E4': 20, 'W4': 20, 'E5': 20,
    }

    all_ok = True
    for l in MSG_LABELS:
        actual = skel.get(f'{l},0', None)
        exp = expected[l]
        ok = actual == exp
        if not ok:
            all_ok = False
        check = '\u2713' if ok else 'FAIL'
        print(f'  {l}: class_0 = {actual}, expected = {exp} {check}')

    assert all_ok, 'Family encoding violated'
    print('  \u2713 Asserted: Position-0 class perfectly encodes the 3-family partition.')
    return {'all_match': all_ok}

