def parse_section_arg(arg: str | None, sections: list[tuple]) -> set[str]:
    """Parse the section argument into a set of `num_str` values.

    `None`        → all sections (using their printed §N labels).
    `'7'`         → {'7'}.
    `'7..11'`     → {'7', '8', '9', '10', '11'} (range over int interpretation).

    We match on `num_str`, not the iteration index, so user-facing section
    numbers stay stable when sections are added or skipped (e.g. §97 is
    inlined into §1 and not in SECTIONS, but §98 still works as expected).
    """
    all_nums = {num_str for num_str, _, _ in sections}
    if arg is None:
        return all_nums
    if '..' in arg:
        lo, hi = arg.split('..', 1)
        return {str(n) for n in range(int(lo), int(hi) + 1)} & all_nums
    return {arg} & all_nums


def main() -> int:
    ap = argparse.ArgumentParser(description='Eye-puzzle cryptanalysis harness')
    ap.add_argument('section', nargs='?', default=None,
                    help="section number (e.g. '11') or range (e.g. '9..13')")
    args = ap.parse_args()

    selected = parse_section_arg(args.section, SECTIONS)
    m = parse_eyes_json()

    results: dict[str, object] = {}
    failures: list[tuple[str, BaseException]] = []
    print('=' * 80)
    print('NOITA EYE-PUZZLE CRYPTANALYSIS HARNESS')
    print('Reproduces every structural claim in eye/CRYPTANALYSIS.md.')
    print('Each section asserts its headline numbers; `AssertionError` = bug.')
    print('=' * 80)

    for num_str, _title, fn in SECTIONS:
        if num_str not in selected:
            continue
        try:
            # Section-specific argument plumbing
            if fn is section_10_monoalpha_within_block:
                comp_of = results.get('9', {}).get('comp_of') if isinstance(
                    results.get('9'), dict) else None
                if comp_of is None:
                    # Section 10 doesn't actually need comp_of; we recompute the iso list.
                    res = fn(m, {})
                else:
                    res = fn(m, comp_of)
            elif fn is section_11_block_segmentation:
                comp_of = results['9']['comp_of'] if '9' in results else None
                if comp_of is None:
                    # Re-derive comp_of so section 11 can run standalone.
                    comp_of = section_9_plaintext_equivalence_graph(m)['comp_of']
                res = fn(m, comp_of)
            elif fn is section_12_per_block_ioc:
                blocks = results.get('11', {}).get('blocks') if isinstance(
                    results.get('11'), dict) else None
                if blocks is None:
                    comp_of = section_9_plaintext_equivalence_graph(m)['comp_of']
                    blocks = section_11_block_segmentation(m, comp_of)['blocks']
                res = fn(m, blocks)
            elif fn is section_13_wheel_cipher_refutation:
                blocks = results.get('11', {}).get('blocks') if isinstance(
                    results.get('11'), dict) else None
                # Section 13 builds its own (different, stricter) blocks internally.
                res = fn(m, blocks or [])
            elif fn is section_15_class_frequency_profile:
                comp_of = results.get('9', {}).get('comp_of') if isinstance(
                    results.get('9'), dict) else None
                if comp_of is None:
                    comp_of = section_9_plaintext_equivalence_graph(m)['comp_of']
                res = fn(m, comp_of)
            elif fn is section_297_decoded_corpus_preview:
                mapping = results.get('296', {}).get('mapping') if isinstance(
                    results.get('296'), dict) else None
                res = fn(m, mapping)
            elif fn is section_298_bigram_trigram_validation:
                mapping = results.get('296', {}).get('mapping') if isinstance(
                    results.get('296'), dict) else None
                res = fn(m, mapping)
            else:
                res = fn(m)
            results[num_str] = res
        except AssertionError as exc:
            failures.append((num_str, exc))
            print(f'\n  ✗ ASSERTION FAILED in §{num_str}: {exc}')
        except Exception as exc:  # noqa: BLE001
            failures.append((num_str, exc))
            print(f'\n  ✗ UNEXPECTED ERROR in §{num_str}: {exc!r}')

    # ─── final summary ───
    print(f'\n{"=" * 80}\nHARNESS RESULTS\n{"=" * 80}')
    sorted_sel = sorted(selected, key=lambda s: int(s))
    print(f'  sections run: {[int(s) for s in sorted_sel]}')
    print(f'  passed: {len(selected) - len(failures)}')
    print(f'  failed: {len(failures)}')
    if failures:
        for num_str, exc in failures:
            print(f'    §{num_str}: {exc}')
        return 1
    print('\n  ALL ASSERTIONS PASSED.')
    print('  Every headline number in CRYPTANALYSIS.md is reproduced from this harness.')

    # ── External citations cross-reference banner ──
    ran_section_nums = set(results)
    cited_sections = sorted(
        (int(k) for k in EXTERNAL_CITATIONS if k in ran_section_nums),
        key=int)
    if cited_sections:
        print(f'\n{"-" * 80}\n  EXTERNAL CITATIONS (peer-review cross-refs)\n{"-" * 80}')
        for sec in cited_sections:
            print(f'  §{sec}:')
            for source, claim in EXTERNAL_CITATIONS[str(sec)]:
                print(f'      • {source:<18}  {claim}')
        print(f'  {"-" * 76}')
        print('  Every external claim listed above is reproduced from this harness.')
        print('  Run `python eye/cryptanalysis_harness.py 91` for the consolidated')
        print('  peer-review reconciliation report.')
    return 0

if __name__ == '__main__':
    sys.exit(main())
